-- Poems batch 15
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('138347e2-4451-4bbf-a3da-0abb3194d570','和思黯憶南莊見示','劉禹錫','唐','唐诗','tang','','[]','丞相新家伊水頭，智囊心匠日增修。',64,'全唐诗/poet.tang.19000.json','["丞相新家伊水頭，智囊心匠日增修。", "化成池沼無痕跡，奔走清波不自由。", "臺上看山徐舉酒，潭中見月慢回舟。", "從來天下推尤物，合屬人間第一流。"]'),
('f13210ea-a534-49e0-8f95-f4b2999549dc','酬思黯見示小飲四韻','劉禹錫','唐','唐诗','tang','','[]','拋却人間第一官，俗情驚怪我方安。',64,'全唐诗/poet.tang.19000.json','["拋却人間第一官，俗情驚怪我方安。", "兵府相印無心戀，洛水嵩雲恣意看。", "三足鼎中知味久，百尋竿上擲身難。", "追呼故舊連宵飲，直到天明興未闌。"]'),
('d7265b1f-1a37-4d58-b6ef-e3396a291aa2','和僕射牛相公春日閑坐見懷','劉禹錫','唐','唐诗','tang','','[]','官曹崇重難頻入，第宅清閑且獨行。',64,'全唐诗/poet.tang.19000.json','["官曹崇重難頻入，第宅清閑且獨行。", "階蟻相逢如偶語，園蜂速去恐違程。", "人於紅藥惟看色，鶯到垂楊不惜聲。", "東洛池臺怨拋擲，移文非久會應成。"]'),
('95818c9a-fb02-49b8-a75a-90d4aee426ca','酬元九侍御贈璧竹鞭長句','劉禹錫','唐','唐诗','tang','','[]','碧玉孤根生在林，美人相贈比雙金。',64,'全唐诗/poet.tang.19000.json','["碧玉孤根生在林，美人相贈比雙金。", "初開郢客緘封後，想見巴山冰雪深。", "多節本懷端直性，露青猶有歲寒心。", "何時策馬同歸去，關樹扶疎敲鐙吟。"]'),
('d0617c77-dfcb-41e1-b2eb-ea4402c7d9b5','酬竇員外使君寒食日途次松滋渡先寄示四韻','劉禹錫','唐','唐诗','tang','','[]','楚鄉寒食橘花時，野渡臨風駐綵旗。',64,'全唐诗/poet.tang.19000.json','["楚鄉寒食橘花時，野渡臨風駐綵旗。", "草色連雲人去住，水紋如縠燕差池。", "朱輪尚憶羣飛雉，青綬初縣左顧龜。", "非是湓城舊司馬，水曹何事與新詩。"]'),
('8bd180ce-c455-4411-9886-058b27a93216','寄楊八拾遺','劉禹錫','唐','唐诗','tang','','[]','聞君前日獨庭爭，漢帝偏知白馬生。',64,'全唐诗/poet.tang.19000.json','["聞君前日獨庭爭，漢帝偏知白馬生。", "忽領簿書遊太學，寧勞侍從厭承明。", "洛陽本自宜才子，海內而今有直聲。", "爲謝同僚老博士，范雲來歲即公卿。"]'),
('18a4c844-9986-4fff-b071-00d2e154a39f','酬竇員外郡齋宴客偶命柘枝因見寄兼呈張十一院長元九侍御','劉禹錫','唐','唐诗','tang','','[]','分憂餘刃又從公，白羽胡牀嘯詠中。',64,'全唐诗/poet.tang.19000.json','["分憂餘刃又從公，白羽胡牀嘯詠中。", "綵筆諭戎矜倚馬，華堂留客看驚鴻。", "渚宮油幕方高步，澧浦甘棠有幾叢。", "若問騷人何處所，門臨寒水落江楓。"]'),
('5a439825-ff4c-49ee-866d-84586386b57d','謝竇員外旬休早涼見示詩','劉禹錫','唐','唐诗','tang','','[]','新秋十日澣朱衣，鈴閣無聲公吏歸。',64,'全唐诗/poet.tang.19000.json','["新秋十日澣朱衣，鈴閣無聲公吏歸。", "風韻漸高梧葉動，露光初重槿花稀。", "四時苒苒催容鬢，三爵油油忘是非。", "更報明朝池上酌，人知太守字玄暉。"]'),
('5a7da397-197d-437e-9fc7-88fe96d648c4','南海馬大夫遠示著述兼酬拙詩輒著微誠再有長句時蔡戎未弭故見於篇末','劉禹錫','唐','唐诗','tang','','[]','漢家旄節付雄才，百越南溟統外臺。',64,'全唐诗/poet.tang.19000.json','["漢家旄節付雄才，百越南溟統外臺。", "身在絳紗傳六藝，腰懸青綬亞三臺。", "連天浪靜長鯨息，映日帆多寶舶來。", "聞道楚氛猶未滅，終須旌斾掃雲雷。"]'),
('c55f56eb-431d-4e73-97ec-8f067a5ef5c7','和南海馬大夫聞楊侍郎出守郴州因有寄上之作','劉禹錫','唐','唐诗','tang','','[]','忽驚金印駕枝轓，遂別鳴珂聽曉猿。',64,'全唐诗/poet.tang.19000.json','["忽驚金印駕枝轓，遂別鳴珂聽曉猿。", "碧落仙來雖暫謫，赤泉侯在是深恩。", "玉環慶遠瞻台坐，銅柱勳高壓海門。", "一詠瓊瑤百憂散，何勞更樹北堂萱。"]'),
('f72834f8-270d-419c-92c1-603720ce7d3a','馬大夫見示浙西王侍御贈答詩因命同作','劉禹錫','唐','唐诗','tang','','[]','憶逐羊車凡幾時，今來舊府統戎師。',64,'全唐诗/poet.tang.19000.json','["憶逐羊車凡幾時，今來舊府統戎師。", "象筵照室會詞客，銅鼓臨軒舞海夷。", "百越酋豪稱故吏，十洲風景助新詩。", "秣陵從事何年別，一見瓊章如素期。"]'),
('3e72e0e6-b329-41f0-a061-f709c5fa3737','寄唐州楊八歸厚','劉禹錫','唐','唐诗','tang','','[]','淮安古地擁州師，畫角金鐃旦夕吹。',64,'全唐诗/poet.tang.19000.json','["淮安古地擁州師，畫角金鐃旦夕吹。", "淺草遙迎鷫鸘馬，春風亂颭辟邪旗。", "謫仙年月今應滿，戇諫聲名衆所知。", "何況遷喬舊同伴，一雙先入鳳凰池。"]'),
('8b9665d2-057e-44a6-8f9f-d91b6f3c6552','寄朗州溫右史曹長','劉禹錫','唐','唐诗','tang','','[]','暫別瑤墀鴛鷺行，綵旗雙引到沅湘。',64,'全唐诗/poet.tang.19000.json','["暫別瑤墀鴛鷺行，綵旗雙引到沅湘。", "城邊流水桃花過，簾外春風杜若香。", "史筆枉將書紙尾，朝纓不稱濯滄浪。", "雲臺公業家聲在，徵詔何時出建章。"]'),
('10d07bec-a51c-4474-b05f-ff7fc018c4f4','詶楊司業巨源見寄','劉禹錫','唐','唐诗','tang','','[]','辟雍流水近靈臺，中有詩篇絕世才。',64,'全唐诗/poet.tang.19000.json','["辟雍流水近靈臺，中有詩篇絕世才。", "渤海歸人將集去，棃園弟子請詞來。", "瓊枝未識魂空斷，寶匣初臨手自開。", "莫道專城管雲雨，其如心似不然灰。"]'),
('25eeaa0b-dad0-4164-bb62-1896bdb82443','詶國子崔博士立之見寄','劉禹錫','唐','唐诗','tang','','[]','健筆高科早絕倫，後來無不揖芳塵。',64,'全唐诗/poet.tang.19000.json','["健筆高科早絕倫，後來無不揖芳塵。", "遍看今日乘軒客，多是昔年呈卷人。", "胄子執經瞻講坐，郎官共食接華茵。", "煩君遠寄相思曲，慰問天南一逐臣。"]'),
('27f11984-b48d-411c-a8ed-100684a6f731','張郎中籍遠寄長句開緘之日已及新秋因舉目前仰酬高韻','劉禹錫','唐','唐诗','tang','','[]','南宮詞客寄新篇，清似湘靈促柱弦。',64,'全唐诗/poet.tang.19000.json','["南宮詞客寄新篇，清似湘靈促柱弦。", "京邑舊遊勞夢想，歷陽秋色正澄鮮。", "雲銜日脚成山雨，風駕潮頭入渚田。", "對此獨吟還獨酌，知音不見思愴然。"]'),
('9f57b2df-7f47-4600-a68a-a3efb709ff40','浙東元相公書歎梅雨鬱蒸之候因寄七言','劉禹錫','唐','唐诗','tang','','[]','稽山自與岐山別，何事連年鸑鷟飛。',64,'全唐诗/poet.tang.19000.json','["稽山自與岐山別，何事連年鸑鷟飛。", "百辟商量舊相入，九天祗候老臣歸。", "平湖晚泛窺清鏡，高閣晨開掃翠微。", "今日看書最惆悵，爲聞梅雨損朝衣。"]'),
('a90a8d61-6303-4c53-b681-db94090369ce','酬嚴給事賀加五品兼簡同制水部李郎中','劉禹錫','唐','唐诗','tang','','[]','九天雨露傳青詔，八舍郎官換綠衣。',64,'全唐诗/poet.tang.19000.json','["九天雨露傳青詔，八舍郎官換綠衣。", "初佩銀魚隨仗入，宜乘白馬退朝歸。", "彫盤賀喜開瑤席，綵筆題詩出鎖闈。", "聞道水曹偏得意，霞朝霧夕有光輝。"]'),
('e767e376-1ab0-435f-97cc-2479f2e90729','裴相公大學士見示答張秘書謝馬詩幷羣公屬和因命追作','劉禹錫','唐','唐诗','tang','','[]','草玄門戶少塵埃，丞相幷州寄馬來。',64,'全唐诗/poet.tang.19000.json','["草玄門戶少塵埃，丞相幷州寄馬來。", "初自寒垣銜苜蓿，忽行幽徑破莓苔。", "尋花緩轡威遲去，帶酒垂鞭躞蹀回。", "不與王侯與詞客，知輕富貴重清才。"]'),
('8d7f4579-c049-4917-8d35-e18b42f9e357','奉和裴侍中將赴漢南留別座上諸公','劉禹錫','唐','唐诗','tang','','[]','金貂曉出鳳池頭，玉節前臨南雍州。',64,'全唐诗/poet.tang.19000.json','["金貂曉出鳳池頭，玉節前臨南雍州。", "暫輟洪鑪觀劍戟，還將大筆注春秋。", "管弦席上留高韻，山水途中入勝遊。", "峴首風煙看未足，便應重拜富民侯。"]'),
('7b7e7ffb-56ef-43fe-a140-b4a7a3d12cef','和蘇郎中尋豐安里舊居寄主客張郎中','劉禹錫','唐','唐诗','tang','','[]','漳濱臥起恣閑遊，宣室徵還未白頭。',64,'全唐诗/poet.tang.19000.json','["漳濱臥起恣閑遊，宣室徵還未白頭。", "舊隱來尋通德里，新篇寫出畔牢愁。", "池看科斗成文字，鳥聽提壺憶獻酬。", "同學同年又同舍，許君雲路並華輈。"]'),
('97e74ab5-16ae-4acf-b0b1-9329ebce61fe','詶浙東李侍郎越州春晚即事長句','劉禹錫','唐','唐诗','tang','','[]','越中藹藹繁華地，秦望峰前禹穴西。',64,'全唐诗/poet.tang.19000.json','["越中藹藹繁華地，秦望峰前禹穴西。", "湖草初生邊鴈去，山花半謝杜鵑啼。", "青油晝卷臨高閣，紅斾晴翻繞古堤。", "明日漢庭徵舊德，老人爭出若耶溪。"]'),
('cdea5f37-42c5-40e2-ad6c-f4531aaa4cba','詶淮南牛相公述舊見貽','劉禹錫','唐','唐诗','tang','','[]','少年曾忝漢庭臣，晚歲空餘老病身。',64,'全唐诗/poet.tang.19000.json','["少年曾忝漢庭臣，晚歲空餘老病身。", "初見相如成賦日，尋爲丞相掃門人。", "追思往事咨嗟久，喜奉清光笑語頻。", "猶有登朝舊冠冕，待公三入拂埃塵。"]'),
('8d6b6e0a-c870-4e53-9f3c-00b4ea5e8129','和僕射牛相公追感韋裴六相登庸皆四十餘未五十薨歿豈早榮枯之義今年將六十猶粗强健因親故勸酒率然成篇幷見寄之作','劉禹錫','唐','唐诗','tang','','[]','坐鎮清朝獨殷然，閑徵故事數前賢。',64,'全唐诗/poet.tang.19000.json','["坐鎮清朝獨殷然，閑徵故事數前賢。", "用才同踐鈞衡地，稟氣終分大小年。", "威鳳本池思泛泳，仙查舊路望回旋。", "猶憐綺季深山裏，唯有松風與石田。"]'),
('21a115d0-fda4-4d59-82d5-61c7735fe2b4','和僕射牛相公以離闕庭七年班行親故亡歿十無一人再覩龍顏喜慶雖極感歎風燭能不愴然因成四韻幷示集賢中書二相公所和','劉禹錫','唐','唐诗','tang','','[]','久辭龍闕擁紅旗，喜見天顏拜赤墀。',64,'全唐诗/poet.tang.19000.json','["久辭龍闕擁紅旗，喜見天顏拜赤墀。", "三省英寮非舊侶，萬年芳樹長新枝。", "交朋接武居仙院，幕客追風入鳳池。", "雲母屏風即施設，可憐榮耀冠當時。"]'),
('737a7344-0f92-49ce-8839-52edc58da95a','和僕射牛相公見示長句','劉禹錫','唐','唐诗','tang','','[]','靜得天和興自濃，不緣宦達性靈慵。',64,'全唐诗/poet.tang.19000.json','["靜得天和興自濃，不緣宦達性靈慵。", "大鵬六月有閑意，仙鶴千年無躁容。", "流輩盡來多歎息，官班高後少過從。", "唯應加築露臺上，賸見終南雲外峰。"]'),
('db4fa5f6-b1b2-4a62-9904-608fe6415473','和牛相公雨後寓懷見示','劉禹錫','唐','唐诗','tang','','[]','金火交爭正抑揚，蕭蕭飛雨助清商。',64,'全唐诗/poet.tang.19000.json','["金火交爭正抑揚，蕭蕭飛雨助清商。", "曉看紈扇恩情薄，夜覺紗燈刻數長。", "樹上早蟬才發響，庭中百草已無光。", "當年富貴亦惆悵，何況悲翁髮似霜。"]'),
('b05d236a-d968-40de-857e-66615ef6d98b','和陳許王尚書酬白少傅侍郎長句因通簡汝洛舊遊之什','劉禹錫','唐','唐诗','tang','','[]','寥廓高翔不可追，風雲失路蹔相隨。',64,'全唐诗/poet.tang.19000.json','["寥廓高翔不可追，風雲失路蹔相隨。", "方同洛下書生詠，又見軍前大將旗。", "雪裏命賓開玉帳，飲中請號駐金巵。", "竹林一自王戎去，嵇阮雖貧興未衰。"]'),
('0ea4bb85-cbb9-4cc0-8743-4141422fc5fc','和僕射牛相公寓言二首 一','劉禹錫','唐','唐诗','tang','','[]','兩度竿頭立定誇，回眸舉袖拂青霞。',64,'全唐诗/poet.tang.19000.json','["兩度竿頭立定誇，回眸舉袖拂青霞。", "盡拋今日貴人樣，復振前朝名相家。", "御史定來休直宿，尚書依舊趂參衙。", "具瞻尊重誠無敵，猶憶洛陽千樹花。"]'),
('0b26cbe9-324d-4de8-bc54-4b4beb2e7a3c','和僕射牛相公寓言二首 二','劉禹錫','唐','唐诗','tang','','[]','心如止水鑒常明，見盡人間萬物情。',64,'全唐诗/poet.tang.19000.json','["心如止水鑒常明，見盡人間萬物情。", "鵰鶚騰空猶逞俊，驊騮嚙足自無驚。", "時來未覺權爲祟，貴了方知退是榮。", "只恐重重世緣在，事須三度副蒼生。"]'),
('66a7dae5-359f-43b0-a186-ee91402f5b8f','詶太原狄尚書見寄','劉禹錫','唐','唐诗','tang','','[]','家聲烜赫冠前賢，時無穹崇鎮北邊。',64,'全唐诗/poet.tang.19000.json','["家聲烜赫冠前賢，時無穹崇鎮北邊。", "身上官銜如座主，幕中譚笑取同年。", "幽幷俠少趨鞭弭，燕趙佳人奉管弦。", "仍把天兵書號筆，遠題長句寄山川。"]'),
('c986bb0e-352c-4c43-b6b9-762c0736b336','詶宣州崔大夫見寄','劉禹錫','唐','唐诗','tang','','[]','白衣曾拜漢尚書，今日恩光到敝廬。',64,'全唐诗/poet.tang.19000.json','["白衣曾拜漢尚書，今日恩光到敝廬。", "再入龍樓稱綺季，應緣狗監說相如。", "中郎南鎮權方重，內史高齋興有餘。", "遙想敬亭春欲暮，百花飛盡柳花初。"]'),
('bd7d13c2-5405-4500-8b69-7e72e724070a','詶皇甫十少尹暮秋久雨喜晴有懷見示','劉禹錫','唐','唐诗','tang','','[]','雨餘獨坐卷簾帷，便得詩人喜霽詩。',64,'全唐诗/poet.tang.19000.json','["雨餘獨坐卷簾帷，便得詩人喜霽詩。", "搖落從來長年感，慘舒偏是病身知。", "掃開雲霧呈光景，流盡潢汙見路岐。", "何況菊香新酒熟，神州司馬好狂時。"]'),
('7a11fbb0-0fa3-436a-a778-a2095d3fb85e','再授連州至衡陽酬柳柳州贈別','劉禹錫','唐','唐诗','tang','','["\u53cb\u60c5"]','去國十年同赴召，渡湘千里又分岐。',64,'全唐诗/poet.tang.19000.json','["去國十年同赴召，渡湘千里又分岐。", "重臨事異黃丞相，三黜名慙柳士師。", "歸目併隨回鴈盡，愁腸正遇斷猿時。", "桂江東過連山下，相望長吟有所思。"]'),
('8038adf6-235d-4ad7-bec5-ad311f918d66','望夫山','劉禹錫','唐','唐诗','tang','','[]','何代提戈去不還，獨留形影白雲間。',64,'全唐诗/poet.tang.19000.json','["何代提戈去不還，獨留形影白雲間。", "肌膚銷盡雪霜色，羅綺點成苔蘚斑。", "江燕不能傳遠信，野花空解妒愁顏。", "近來豈少征人婦，笑採蘼蕪上北山。"]'),
('89f1cd0f-88d7-42bb-ab45-e3a1acf3bf79','懷妓 一','劉禹錫','唐','唐诗','tang','','[]','玉釵重合兩無緣，魚在深潭鶴在天。',64,'全唐诗/poet.tang.19000.json','["玉釵重合兩無緣，魚在深潭鶴在天。", "得意紫鸞休舞鏡，能言青鳥罷銜牋。", "金盆已覆難收水，玉軫長拋不續弦。", "若向蘼蕪山下過，遙將紅淚灑窮泉。"]'),
('77dfc220-7dd8-443d-a125-e7a0358d2631','懷妓 二','劉禹錫','唐','唐诗','tang','','[]','鸞飛遠樹棲何處，鳳得新巢想稱心。',64,'全唐诗/poet.tang.19000.json','["鸞飛遠樹棲何處，鳳得新巢想稱心。", "紅壁尚留香漠漠，碧雲初斷信沈沈。", "情知點污投泥玉，猶自經營買笑金。", "從此山頭似人石，丈夫形狀淚痕深。"]'),
('66570a4c-477c-42eb-a646-e01a06b89a5f','懷妓 三','劉禹錫','唐','唐诗','tang','','[]','但曾行處遍尋看，雖是生離死一般。',64,'全唐诗/poet.tang.19000.json','["但曾行處遍尋看，雖是生離死一般。", "買笑樹邊花已老，畫眉窗下月猶殘。", "雲藏巫峽音容斷，路隔星橋過往難。", "莫怪詩成無淚滴，盡傾東海也須乾。"]'),
('fdf3590b-e5ba-4bef-ac00-2e332ddf8069','懷妓 四','劉禹錫','唐','唐诗','tang','','[]','三山不見海沈沈，豈有仙蹤更可尋。',64,'全唐诗/poet.tang.19000.json','["三山不見海沈沈，豈有仙蹤更可尋。", "青鳥去時雲路斷，姮娥歸處月宮深。", "紗窗遙想春相憶，書幌誰憐夜獨吟。", "料得夜來天上鏡，只應偏照兩人心。"]'),
('22570e9e-e054-45fa-b91f-c383e8df2fba','荅東陽于令寒碧圖詩','劉禹錫','唐','唐诗','tang','','[]','東陽本是佳山水，何況曾經沈隱侯。',64,'全唐诗/poet.tang.19000.json','["東陽本是佳山水，何況曾經沈隱侯。", "化得邦人解吟詠，如今縣令亦風流。", "新開譚洞疑仙境，遠寫丹青到雍州。", "落在尋常畫師手，猶能三伏凜生秋。"]'),
('a1bd43e7-6c89-4d49-a597-4b4fa2bb2ab4','麻姑山','劉禹錫','唐','唐诗','tang','','[]','曾遊仙蹟見豐碑，除却麻姑更有誰。',64,'全唐诗/poet.tang.19000.json','["曾遊仙蹟見豐碑，除却麻姑更有誰。", "雲蓋青山龍臥處，日臨丹洞鶴歸時。", "霜凝上界花開晚，月冷中天果熟遲。", "人到便須拋世事，稻田還儗種靈芝。"]'),
('f0982c5f-6245-45bb-9a7a-21e07a0c4622','自江陵沿流道中','劉禹錫','唐','唐诗','tang','','["\u957f\u6c5f"]','三千三百西江水，自古如今要路津。',64,'全唐诗/poet.tang.19000.json','["三千三百西江水，自古如今要路津。", "月夜歌謠有漁父，風天氣色屬商人。", "沙村好處多逢寺，山葉紅時覺勝春。", "行到南朝征戰地，古來名將盡爲神。"]'),
('8f8b2289-5900-415a-bf1d-534118dcac56','別夔州官吏','劉禹錫','唐','唐诗','tang','','[]','三年楚國巴城守，一去揚州揚子津。',64,'全唐诗/poet.tang.19000.json','["三年楚國巴城守，一去揚州揚子津。", "青帳聯延喧驛步，白頭俯傴到江濱。", "巫山暮色常含雨，峽水秋來不恐人。", "惟有九歌詞數首，里中留與賽蠻神。"]'),
('950ce4d5-d7b9-47ab-aee8-3a72de4c4143','魚復江中','劉禹錫','唐','唐诗','tang','','[]','扁舟盡室貧相逐，白髮藏冠鑷更加。',64,'全唐诗/poet.tang.19000.json','["扁舟盡室貧相逐，白髮藏冠鑷更加。", "遠水自澄終日綠，晴林長落過春花。", "客情浩蕩逢鄉語，詩意留連重物華。", "風檣好住貪程去，斜日青帘背酒家。"]'),
('a4bf89a1-d3e1-418c-abdd-25129c326348','巫山神女廟','劉禹錫','唐','唐诗','tang','','[]','巫山十二鬱蒼蒼，片石亭亭號女郎。',64,'全唐诗/poet.tang.19000.json','["巫山十二鬱蒼蒼，片石亭亭號女郎。", "曉霧乍開疑卷幔，山花欲謝似殘妝。", "星河好夜聞清佩，雲雨歸時帶異香。", "何事神仙九天上，人間來就楚襄王。"]'),
('df3d125a-e9b0-46d1-8d69-a2585824a34e','柳絮','劉禹錫','唐','唐诗','tang','','[]','飄颺南陌起東鄰，漠漠濛濛暗度春。',64,'全唐诗/poet.tang.19000.json','["飄颺南陌起東鄰，漠漠濛濛暗度春。", "花巷暖隨輕舞蝶，玉樓晴拂豔妝人。", "縈迴謝女題詩筆，點綴陶公漉酒巾。", "何處好風偏似雪，隋河堤上古江津。"]'),
('d7ad5829-d0c0-43b7-9d35-971dc706e552','贈同年陳長史員外','劉禹錫','唐','唐诗','tang','','[]','明州長史外臺郎，憶昔同年翰墨場。',64,'全唐诗/poet.tang.19000.json','["明州長史外臺郎，憶昔同年翰墨場。", "一自分襟多歲月，相逢滿眼是淒涼。", "推賢有愧韓安國，論舊唯存盛孝章。", "所歎謬遊東閣下，看君無計出恓惶。"]'),
('8b1b03d2-e68e-4f17-ae92-f1a92f40551e','送周魯儒赴舉詩','劉禹錫','唐','唐诗','tang','','[]','宋日營陽內史孫，因家占得九疑村。',64,'全唐诗/poet.tang.19000.json','["宋日營陽內史孫，因家占得九疑村。", "童心便有愛書癖，手指今餘把筆痕。", "自握蛇珠辭白屋，欲憑雞卜謁金門。", "若逢廣坐問羊酪，從此知名在一言。"]'),
('2e6914b9-8bf8-49ff-a94a-8e547693c129','送曹璩歸越中舊隱詩','劉禹錫','唐','唐诗','tang','','[]','行盡瀟湘萬里餘，少逢知己憶吾廬。',64,'全唐诗/poet.tang.19000.json','["行盡瀟湘萬里餘，少逢知己憶吾廬。", "數間茅屋閒臨水，一盞秋燈夜讀書。", "地遠何當隨計吏，策成終自詣公車。", "剡中若問連州事，唯有千山畫不如。"]'),
('2842fcb0-0112-40e3-bdf3-554fd0d310eb','白鷹','劉禹錫','唐','唐诗','tang','','[]','毛羽斒斕白紵裁，馬前擎出不驚猜。',64,'全唐诗/poet.tang.19000.json','["毛羽斒斕白紵裁，馬前擎出不驚猜。", "輕拋一點入雲去，喝殺三聲掠地來。", "綠玉觜攢雞腦破，玄金爪擘兔心開。", "都緣解搦生靈物，所以人人道俊哉。"]'),
('17f0836f-c3eb-470c-bcb1-d906e72592ad','送工部張侍郎入蕃弔祭','劉禹錫','唐','唐诗','tang','','[]','月窟賓諸夏，雲官降九天。',72,'全唐诗/poet.tang.19000.json','["月窟賓諸夏，雲官降九天。", "飾終鄰好重，錫命禮容全。", "水咽猶登隴，沙鳴稍極邊。", "路因乘驛近，志爲飲冰堅。", "毳帳差池見，烏旗搖曳前。", "歸來賜金石，榮耀自編年。"]'),
('d95b17c8-b7f3-4fd2-ac2e-e23045fe1b5c','早秋送臺院楊侍御歸朝','劉禹錫','唐','唐诗','tang','','[]','仙署棣華春，當時已絕倫。',72,'全唐诗/poet.tang.19000.json','["仙署棣華春，當時已絕倫。", "今朝丹闕下，更入白眉人。", "重振高陽族，分居要路津。", "一門科第足，五府辟書頻。", "鷙鳥得秋氣，法星懸火旻。", "聖朝寰海靜，所至不埋輪。"]'),
('a891ddeb-0dd1-486f-9ea1-54682101004c','送陸侍御歸淮南使府五韻','劉禹錫','唐','唐诗','tang','','["\u6cf0\u5c71"]','江左重詩篇，陸生名久傳。',60,'全唐诗/poet.tang.19000.json','["江左重詩篇，陸生名久傳。", "鳳城來已熟，羊酪不嫌羶。", "歸路芙蓉府，離堂玳瑁筵。", "泰山呈臘雪，隋柳布新年。", "曾忝揚州薦，因君達短牋。"]'),
('f0914a95-cdd3-4cec-96b1-6194738960fc','送令狐相公自僕射出鎮南梁','劉禹錫','唐','唐诗','tang','','[]','夏木正陰成，戎裝出帝京。',72,'全唐诗/poet.tang.19000.json','["夏木正陰成，戎裝出帝京。", "沾襟辭闕淚，回首別鄉情。", "雲樹褒中路，風煙漢上城。", "前旌傳谷去，後騎踏橋聲。", "久領鴛行重，無嫌虎綬輕。", "終提一麾去，再入福蒼生。"]'),
('a7fd02c4-d0a5-4aa0-a74c-c5262963531e','奉送裴司徒令公自東都留守再命太原','劉禹錫','唐','唐诗','tang','','[]','星使出關東，兵符賜上公。',72,'全唐诗/poet.tang.19000.json','["星使出關東，兵符賜上公。", "山河歸舊國，管籥換離宮。", "行色旌旗動，軍聲鼓角雄。", "愛棠餘故吏，騎竹見新童。", "漢壘三秋靜，胡沙萬里空。", "其如天下望，旦夕詠清風。"]'),
('d5e6b9e1-398b-4105-9039-a9076d0431fc','海陽湖別浩初師','劉禹錫','唐','唐诗','tang','','[]','近郭看殊境，獨遊常鮮懽。',95,'全唐诗/poet.tang.19000.json','["近郭看殊境，獨遊常鮮懽。", "逢君駐緇錫，觀貌稱林巒。", "湖滿景方霽，野香春未闌。", "愛泉移席近，聞石輟棊看。", "風止松猶韻，花繁露未乾。", "橋形出樹曲，巖影落池寒別路千嶂裏，詩情暮雲端。", "他年買山處，似此得隳官。"]'),
('a901da4c-d0ab-4c7a-a389-1d4ec74d3523','許給事見示哭工部劉尚書詩因命同作','劉禹錫','唐','唐诗','tang','','[]','漢室賢王後，孔門高第人。',144,'全唐诗/poet.tang.19000.json','["漢室賢王後，孔門高第人。", "濟時成國器，樂道任天真。", "特達圭無玷，堅貞竹有筠。", "總戎寬得衆，市義貴能貧。", "護塞無南牧，馳心拱北辰。", "乞身來闕下，賜告臥漳濱。", "榮耀初題劒，清羸已拖紳。", "宮星徒列位，隙日不回輪。", "自昔追飛侶，今爲侍從臣。", "素弦哀已絕，青簡歎猶新。", "未遂揮金樂，空悲撤瑟晨。", "淒涼竹林下，無復見清塵。"]'),
('6e27c564-356b-4c7b-8594-861f03d55cfc','武陵書懷五十韻','劉禹錫','唐','唐诗','tang','','[]','西漢開支郡，南朝號戚藩。',288,'全唐诗/poet.tang.19000.json','["西漢開支郡，南朝號戚藩。", "四封當列宿，百雉俯清沅。", "高岸朝霞合，驚湍激箭奔。", "積陰春暗度，將霽霧先昏。", "俗尚東皇祀，謠傳義帝冤。", "桃花迷隱跡，楝葉慰忠魂。", "戶算資漁獵，鄉豪恃子孫。", "照山畬火動，踏月俚歌喧。", "擁檝舟爲市，連甍竹覆軒。", "披沙金粟見，拾羽翠翹翻。", "茗折蒼溪秀，蘋生枉渚暄。", "禽驚格磔起，魚戲噞喁繁。", "沈約臺榭故，李衡墟落存。", "湘靈悲鼓瑟，泉客泣酬恩。", "露變蒹葭浦，星懸橘柚村。", "虎咆空野震，鼉作滿川渾。", "鄰里皆遷客，兒童習左言。", "炎天無冽井，霜月見芳蓀。", "清白家傳遠，詩書志所敦。", "列科叨甲乙，從宦出丘樊。", "結友心多契，馳聲氣尚吞。", "士安曾重賦，元禮許登門。", "草檄嫖姚幕，巡兵戊己屯。", "築臺先自隗，送客獨留髠。"]'),
('5805a4c4-b41a-4876-9fe5-7a2f3affa462','早秋集賢院即事','劉禹錫','唐','唐诗','tang','','[]','金數已三伏，火星正西流。',96,'全唐诗/poet.tang.19000.json','["金數已三伏，火星正西流。", "樹含秋露曉，閣倚碧天秋。", "灰琯應新律，銅壺添夜籌。", "商飆從朔塞，爽氣入神州。", "蕙草香書殿，槐花點御溝。", "山明真色見，水靜濁煙收。", "早歲忝華省，再來成白頭。", "幸依羣玉府，末路尚瀛洲。"]'),
('05e0a730-a944-41ec-bccd-5c9169cda69a','奉和吏部楊尚書太常李卿二相公策免後即事述懷贈答十韻','劉禹錫','唐','唐诗','tang','','[]','文雅關西族，衣冠趙北都。',120,'全唐诗/poet.tang.19000.json','["文雅關西族，衣冠趙北都。", "有聲真漢相，無纇勝隋珠。", "當軸龍爲友，臨池鳳不孤。", "九天開內殿，百辟看晨趨。", "誡滿澄欹器，成功別大罏。", "餘芳在公論，積慶是神扶。", "步武離台席，徊翔集帝梧。", "詮材秉秦鏡，典樂去齊竽。", "瀟灑風塵外，逢迎詩酒徒。", "唯應待華誥，更食萬錢廚。"]'),
('8a9d9842-af13-4e4a-9973-63799a2ff132','晚歲登武陵城顧望水陸悵然有作','劉禹錫','唐','唐诗','tang','','[]','星象承烏翼，蠻陬想犬牙。',168,'全唐诗/poet.tang.19000.json','["星象承烏翼，蠻陬想犬牙。", "俚人祠竹節，仙洞閉桃花。", "城基歷漢魏，江源自賨巴。", "華表廖王墓，菜地黃瓊家。", "霜輕菊秀晚，石淺水紋斜。", "樵音繞故壘，汲路明寒沙。", "清風稍改葉，盧橘始含葩。", "野橋過驛騎，叢祠發逈笳。", "跳鱗避舉網，倦鳥寄行楂。", "路塵高出樹，山火遠連霞。", "夕曛轉赤岸，浮靄起蒼葭。", "軋軋渡水槳，連連赴林鴉。", "呌閽道非遠，賜環期自賒。", "孤臣本危涕，喬木在天涯。"]'),
('6a6a36c8-34df-416d-bc29-0c07dcf5866f','罷郡歸洛陽寄友人','劉禹錫','唐','唐诗','tang','','["\u6292\u60c5", "\u611f\u6168", "\u56de\u5fc6", "\u58ee\u5fd7\u672a\u916c"]','遠謫年猶少，初歸鬢已衰。',72,'全唐诗/poet.tang.19000.json','["遠謫年猶少，初歸鬢已衰。", "門閑故吏去，室靜老僧期。", "不見蜘蛛集，頻爲佝僂欺。", "穎微囊未出，寒甚谷難吹。", "濩落唯心在，平生有己知。", "商歌夜深後，聽者竟爲誰。"]'),
('3f74fe9b-46ed-42fd-9d5c-a2c6ec586409','經伏波神祠','劉禹錫','唐','唐诗','tang','','[]','蒙蒙篁竹下，有路上壺頭。',72,'全唐诗/poet.tang.19000.json','["蒙蒙篁竹下，有路上壺頭。", "漢壘麏鼯鬬，蠻溪霧雨愁。", "懷人敬遺像，閱世指東流。", "自負霸王略，安知恩澤侯。", "鄉園辭石柱，筋力盡炎洲。", "一以功名累，飜思馬少游。"]'),
('a4e609f3-eab1-4cc7-84fd-f02aae45291b','和汴州令狐相公到鎮改月偶書所懷','劉禹錫','唐','唐诗','tang','','[]','受脤新梁苑，和羹舊傅巖。',264,'全唐诗/poet.tang.19000.json','["受脤新梁苑，和羹舊傅巖。", "援毫動星宿，垂釣取韜鈐。", "赫奕三川至，歡呼百姓瞻。", "綠油貔虎擁，青紙鳳皇銜。", "外壘曾無警，中廚亦罷監。", "推誠人自服，去殺令逾嚴。", "赳赳容皆飾，幡幡口盡鉗。", "爲兄憐庾翼，選壻得蕭咸。", "鬱倔咽喉地，駢臻水陸兼。", "度橋鳴紺幰，入肆颺雲帆。", "端月當中氣，東風應遠占。", "管弦喧夜景，燈燭掩寒蟾。", "酒每傾三雅，書能發百函。", "詞人羞布鼓，遠客獻貂襜。", "歌榭白團扇，舞筵金縷衫。", "旌旗遙一簇，舄履近相攙。", "花樹當朱閣，晴河逼翠簾。", "衣風飄靉靆，燭淚滴巉巖。", "玉斝虛頻易，金爐暖更添。", "映鐶窺豔豔，隔袖見纖纖。", "謝傅何由接，桓伊定不凡。", "應憐郡齋老，旦夕鑷霜䫇。"]'),
('8fc15312-ebe5-4141-8679-e2fa6217eeb0','遙賀白賓客分司初到洛中戲呈馮尹','劉禹錫','唐','唐诗','tang','','[]','西辭望苑去，東占洛陽才。',72,'全唐诗/poet.tang.19000.json','["西辭望苑去，東占洛陽才。", "度嶺無愁思，看山不懊來。", "冥鴻何所慕，遼鶴乍飛廻。", "洗竹通新逕，攜琴上舊臺。", "塵埃長者撤，風月故人杯。", "聞道龍門峻，還因上客開。"]'),
('be76d833-412a-44f8-9871-6153103c7b5a','白侍郎大尹自河南寄示池北新葺水齋即事招賓十四韻兼命同作','劉禹錫','唐','唐诗','tang','','[]','公府有高政，新齋池上開。',168,'全唐诗/poet.tang.19000.json','["公府有高政，新齋池上開。", "再吟佳句後，一似畫圖來。", "結搆疎林下，夤緣曲岸隈。", "綠波穿戶牖，碧甃疊瓊瓌。", "幽異當軒滿，清光繞砌廻。", "潭心澄晚鏡，渠口起晴雷。", "瑤草緣堤種，松煙上島栽。", "遊魚驚撥刺，浴鷺喜毰毸。", "爲客烹林笋，因僧採石苔。", "酒缾常不罄，書案任成堆。", "簷外青雀舫，坐中鸚鵡杯。", "蒲根抽九節，蓮萼捧重臺。", "芳訊此時到，勝遊何日陪。", "共譏吳太守，自占洛陽才。"]'),
('edca8c83-0380-4c83-af64-371da14c6611','和令狐相公謝太原李侍中寄蒲桃','劉禹錫','唐','唐诗','tang','','[]','珍果出西域，移根到北方。',96,'全唐诗/poet.tang.19000.json','["珍果出西域，移根到北方。", "昔年隨漢使，今日寄梁王。", "上相芳緘至，行臺綺席張。", "魚鱗含宿潤，馬乳帶殘霜。", "染指鉛粉膩，滿喉甘露香。", "醞成十日酒，味敵五雲槳。", "咀嚼停金盞，稱嗟響畫堂。", "慙非末至客，不得一枝嘗。"]'),
('8b282727-8bff-446e-8add-a32cfba7671d','和令狐相公玩白菊','劉禹錫','唐','唐诗','tang','','[]','家家菊盡黃，梁國獨如霜。',96,'全唐诗/poet.tang.19000.json','["家家菊盡黃，梁國獨如霜。", "瑩靜真琪樹，分明對玉堂。", "仙人披雪氅，素女不紅妝。", "粉蝶來難見，麻衣拂更香。", "向風搖羽扇，含露滴瓊槳。", "高豔遮銀井，繁枝覆象牀。", "桂叢慙竝發，梅蘂妬先芳。", "一入瑤華詠，從茲播樂章。"]'),
('047e6adc-a25f-4d4a-93bc-26d6cb1c21b3','令狐相公見示新栽蕙蘭二草之什兼命同作','劉禹錫','唐','唐诗','tang','','[]','上國庭前草，移來漢水潯。',72,'全唐诗/poet.tang.19000.json','["上國庭前草，移來漢水潯。", "朱門雖易地，玉樹有餘陰。", "豔彩凝還泛，清香絕復尋。", "光華童子佩，柔軟美人心。", "惜晚含遠思，賞幽空獨吟。", "寄言知音者，一奏風中琴。"]'),
('a4009be3-4a63-477a-be72-0670f45c6757','和令狐相公南齋小讌聽阮咸','劉禹錫','唐','唐诗','tang','','[]','阮巷久蕪沈，四弦有遺音。',72,'全唐诗/poet.tang.19000.json','["阮巷久蕪沈，四弦有遺音。", "雅聲發蘭室，遠思含竹林。", "座絕衆賓語，庭移芳樹陰。", "飛觴助真氣，寂聽無流心。", "影似白團扇，調諧朱弦琴。", "一毫不平意，幽怨古猶今。"]'),
('8b5741ba-0a9b-4a04-9ea8-fed55e797055','和令狐相公九日對黃白二菊花見懷','劉禹錫','唐','唐诗','tang','','[]','素萼迎寒秀，金英帶露香。',72,'全唐诗/poet.tang.19000.json','["素萼迎寒秀，金英帶露香。", "繁華照旄鉞，榮盛對銀黃。", "琮璧交輝映，衣裳雜彩章。", "晴雲遙蓋覆，秋蝶近悠揚。", "空想逢九日，何由陪一觴。", "滿叢佳色在，未肯委嚴霜。"]'),
('64787797-5a57-48aa-8232-01433784e4e7','令狐僕射與余投分素深縱山川阻修然音問相繼今年十一月僕射疾不起聞予已承訃書寢門長慟後日有使者兩輩持書幷詩計其日時已是臥疾手筆盈幅翰墨尚新律詞一篇音韻彌切收淚握管以成報章雖廣陵之弦於今絕矣而蓋泉之感猶庶聞焉焚之繐帳之前附于舊編之末','劉禹錫','唐','唐诗','tang','','[]','前日寢門慟，至今悲有餘。',98,'全唐诗/poet.tang.19000.json','["前日寢門慟，至今悲有餘。", "已嗟萬化盡，方見八行書。", "滿紙傳相憶，裁詩怨索居。", "危弦音有絕，哀玉韻[猶]虛。", "忽歎幽明異，俄驚歲月除。", "文章雖不朽，精魂竟焉如。", "零淚霑青簡，傷心見素車。", "悽涼從此後，無復望雙魚。"]'),
('7bf727ff-362a-4a5f-8578-5897237bb530','和樂天閑園獨賞八韻前以蜂鶴拙句寄呈今辱蝸蟻妍詞見答因成小巧以取大咍','劉禹錫','唐','唐诗','tang','','[]','永日無人事，芳園任興行。',96,'全唐诗/poet.tang.19000.json','["永日無人事，芳園任興行。", "陶廬樹可愛，潘宅雨新晴。", "傅粉琅玕節，熏香菡萏莖。", "榴花裙色好，桐子藥丸成。", "柳蠹枝偏亞，桑空葉再生。", "睢盱欲鬬雀，索漠不言鶯。", "動植隨四氣，飛沈含五情。", "搶榆與水擊，小大強爲名。"]'),
('2dc6bc89-c0b0-4ac9-8ef2-d0719a035bb4','奉和裴令公新成綠野堂即書','劉禹錫','唐','唐诗','tang','','[]','藹藹鼎門外，澄澄洛水灣。',120,'全唐诗/poet.tang.19000.json','["藹藹鼎門外，澄澄洛水灣。", "堂皇臨綠野，坐臥看青山。", "位極却忘貴，功成欲愛閑。", "官名司管籥，心術去機關。", "禁苑凌晨出，園花及露攀。", "池塘魚拔刺，竹逕鳥綿蠻。", "志在安瀟灑，嘗經歷險艱。", "高情方造適，衆意望徵還。", "好客交珠履，華筵舞玉顏。", "無因隨賀燕，翔集畫梁間。"]'),
('c6a082c4-3aa9-4c23-9104-38aeef957d55','三月三日與樂天及河南李尹奉陪裴令公泛洛禊飲各賦十二韻','劉禹錫','唐','唐诗','tang','','[]','洛下今修禊，羣賢勝會稽。',144,'全唐诗/poet.tang.19000.json','["洛下今修禊，羣賢勝會稽。", "盛筵陪玉鉉，通籍盡金閨。", "波上神仙妓，岸旁桃李蹊。", "水嬉如鷺振，歌響雜鶯啼。", "歷覽風光好，沿洄意思迷。", "櫂歌能儷曲，墨客競分題。", "翠幄連雲起，香車向道齊。", "人誇綾步障，馬惜錦障泥。", "塵暗宮牆外，霞明苑樹西。", "舟形隨鷁轉，橋影與虹低。", "川色晴猶遠，烏聲暮欲棲。", "唯餘踏青伴，待月魏王堤。"]'),
('d61a7970-2190-49fe-b455-e005f9e90f5a','樂天少傅五月長齋廣延緇徒謝絕文友坐成睽間因以戲之','劉禹錫','唐','唐诗','tang','','[]','五月長齋戒，深居絕送迎。',120,'全唐诗/poet.tang.19000.json','["五月長齋戒，深居絕送迎。", "不離通德里，便是法王城。", "舉目皆僧事，全家少俗情。", "精修無上道，結念未來生。", "賓閤緇衣占，書堂信鼓鳴。", "戲童爲塔象，啼鳥學經聲。", "黍用青菰角，葵承玉露烹。", "馬家供薏苡，劉氏餉蕪菁。", "暗網籠歌扇，流塵晦酒鐺。", "不知何次道，作佛幾時成。"]'),
('34f4cb4c-c56a-4332-9a5d-d7fe611695e4','酬樂天晚夏閑居欲相訪先詩見貽','劉禹錫','唐','唐诗','tang','','[]','池榭堪臨泛，翛然散鬱陶。',72,'全唐诗/poet.tang.19000.json','["池榭堪臨泛，翛然散鬱陶。", "步因驅鶴緩，吟爲聽蟬高。", "林密添新竹，枝低縋晚桃。", "酒醅晴易熟，藥圃夏頻薅。", "老是班行舊，閑爲鄉里豪。", "經過更何處，風景屬吾曹。"]'),
('5b3c6981-de13-44c7-8ba8-2e0578a5693b','酬樂天醉後狂吟十韻','劉禹錫','唐','唐诗','tang','','[]','散誕人間樂，逍遙地上仙。',120,'全唐诗/poet.tang.19000.json','["散誕人間樂，逍遙地上仙。", "詩家登逸品，釋氏悟真筌。", "制誥留臺閣，歌詞入管弦。", "處身於木鴈，任世變桑田。", "吏隱情兼遂，儒玄道兩全。", "八關齋適罷，三雅興尤偏。", "文墨中年舊，松筠晚歲堅。", "魚書曾替代，香火有因緣。", "欲向醉鄉去，猶爲色界牽。", "好吹楊柳曲，爲我舞金鈿。"]'),
('7dd4b349-2ac3-4ac5-aebf-0667f90a082c','牛相公見示新什謹依本韻次用以抒下情','劉禹錫','唐','唐诗','tang','','[]','劇韻新篇至，因難始見能。',168,'全唐诗/poet.tang.19000.json','["劇韻新篇至，因難始見能。", "雨天龍變化，晴日鳳騫騰。", "遊海驚何極，聞韶素不曾。", "愜心時拊髀，擊節日麾肱。", "符彩添隃墨，波瀾起剡藤。", "揀金光熠熠，累璧勢層層。", "珠媚多藏賈，花撩欲定僧。", "封來真寶物，寄與媿交朋。", "已老無時疾，長貧望歲登。", "雀羅秋寂寂，蟲翅曉薨薨。", "羸驥方辭絆，虛舟已絕絙。", "榮華甘死別，健羨亦生憎。", "玉柱琤瑽韻，金觥雹凸棱。", "何時良宴會，促膝對華燈。"]'),
('33a6409a-a879-498e-a47e-3f61119593e6','奉和中書崔舍人八月十五日夜翫月二十韻','劉禹錫','唐','唐诗','tang','','[]','暮景中秋爽，陰靈既望圓。',240,'全唐诗/poet.tang.19000.json','["暮景中秋爽，陰靈既望圓。", "浮精離碧海，分照接虞淵。", "迥見孤輪出，高從倚蓋旋。", "二儀含皎澈，萬象共澄鮮。", "整御當西陸，舒光麗上玄。", "從星變風雨，順日助陶甄。", "遠近同時望，晶熒此夜偏。", "運行調玉燭，潔白應金天。", "曲沼疑瑤鏡，通衢若象筵。", "逢人盡冰雪，遇景即神仙。", "引素吞銀漢，凝清洗綠煙。", "臯禽警露下，鄰杵思風前。", "水是還珠浦，山成種玉田。", "劒沈三尺影，燈罷九枝然。", "象外形無迹，寰中影有遷。", "稍當雲闕正，未映斗城懸。", "靜對揮宸翰，閑臨襞彩牋。", "境同牛渚上，宿在鳳池邊。", "興掩尋安道，詞勝命仲宣。", "從今紙貴後，不復詠陳篇。"]'),
('a46c3e01-2dd9-42d0-8d96-13bae11ea2e0','奉和淮南李相公早秋即事寄成都武相公','劉禹錫','唐','唐诗','tang','','[]','八柱共承天，東西別隱然。',144,'全唐诗/poet.tang.19000.json','["八柱共承天，東西別隱然。", "遠夷爭慕化，真相故臨邊。", "竝進夔龍位，仍齊龜鶴年。", "同心舟已濟，造膝璧常聯。", "對領專征寄，遙持造物權。", "斗牛添氣色，井絡靜氛煙。", "獻可通三略，分甘出萬錢。", "漢南趨節制，趙北賜山川。", "玉帳觀渝舞，虹旌獵楚田。", "步嫌雙綬重，夢入九城偏。", "秋雨離情動，新詩樂府傳。", "聆音還竊抃，不覺撫么弦。"]'),
('fe6658ab-c063-458d-99dc-77ddf76f75ad','元和癸巳歲仲秋詔發江陵偏師問罪蠻徼後命宣慰釋兵歸降凱旋之辰率爾成詠寄荆南嚴司空','劉禹錫','唐','唐诗','tang','','[]','蠻水阻朝宗，兵符下渚宮。',144,'全唐诗/poet.tang.19000.json','["蠻水阻朝宗，兵符下渚宮。", "前籌得上策，無戰已成功。", "漢使星飛入，夷心草偃同。", "歌謠開竹棧，拜舞戢桑弓。", "就日知冰釋，投人念鳥窮。", "網羅三面解，章奏九門通。", "卉服聯操袂，雕題盡鞠躬。", "降幡秋練白，驛騎晝塵紅。", "火號休傳警，機橋罷亙空。", "登山不見虜，振斾自生風。", "江遠煙波靜，軍回氣色雄。", "佇看聞喜後，金石賜元戎。"]'),
('0bc78975-ade9-4fe2-8c2c-c4b46e62539a','和李六侍御文宣王廟釋奠作','劉禹錫','唐','唐诗','tang','','[]','歎息魯先師，生逢周室卑。',120,'全唐诗/poet.tang.19000.json','["歎息魯先師，生逢周室卑。", "有心律天道，無位救陵夷。", "歷聘不能用，領徒空爾爲。", "儒風正禮樂，旅象入蓍龜。", "西狩非其應，中都安足施。", "世衰由我賤，泣下爲人悲。", "遺教光文德，興王叶夢期。", "土田封後胤，冕服飾虛儀。", "鐘鼓膠庠薦，牲牢郡邑祠。", "聞君喟然歎，偏在上丁時。"]'),
('fb3d578d-24c9-4cdf-acf2-8ee5ea6ae584','和竇中丞晚入容江作','劉禹錫','唐','唐诗','tang','','[]','漢郡三十六，鬱林東南遙。',96,'全唐诗/poet.tang.19000.json','["漢郡三十六，鬱林東南遙。", "人倫選清臣，天外頒詔條。", "桂水步秋浪，火山凌霧朝。", "分圻辨風物，入境聞謳謠。", "莎岸見長亭，煙林隔麗譙。", "日落舟益駛，川平旗自飄。", "珠浦遠明滅，金沙晴動搖。", "一吟道中作，離思懸層霄。"]'),
('b849afe9-f7db-4f53-b688-fafa65b264f1','南海馬大夫見惠著述三通勒成四帙上自邃古達于國朝采其菁華至簡如富欽受嘉貺詩以謝之','劉禹錫','唐','唐诗','tang','','[]','紅旗閱五兵，絳帳領諸生。',72,'全唐诗/poet.tang.19000.json','["紅旗閱五兵，絳帳領諸生。", "味道輕鼎食，退公猶筆耕。", "青箱傳學遠，金匱納書成。", "一瞬見前事，九流當抗行。", "編蒲曾苦思，垂竹媿無名。", "今日承芳訊，誰言贈衮榮。"]'),
('11e7048c-4997-4a3d-989a-008e2c88733f','和楊侍郎初至郴州紀事書情題郡齋八韻','劉禹錫','唐','唐诗','tang','','[]','旌節下朝臺，分圭從北回。',96,'全唐诗/poet.tang.19000.json','["旌節下朝臺，分圭從北回。", "城頭鶴立處，驛樹鳳栖來。", "舊路芳塵在，新恩馹騎催。", "里閭風偃草，鼓舞抃成雷。", "吏散山禽囀，庭香夏蕊開。", "郡齋堪四望，壁記有三台。", "人訝徵黃晚，文非弔屈哀。", "一吟梁甫曲，知是臥龍才。"]'),
('8fb030e1-a5a9-4892-87e9-37a6e15ec01b','和東川王相公新漲驛池八韻','劉禹錫','唐','唐诗','tang','','[]','今日池塘上，初移造物權。',96,'全唐诗/poet.tang.19000.json','["今日池塘上，初移造物權。", "苞藏成別島，沿濁致清漣。", "變化生言下，蓬瀛落眼前。", "泛觴驚翠羽，開幕對紅蓮。", "遠寫風光入，明含氣象全。", "渚煙籠驛樹，波日漾寶筵。", "曲岸留緹騎，中流轉綵船。", "無因接元禮，共載比神仙。"]'),
('4fdf8255-c250-4a77-ad9e-7bdf6bd865f6','酬楊八庶子喜韓吳興與余同遷見贈','劉禹錫','唐','唐诗','tang','','[]','早遇聖明朝，鴈行登九霄。',192,'全唐诗/poet.tang.19000.json','["早遇聖明朝，鴈行登九霄。", "文輕傅武仲，酒逼蓋寬饒。", "捨矢同瞻鵠，當筵共賽梟。", "琢磨三益重，唱和五音調。", "臺柏煙常起，池荷香暗飄。", "星文辭北極，旗影度東遼。", "直道由來黜，浮名豈敢要。", "三湘與百越，雨散又雲搖。", "遠守慙侯籍，徵還荷詔條。", "顇容唯舌在，別恨幾魂銷。", "滿眼悲陳事，逢人少舊僚。", "煙霞爲老伴，蒲柳任先凋。", "虎綬懸新印，龍舼理去橈。", "斷腸天北郡，攜手洛陽橋。", "幢蓋今雖貴，弓旌會見招。", "其如草玄客，空宇久寥寥。"]'),
('6a11b0a8-68ea-44f1-ac31-bb371656d4f7','和兵部鄭侍郎省中四松詩十韻','劉禹錫','唐','唐诗','tang','','[]','右相歷中臺，移松武庫栽。',120,'全唐诗/poet.tang.19000.json','["右相歷中臺，移松武庫栽。", "紫茸抽組綬，青實長玫瑰。", "便有干霄勢，看成搆廈材。", "數分天柱半，影逐日輪回。", "舊賞台階去，新知谷口來。", "息陰常仰望，翫境幾裴回。", "翠粒晴懸露，蒼鱗雨起苔。", "凝音助瑤瑟，飄蘂泛金罍。", "月桂花遙燭，星榆葉對開。", "終須似雞樹，榮茂近昭回。"]'),
('6a555628-6a30-4939-8803-eafa1d7918de','酬鄭州權舍人見寄十二韻','劉禹錫','唐','唐诗','tang','','[]','朱戶凌晨啓，碧梧含早涼。',240,'全唐诗/poet.tang.19000.json','["朱戶凌晨啓，碧梧含早涼。", "人從桔柣至，書到漆沮傍。", "抃會因佳句，情深取斷章。", "愜心同笑語，入耳勝笙簧。", "憶昔三條路，居鄰數仞牆。", "學堂青玉案，綵服紫羅囊。", "麟角看成就，龍駒見抑揚。", "彀中飛一箭，雲際落雙鶬。", "甸邑叨前列，天臺媿後行。", "鯉庭傳事業，雞樹遂翱翔。", "書殿連鳷鵲，神池接鳳凰。", "追遊蒙尚齒，惠好結中腸。", "鎩翮方擡舉，危根易損傷。", "一麾憐棄置，五字借恩光。", "汝海崆峒秀，溱流芍藥芳。", "風行能偃草，境靜不爭桑。", "轉斾趨關右，頒條匝渭陽。", "病吟猶有思，老醉已無狂。", "塵滿鴻溝道，沙驚白狄鄉。", "佇聞黃紙詔，促召紫微郎。"]'),
('330863e1-a65d-49ae-a540-191e0293ce67','和牛相公題姑蘇所寄太湖石兼寄李蘇州','劉禹錫','唐','唐诗','tang','','["\u592a\u6e56"]','震澤生奇石，沈潛得地靈。',240,'全唐诗/poet.tang.19000.json','["震澤生奇石，沈潛得地靈。", "初辭水府出，猶帶龍宮腥。", "發自江湖國，來榮卿相庭。", "從風夏雲勢，上漢古查形。", "拂拭魚鱗見，鏗鏘玉韻聆。", "煙波含宿潤，苔蘚助新青。", "嵌穴胡雛貌，纖鋩蟲篆銘。", "孱顏傲林薄，飛動向雷霆。", "煩熱近還散，餘酲見便醒。", "凡禽不敢息，浮壒莫能停。", "靜稱垂松蓋，鮮宜映鶴翎。", "忘憂常目擊，素尚與心冥。", "眇小欺湘燕，團圓笑落星。", "徒然想融結，安可測年齡。", "採取詢鄉耋，搜求按舊經。", "垂鉤入空隙，隔浪動晶熒。", "有獲人爭賀，歡謠衆共聽。", "一州驚閱寶，千里遠揚舲。", "覩物洛陽陌，懷人吳御亭。", "寄言垂天翼，早晚起滄溟。"]'),
('ba571c1a-7567-479c-a7eb-19b7ade65797','浙西李大夫述夢四十韻幷浙東元相公酬和斐然繼聲','劉禹錫','唐','唐诗','tang','','[]','位是才能取，時因際會遭。',288,'全唐诗/poet.tang.19000.json','["位是才能取，時因際會遭。", "羽儀呈鸑鷟，鋩刃試豪曹。", "洛下推年少，山東許地高。", "門承金鉉鼎，家有玉璜韜。", "海浪扶鵬翅，天風引驥髦。", "便知蓬閣閟，不識魯衣襃。", "興發春塘草，魂交益部刀。", "形開猶抱膝，燭盡遽揮毫。", "昔仕當初筮，逢時詠載橐。", "懷鉛辨蟲蠹，染素學鵝毛。", "車騎方休汝，歸來欲效陶。", "南臺資謇諤，內署選風騷。", "羽化如乘鯉，樓居舊冠鼇。", "美香焚濕麝，名果賜乾萄。", "議赦蠅棲筆，邀歌蟻泛醪。", "代言無所戲，謝表自稱叨。", "蘭焰凝芳澤，芝泥瑩玉膏。", "對頻聲價出，直久夢魂勞。", "草詔令歸馬，批章答獻獒。", "銀花懸院牓，翠羽映簾條。", "諷諫欣然納，奇觚率爾操。", "禁中時諤諤，天下免忉忉。", "左顧龜成印，雙飛鵠織袍。", "謝賓緣地密，潔己是心豪。"]'),
('97d303a2-b213-4dbe-be84-2d326749da82','和浙西李大夫伊川卜居','劉禹錫','唐','唐诗','tang','','[]','早入八元數，嘗承三接恩。',144,'全唐诗/poet.tang.19000.json','["早入八元數，嘗承三接恩。", "飛鳴天上路，鎮壓海西門。", "清望寰中許，高情物外存。", "時來誠不讓，歸去每形言。", "洛下思招隱，江干壓作藩。", "按經修道具，依樣買山村。", "開鑿隨人化，幽陰爲律暄。", "遠移難得樹，立變舊荒園。", "絕塞通潛徑，平泉占上原。", "煙霞遙在想，簿領益爲繁。", "丹禁虛東閤，蒼生望北轅。", "徒令雙白鶴，五里自翩飜。"]'),
('84fcd5fc-e632-4f23-bfb4-635e3efdb94a','省試風光草際浮','劉禹錫','唐','唐诗','tang','','[]','熙熙春景霽，草綠春光麗。',72,'全唐诗/poet.tang.19000.json','["熙熙春景霽，草綠春光麗。", "的歷亂相鮮，葳蕤互虧蔽。", "乍疑芊綿裏，稍動丰茸際。", "影碎翻崇蘭，浮香轉叢蕙。", "含煙絢碧綵，帶露如珠綴。", "幸因採掇日，況此臨芳歲。"]'),
('03f95638-e26e-4d37-a829-0d141eea7989','歷陽書事七十韻','劉禹錫','唐','唐诗','tang','','[]','一夕爲湖地，千年列郡名。',288,'全唐诗/poet.tang.19000.json','["一夕爲湖地，千年列郡名。", "霸王迷路處，亞父所封城。", "漢置東南尉，梁分肘腋兵。", "本吳風俗剽，兼楚語音傖。", "沸井今無湧，烏江舊有名。", "土臺遊柱史，石室隱彭鏗。", "曹操祠猶在，濡須塢未平。", "海潮隨月大，江水應春生。", "憶昨深山裏，終朝看火耕。", "魚書來北闕，鷁首下南荆。", "雲雨巫山暗，蕙蘭湘水清。", "章華樹已失，鄂渚草來迎。", "廬阜香爐出，湓城粉堞明。", "鴈飛彭蠡暮，鴉噪大雷晴。", "平野分風使，恬和趁夜程。", "貴池登陸峻，舂穀渡橋鳴。", "駱驛主人問，悲歡故舊情。", "幾年方一面，卜晝便三更。", "助喜杯盤盛，忘機笑語訇。", "管清疑警鶴，弦巧似嬌鶯。", "熾炭烘蹲獸，華茵織鬬鯨。", "回裾飄霧雨，急節墮瓊英。", "斂黛凝愁色，施鈿耀翠晶。", "容華本南國，妝束學西京。"]'),
('36f4450b-ab48-4dad-8d98-a1f7ae6c66e9','和武中丞秋日寄懷簡諸僚故','劉禹錫','唐','唐诗','tang','','[]','退朝還公府，騎吹息繁陰。',96,'全唐诗/poet.tang.19000.json','["退朝還公府，騎吹息繁陰。", "吏散秋庭寂，烏啼煙樹深。", "威生奉白簡，道勝外華簪。", "風物清遠目，功名懷寸陰。", "雲衢念前侶，綵翰寫沖襟。", "涼菊照幽徑，敗荷攢碧潯。", "感時江海思，報國松筠心。", "空愧壽陵步，芳塵何處尋。"]'),
('a4027d74-3867-4341-ad57-5248746e36a5','和令狐相公春日尋花有懷白侍郎閣老','劉禹錫','唐','唐诗','tang','','[]','芳菲滿雍州，鸞鳳許同遊。',72,'全唐诗/poet.tang.19000.json','["芳菲滿雍州，鸞鳳許同遊。", "花逕須深入，時光不少留。", "色鮮由樹嫩，枝亞爲房稠。", "靜對仍持酒，高看特上樓。", "晴宜連夜賞，雨便一年休。", "共憶秋官處，餘霞曲水頭。"]'),
('7809c5ca-acce-4065-b56e-00d6d2f04440','荆州歌二首 一','劉禹錫','唐','唐诗','tang','','[]','渚宮楊柳暗，麥城朝雉飛。',24,'全唐诗/poet.tang.19000.json','["渚宮楊柳暗，麥城朝雉飛。", "可憐踏青伴，乘暖著輕衣。"]'),
