('bda5af9d-8f84-485a-af43-f396ba111ba2','楊柳枝詞九首 七','劉禹錫','唐','唐诗','tang','','[]','御陌青門拂地垂，千條金縷萬條絲。',32,'全唐诗/poet.tang.19000.json','["御陌青門拂地垂，千條金縷萬條絲。", "如今綰作同心結，將贈行人知不知。"]'),
('e510d91c-2ffa-453d-8a11-8e1589bee761','楊柳枝詞九首 八','劉禹錫','唐','唐诗','tang','','[]','城外春風吹酒旗，行人揮袂日西時。',32,'全唐诗/poet.tang.19000.json','["城外春風吹酒旗，行人揮袂日西時。", "長安陌上無窮樹，唯有垂楊管別離。"]'),
('ae8387df-26b1-427d-802b-dc20c9095d73','楊柳枝詞九首 九','劉禹錫','唐','唐诗','tang','','[]','輕盈嫋娜占年華，舞榭妝樓處處遮。',32,'全唐诗/poet.tang.19000.json','["輕盈嫋娜占年華，舞榭妝樓處處遮。", "春盡絮花留不得，隨風好去落誰家。"]'),
('b0f61bf4-5c31-4875-a33f-97de1a1560d2','浪淘沙九首 一','劉禹錫','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u751f\u6d3b", "\u7530\u56ed", "\u4e94\u5e74\u7ea7\u4e0b\u518c", "\u5411\u5f80"]','九曲黃河萬里沙，浪淘風簸自天涯。',32,'全唐诗/poet.tang.19000.json','["九曲黃河萬里沙，浪淘風簸自天涯。", "如今直上銀河去，同到牽牛織女家。"]'),
('f01e5b9e-7577-4eac-8b92-29963022ef7e','浪淘沙九首 二','劉禹錫','唐','唐诗','tang','','[]','洛水橋邊春日斜，碧流清淺見瓊砂。',32,'全唐诗/poet.tang.19000.json','["洛水橋邊春日斜，碧流清淺見瓊砂。", "無端陌上狂風急，驚起鴛鴦出浪花。"]'),
('8ac6a6e5-66cc-4b4b-adda-65874ce18197','浪淘沙九首 三','劉禹錫','唐','唐诗','tang','','[]','汴水東流虎眼紋，清淮曉色鴨頭春。',32,'全唐诗/poet.tang.19000.json','["汴水東流虎眼紋，清淮曉色鴨頭春。", "君看渡口淘沙處，渡却人間多少人。"]'),
('30df2a91-7606-46b7-927a-0f1c7f2a6de1','浪淘沙九首 四','劉禹錫','唐','唐诗','tang','','[]','鸚鵡洲頭浪颭沙，青樓春望日將斜。',32,'全唐诗/poet.tang.19000.json','["鸚鵡洲頭浪颭沙，青樓春望日將斜。", "銜泥燕子爭歸舍，獨自狂夫不憶家。"]'),
('a9a7db27-2e80-4973-8bfb-30430c70e147','浪淘沙九首 五','劉禹錫','唐','唐诗','tang','','[]','濯錦江邊兩岸花，春風吹浪正淘沙。',32,'全唐诗/poet.tang.19000.json','["濯錦江邊兩岸花，春風吹浪正淘沙。", "女郎剪下鴛鴦錦，將向中流疋晚霞。"]'),
('82f26fde-fc47-4c9f-b84c-0a53760dcba2','浪淘沙九首 六','劉禹錫','唐','唐诗','tang','','[]','日照澄洲江霧開，淘金女伴滿江隈。',32,'全唐诗/poet.tang.19000.json','["日照澄洲江霧開，淘金女伴滿江隈。", "美人首飾侯王印，盡是沙中浪底來。"]'),
('25cc9c38-bca2-4fcb-b3f1-4d9f7c548283','浪淘沙九首 七','劉禹錫','唐','唐诗','tang','','[]','八月濤聲吼地來，頭高數丈觸山回。',32,'全唐诗/poet.tang.19000.json','["八月濤聲吼地來，頭高數丈觸山回。", "須臾却入海門去，卷起沙堆似雪堆。"]'),
('10a05f66-355d-4cc8-9a16-50c0fd7d8aac','浪淘沙九首 八','劉禹錫','唐','唐诗','tang','','[]','莫道讒言如浪深，莫言遷客似沙沉。',32,'全唐诗/poet.tang.19000.json','["莫道讒言如浪深，莫言遷客似沙沉。", "千淘萬漉雖辛苦，吹盡狂沙始到金。"]'),
('ff4db6be-59c1-48b9-b49c-f741da35d197','浪淘沙九首 九','劉禹錫','唐','唐诗','tang','','[]','流水淘沙不暫停，前波未滅後波生。',32,'全唐诗/poet.tang.19000.json','["流水淘沙不暫停，前波未滅後波生。", "令人忽憶瀟湘渚，回唱迎神三兩聲。"]'),
('3861b957-d5e8-4378-b18e-b2df91f3c463','洛中送韓七中丞之吳興口號五首 一','劉禹錫','唐','唐诗','tang','','[]','昔年意氣結羣英，幾度朝回一字行。',32,'全唐诗/poet.tang.19000.json','["昔年意氣結羣英，幾度朝回一字行。", "海北江南零落盡，兩人相見洛陽城。"]'),
('140c0694-f46b-403b-b4f7-7d4091987d83','洛中送韓七中丞之吳興口號五首 二','劉禹錫','唐','唐诗','tang','','[]','自從雲散各東西，每日歡娛却慘悽。',32,'全唐诗/poet.tang.19000.json','["自從雲散各東西，每日歡娛却慘悽。", "離別苦多相見少，一生心事在書題。"]'),
('addc88f8-af29-4f67-b55b-1278aa550eb1','洛中送韓七中丞之吳興口號五首 三','劉禹錫','唐','唐诗','tang','','[]','今朝無意訴離杯，何況清弦急管催。',32,'全唐诗/poet.tang.19000.json','["今朝無意訴離杯，何況清弦急管催。", "本欲醉中輕遠別，不知翻引酒悲來。"]'),
('cb347c3d-d86d-4941-9d38-ae4a8a776f97','洛中送韓七中丞之吳興口號五首 四','劉禹錫','唐','唐诗','tang','','[]','駱駝橋上蘋風急，鸚鵡杯中箬下春。',32,'全唐诗/poet.tang.19000.json','["駱駝橋上蘋風急，鸚鵡杯中箬下春。", "水碧山青知好處，開顏一笑向何人。"]'),
('9d171f79-2daa-4af8-af86-bf7b5512374d','洛中送韓七中丞之吳興口號五首 五','劉禹錫','唐','唐诗','tang','','[]','溪中士女出笆籬，溪上鴛鴦避畫旗。',32,'全唐诗/poet.tang.19000.json','["溪中士女出笆籬，溪上鴛鴦避畫旗。", "何處人間似仙境，春山攜妓採茶時。"]'),
('8f625f26-80bb-4d9c-8080-ae4e2dbd01a4','送廖參謀東遊二首 一','劉禹錫','唐','唐诗','tang','','[]','九陌逢君又別離，行雲別鶴本無期。',32,'全唐诗/poet.tang.19000.json','["九陌逢君又別離，行雲別鶴本無期。", "望嵩樓上忽相見，看過花開花落時。"]'),
('dab42484-7a1a-4ffd-bfce-4c9b5cb5463e','送廖參謀東遊二首 二','劉禹錫','唐','唐诗','tang','','[]','繁花落盡君辭去，綠草垂楊引征路。',32,'全唐诗/poet.tang.19000.json','["繁花落盡君辭去，綠草垂楊引征路。", "東道諸侯皆故人，留連必是多情處。"]'),
('f92f8c8a-3448-453e-9fb1-af43970a5d52','洛中春末送杜錄事赴蘄州','劉禹錫','唐','唐诗','tang','','[]','樽前花下長相見，明日忽爲千里人。',32,'全唐诗/poet.tang.19000.json','["樽前花下長相見，明日忽爲千里人。", "君過午橋回首望，洛城猶自有殘春。"]'),
