('d12186f8-919b-4f5e-9eee-beac6259aefe','送霄韻上人遊天台','劉禹錫','唐','唐诗','tang','','[]','曲江僧向松江見，又到天台看石橋。',32,'全唐诗/poet.tang.19000.json','["曲江僧向松江見，又到天台看石橋。", "鶴戀故巢雲戀岫，比君猶自不逍遙。"]'),
('e9c687d1-395c-464c-b931-51b3e77a74e8','臺城懷古','劉禹錫','唐','唐诗','tang','','[]','清江悠悠王氣沉，六朝遺事何處尋。',32,'全唐诗/poet.tang.19000.json','["清江悠悠王氣沉，六朝遺事何處尋。", "宮牆隱嶙圍野澤，鸛鶂夜鳴秋色深。"]'),
('7a21f2b2-07df-45f7-928c-ade985b22bea','戲贈崔千牛','劉禹錫','唐','唐诗','tang','','[]','學道深山許老人，留名萬代不關身。',32,'全唐诗/poet.tang.19000.json','["學道深山許老人，留名萬代不關身。", "勸君多買長安酒，南陌東城占取春。"]'),
('1565ee71-07ab-4a52-8cf4-4749c9485232','揚州春夜李端公益張侍御登段侍御平路密縣李少府畼秘書張正字復元同會於水館對酒聯句追刻燭擊銅缽故事遲輒舉觥以飲之逮夜艾羣公沾醉紛然就枕余偶獨醒因題詩於段君枕上以志其事','劉禹錫','唐','唐诗','tang','','[]','寂寂獨看金燼落，紛紛只見玉山頽。',32,'全唐诗/poet.tang.19000.json','["寂寂獨看金燼落，紛紛只見玉山頽。", "自羞不是高陽侶，一夜星星騎馬回。"]'),
('b694fdfc-0281-457e-9d6b-831b5e9e97ac','逢王十二學士入翰林因以詩贈','劉禹錫','唐','唐诗','tang','','[]','廄馬翩翩禁外逢，星槎上漢杳難從。',32,'全唐诗/poet.tang.19000.json','["廄馬翩翩禁外逢，星槎上漢杳難從。", "定知欲報淮南詔，促召王褒入九重。"]'),
('e4d6fe3c-1d4f-4e0d-8822-d4703adb4859','闕下口號呈柳儀曹','劉禹錫','唐','唐诗','tang','','[]','綵仗神旗獵曉風，雞人一唱鼓蓬蓬。',32,'全唐诗/poet.tang.19000.json','["綵仗神旗獵曉風，雞人一唱鼓蓬蓬。", "銅壺漏水何時歇，如此相催即老翁。"]'),
('ad92f601-058c-42e6-88b6-05dbaa831e97','監祠夕月壇書事','劉禹錫','唐','唐诗','tang','','[]','西皥司分晝夜平，羲和停午太陰生。',32,'全唐诗/poet.tang.19000.json','["西皥司分晝夜平，羲和停午太陰生。", "鏗鏘揖讓秋光裏，觀者如雲出鳳城。"]'),
('a42d87f4-4427-4933-90d9-d25d0192f409','元和甲午歲詔書盡徵江湘逐客余自武陵赴京宿於都亭有懷續來諸君子','劉禹錫','唐','唐诗','tang','','[]','雷雨江山起臥龍，武陵樵客躡仙蹤。',32,'全唐诗/poet.tang.19000.json','["雷雨江山起臥龍，武陵樵客躡仙蹤。", "十年楚水楓林下，今夜初聞長樂鐘。"]'),
('29d444cc-e2a3-467a-a6f9-adfb9465e09e','元和十一年自朗州召至京戲贈看花諸君子','劉禹錫','唐','唐诗','tang','','[]','紫陌紅塵拂面來，無人不道看花回。',32,'全唐诗/poet.tang.19000.json','["紫陌紅塵拂面來，無人不道看花回。", "玄都觀裏桃千樹，盡是劉郎去後栽。"]'),
('82833199-92e1-4499-8d37-92a78299f1a4','再遊玄都觀','劉禹錫','唐','唐诗','tang','','[]','百畝庭中半是苔，桃花淨盡菜花開。',32,'全唐诗/poet.tang.19000.json','["百畝庭中半是苔，桃花淨盡菜花開。", "種桃道士歸何處，前度劉郎今又來。"]'),
('65a67416-3820-4312-9cd1-a0e852a6f972','與歌者米嘉榮','劉禹錫','唐','唐诗','tang','','[]','唱得涼州意外聲，舊人唯數米嘉榮。',32,'全唐诗/poet.tang.19000.json','["唱得涼州意外聲，舊人唯數米嘉榮。", "近來時世輕先輩，好染髭鬚事後生。"]'),
('b0826a24-d535-4694-afc4-9818a327c2ab','望夫石','劉禹錫','唐','唐诗','tang','','["\u601d\u5ff5", "\u4e08\u592b", "\u5987\u5973"]','終日望夫夫不歸，化爲孤石苦相思。',32,'全唐诗/poet.tang.19000.json','["終日望夫夫不歸，化爲孤石苦相思。", "望來已是幾千載，只似當時初望時。"]'),
('7734c93d-ef83-4857-abc1-07708e9099b3','聽舊宮中樂人穆氏唱歌','劉禹錫','唐','唐诗','tang','','[]','曾隨織女渡天河，記得雲間第一歌。',32,'全唐诗/poet.tang.19000.json','["曾隨織女渡天河，記得雲間第一歌。", "休唱貞元供奉曲，當時朝士已無多。"]'),
('f0e03469-e857-45ba-8d0e-128339365f0f','金陵五題 石頭城','劉禹錫','唐','唐诗','tang','','["\u548f\u7269", "\u548f\u53f2\u6000\u53e4", "\u548f\u7269\u8bd7", "\u5e26\u6709\u5730\u540d", "\u5730\u540d"]','山圍故國周遭在，潮打空城寂寞回。',32,'全唐诗/poet.tang.19000.json','["山圍故國周遭在，潮打空城寂寞回。", "淮水東邊舊時月，夜深還過女牆來。"]'),
('4fa92777-9bd6-45ca-9272-bac30459cf5e','金陵五題 烏衣巷','劉禹錫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6000\u53e4", "\u4e03\u8a00\u7edd\u53e5", "\u5e26\u6709\u5730\u540d", "\u5730\u540d"]','朱雀橋邊野草花，烏衣巷口夕陽斜。',32,'全唐诗/poet.tang.19000.json','["朱雀橋邊野草花，烏衣巷口夕陽斜。", "舊時王謝堂前燕，飛入尋常百姓家。"]'),
('e1f9f0cf-2d5f-45f0-a475-1be8b4270d7d','金陵五題 臺城','劉禹錫','唐','唐诗','tang','','[]','臺城六代競豪華，結綺臨春事最奢。',32,'全唐诗/poet.tang.19000.json','["臺城六代競豪華，結綺臨春事最奢。", "萬戶千門成野草，只緣一曲後庭花。"]'),
