('9b64dd5a-fad5-44ee-ab8a-a95341fb0760','赴連山途次德宗山陵寄張員外','劉禹錫','唐','唐诗','tang','','[]','常時並冕奉天顏，委佩低簪彩仗間。',32,'全唐诗/poet.tang.19000.json','["常時並冕奉天顏，委佩低簪彩仗間。", "今日獨來張樂地，萬重雲水望橋山。"]'),
('2da45dd5-10b3-4d7c-93df-3e86997313f5','嘗茶','劉禹錫','唐','唐诗','tang','','[]','生拍芳叢鷹觜芽，老郎封寄謫仙家。',32,'全唐诗/poet.tang.19000.json','["生拍芳叢鷹觜芽，老郎封寄謫仙家。", "今宵更有湘江月，照出菲菲滿盌花。"]'),
('5427e8da-e121-4b37-b206-0359bbe7a1c1','梁國祠','劉禹錫','唐','唐诗','tang','','[]','梁國三郎威德尊，女巫簫鼓走鄉村。',32,'全唐诗/poet.tang.19000.json','["梁國三郎威德尊，女巫簫鼓走鄉村。", "萬家長見空山上，雨氣蒼茫生廟門。"]'),
('63f618fd-aa42-48ed-806c-41176fec9abe','望洞庭','劉禹錫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u56db\u5e74\u7ea7\u4e0b\u518c", "\u5c71\u6c34", "\u5199\u666f", "\u666f\u70b9", "\u5c0f\u5b66\u53e4\u8bd7"]','湖光秋月兩相和，潭面無風鏡未磨。',32,'全唐诗/poet.tang.19000.json','["湖光秋月兩相和，潭面無風鏡未磨。", "遙望洞庭山水翠，白銀盤裏一青螺。"]'),
('fe4b1751-5414-444e-9f9e-7fae7d38cdff','楊柳枝','劉禹錫','唐','唐诗','tang','','["\u6000\u4eba", "\u67f3\u6811"]','春江一曲柳千條，二十年前舊板橋。',32,'全唐诗/poet.tang.19000.json','["春江一曲柳千條，二十年前舊板橋。", "曾與美人橋上別，恨無消息到今朝。"]'),
('29e12604-4708-4c68-9d61-6d313c3a7a01','樓上','劉禹錫','唐','唐诗','tang','','[]','江上樓高二十梯，梯梯登徧與雲齊。',32,'全唐诗/poet.tang.19000.json','["江上樓高二十梯，梯梯登徧與雲齊。", "人從別浦經年去，天向平蕪盡處低。"]'),
('d5ac076b-9170-4aa1-b6a4-c67a96445b79','洛濱病臥戶部李侍郎見惠藥物謔以文星之句斐然仰謝','劉禹錫','唐','唐诗','tang','','[]','隱几支頤對落暉，故人書信到柴扉。',32,'全唐诗/poet.tang.19000.json','["隱几支頤對落暉，故人書信到柴扉。", "周南留滯商山老，星象如今屬少微。"]'),
('59f8f90e-1d85-45e9-9f1f-37e0c41f1e54','故洛城古牆','劉禹錫','唐','唐诗','tang','','[]','粉落椒飛知幾春，風吹雨灑旋成塵。',32,'全唐诗/poet.tang.19000.json','["粉落椒飛知幾春，風吹雨灑旋成塵。", "莫言一片危基在，猶過無窮來往人。"]'),
('8bd51641-ede0-4569-9ddc-12fdb255ff2e','句','劉禹錫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','湖上收宿雨，故國思如此。',48,'全唐诗/poet.tang.19000.json','["湖上收宿雨，故國思如此。", "若爲天外心，東屯滄海闊。", "南讓洞庭寬，翠粒照晴露。", "銀花垂院牓，翠羽撼絛鈴。"]'),
('da254237-36a9-4eec-b44c-47058833c411','山亭懷古','張弘靖','唐','唐诗','tang','','[]','叢石依古城，懸泉灑清池。',48,'全唐诗/poet.tang.19000.json','["叢石依古城，懸泉灑清池。", "高低袤丈內，衡霍相蔽虧。", "歸田竟何因，爲郡豈所宜。", "誰能辨人野，寄適聊在斯。"]'),
('12917272-66e2-4bf0-907d-2d259a3b8b10','和張相公太原山亭懷古詩','韓察','唐','唐诗','tang','','[]','公府政多暇，思與仁智全。',48,'全唐诗/poet.tang.19000.json','["公府政多暇，思與仁智全。", "爲山想巖穴，引水聽潺湲。", "軒冕迹自逸，塵俗無由牽。", "蒼生方矚望，詎得賦歸田。"]'),
('7f252a74-bab6-43d4-ae9c-5572a0530c42','和張相公太原山亭懷古詩','崔恭','唐','唐诗','tang','','[]','高情樂閑放，寄跡山水中。',48,'全唐诗/poet.tang.19000.json','["高情樂閑放，寄跡山水中。", "朝霞鋪座右，虛白貯清風。", "潛竇激飛泉，石路躋且崇。", "步武有勝概，不與俗情同。"]'),
('96fd51b9-ca03-4a78-87e2-b760e7d95a74','和張相公太原山亭懷古詩','陸瀍','唐','唐诗','tang','','[]','激水瀉飛瀑，寄懷良在茲。',48,'全唐诗/poet.tang.19000.json','["激水瀉飛瀑，寄懷良在茲。", "如何謝安石，要結東山期。", "入座蘭蕙馥，當軒松桂滋。", "於焉悟幽道，境寂心自怡。"]'),
('4538510b-62de-4da9-8791-4b5b45eceaa5','和張相公太原亭懷古詩','胡[証]','唐','唐诗','tang','','[]','飛泉天台狀，峭石蓬萊姿。',48,'全唐诗/poet.tang.19000.json','["飛泉天台狀，峭石蓬萊姿。", "潺湲與青翠，咫尺當幽奇。", "居然盡精道，得以書妍詞。", "豈無他山勝，懿此清軒墀。"]'),
('9d68c454-9ece-40e2-b65e-207175f540c0','句','胡[証]','唐','唐诗','tang','','[]','詩書入京國，旌斾過鄉關。',12,'全唐诗/poet.tang.19000.json','["詩書入京國，旌斾過鄉關。"]'),
('56b4c2ad-8c27-4d0a-ac7c-4f4e4f266701','和太原山亭懷古詩','張賈','唐','唐诗','tang','','[]','中庭起崖谷，漱玉下漣漪。',48,'全唐诗/poet.tang.19000.json','["中庭起崖谷，漱玉下漣漪。", "丹丘誰云遠，寓象得心期。", "豈不貴鍾鼎，至懷在希夷。", "唯當蓬萊閣，靈鳳復來儀。"]'),
('b65fa19a-721a-40c6-b64b-d6867ffb8a8b','和裴司空答張祕書贈馬詩','張賈','唐','唐诗','tang','','[]','閣下從容舊客卿，寄來駿馬賞高情。',64,'全唐诗/poet.tang.19000.json','["閣下從容舊客卿，寄來駿馬賞高情。", "任追煙景騎仍醉，知有文章倚便成。", "步步自憐春日影，蕭蕭猶起朔風聲。", "須知上宰吹噓意，送入天門上路行。"]'),
('707a92e3-4560-47e5-8bbe-5ceff0e85bc2','句','張賈','唐','唐诗','tang','','[]','夫子生知者，相期妙理中。',12,'全唐诗/poet.tang.19000.json','["夫子生知者，相期妙理中。"]'),
('080ad915-4f82-48a9-820a-7d25758e5742','吳興三絕','張文規','唐','唐诗','tang','','[]','蘋洲須覺池沼俗，苧布直勝羅紈輕。',48,'全唐诗/poet.tang.19000.json','["蘋洲須覺池沼俗，苧布直勝羅紈輕。", "清風樓下草初出，明月峽中茶始生。", "吳興三絕不可捨，勸子強爲吳會行。"]'),
('f44b8de6-f634-4dcd-9976-675e2f0e9507','湖州貢焙新茶','張文規','唐','唐诗','tang','','[]','鳳輦尋春半醉回，僊娥進水御簾開。',32,'全唐诗/poet.tang.19000.json','["鳳輦尋春半醉回，僊娥進水御簾開。", "牡丹花笑金鈿動，傳奏吳興紫筍來。"]'),
('b3217593-db7c-425d-bbc2-012c956c9b7d','句','張文規','唐','唐诗','tang','','[]','誰云隼旟吏，長對虎頭巖。',12,'全唐诗/poet.tang.19000.json','["誰云隼旟吏，長對虎頭巖。"]'),
('6fe52a30-0b0b-4be5-aa09-b2c992d4ef65','緱山鶴','張仲素','唐','唐诗','tang','','[]','羽客驂仙鶴，將飛駐碧山。',72,'全唐诗/poet.tang.19000.json','["羽客驂仙鶴，將飛駐碧山。", "映松殘雪在，度嶺片雲還。", "清唳因風遠，高姿對水閑。", "笙歌憶天上，城郭歎人間。", "幾變霜毛潔，方殊藻質斑。", "迢迢煙路逸，奮翮詎能攀。"]'),
('7102c9d2-43aa-4f28-81c5-7882e900053e','夜聞洛濱吹笙','張仲素','唐','唐诗','tang','','[]','王子千年後，笙音五夜聞。',72,'全唐诗/poet.tang.19000.json','["王子千年後，笙音五夜聞。", "逶迤繞清洛，斷續下仙雲。", "泄泄飄難定，啾啾曲未分。", "松風助幽律，波月動輕文。", "鳳管聽何遠，鸞聲若在羣。", "暗空思羽蓋，餘氣自氛氳。"]'),
('bfd2fd75-564e-464c-873a-c851f04155dd','上元日聽太清宮步虛','張仲素','唐','唐诗','tang','','[]','仙客開金籙，元辰會玉京。',72,'全唐诗/poet.tang.19000.json','["仙客開金籙，元辰會玉京。", "靈歌賓紫府，雅韻出層城。", "磬雜音徐徹，風飄響更清。", "紆餘空外盡，斷續聽中生。", "舞鶴紛將集，流雲住未行。", "誰知九陌上，塵俗仰遺聲。"]'),
('07fd95d4-b5ff-4b27-a23f-2df0264d0bf8','玉繩低建章','張仲素','唐','唐诗','tang','','[]','迢迢玉繩下，芒彩正闌干。',72,'全唐诗/poet.tang.19000.json','["迢迢玉繩下，芒彩正闌干。", "稍復臨鳷鵲，方疑近露寒。", "微明連粉堞，的皪映仙盤。", "橫接河流照，低將夜色殘。", "天榆隨影沒，宮樹與光攢。", "遐想西垣客，長吟欲罷難。"]'),
('e38d4be8-d632-4acc-afab-0f200ce3ea20','寒雲輕重色','張仲素','唐','唐诗','tang','','[]','佳期當可許，託思望雲端。',72,'全唐诗/poet.tang.19000.json','["佳期當可許，託思望雲端。", "鱗影朝猶落，繁陰暮自寒。", "因風方嫋嫋，間石已漫漫。", "隱映看鴻度，霏微覺樹攢。", "凝空多似黛，引素乍如紈。", "每向愁中覽，含毫欲狀難。"]'),
('a385e885-39f8-428b-aead-929a3f7e4e42','聖明樂','張仲素','唐','唐诗','tang','','[]','九陌祥煙合，千春瑞月明。',24,'全唐诗/poet.tang.19000.json','["九陌祥煙合，千春瑞月明。", "宮花將苑柳，先發鳳皇城。"]'),
('531c80b8-2306-4399-a1a8-33a92e6f6991','獻壽詞','張仲素','唐','唐诗','tang','','[]','玉帛殊方至，歌鐘比屋聞。',24,'全唐诗/poet.tang.19000.json','["玉帛殊方至，歌鐘比屋聞。", "華夷今一貫，同賀聖朝君。"]'),
('37b9dfcd-837c-477d-9069-e4026b35aa81','宮中樂五首 一','張仲素','唐','唐诗','tang','','[]','網戶交如綺，紗窗薄似煙。',24,'全唐诗/poet.tang.19000.json','["網戶交如綺，紗窗薄似煙。", "樂吹天上曲，人是月中仙。"]'),
('1245f38c-fb63-46df-8976-2c6fd8c30723','宮中樂五首 二','張仲素','唐','唐诗','tang','','[]','翠匣開寒鏡，珠釵挂步搖。',24,'全唐诗/poet.tang.19000.json','["翠匣開寒鏡，珠釵挂步搖。", "妝成祗畏曉，更漏促春宵。"]'),
('fec98322-0461-4f6b-8a31-4b54da2e3890','宮中樂五首 三','張仲素','唐','唐诗','tang','','[]','紅果瑤池實，金盤露井冰。',24,'全唐诗/poet.tang.19000.json','["紅果瑤池實，金盤露井冰。", "甘泉將避暑，臺殿曉光凝。"]'),
('aeec615f-6ccf-44b0-a885-a81ecb51d0e0','宮中樂五首 四','張仲素','唐','唐诗','tang','','[]','月采浮鸞殿，砧聲隔鳳樓。',24,'全唐诗/poet.tang.19000.json','["月采浮鸞殿，砧聲隔鳳樓。", "笙歌臨水檻，紅燭乍迎秋。"]'),
('6eef2cdc-f074-40f3-be85-f762ce7bd198','宮中樂五首 五','張仲素','唐','唐诗','tang','','["\u9ec4\u5c71"]','奇樹留寒翠，神池結夕波。',24,'全唐诗/poet.tang.19000.json','["奇樹留寒翠，神池結夕波。", "黃山一夜雪，渭水瀉聲多。"]'),
('887e948b-092f-4c6c-94e0-581cb1d8ef5b','春遊曲三首 一','張仲素','唐','唐诗','tang','','[]','煙柳飛輕絮，風榆落小錢。',24,'全唐诗/poet.tang.19000.json','["煙柳飛輕絮，風榆落小錢。", "濛濛百花裏，羅綺競鞦韆。"]'),
('3e33777f-d29f-4955-9bf6-e5a40175c817','春遊曲三首 二','張仲素','唐','唐诗','tang','','[]','騁望登香閣，爭高下砌臺。',24,'全唐诗/poet.tang.19000.json','["騁望登香閣，爭高下砌臺。", "林間踏青去，席上寄牋來。"]'),
('3265f523-2b3a-4af0-a213-2fafc6d868c7','春遊曲三首 三','張仲素','唐','唐诗','tang','','[]','行樂三春節，林花百和香。',24,'全唐诗/poet.tang.19000.json','["行樂三春節，林花百和香。", "當年重意氣，先占鬬雞場。"]'),
('481cbbd4-2440-4c33-82e6-272cc85f7917','春閨思','張仲素','唐','唐诗','tang','','["\u601d\u5ff5", "\u5973\u5b50", "\u95fa\u6028"]','裊裊城邊柳，青青陌上桑。',24,'全唐诗/poet.tang.19000.json','["裊裊城邊柳，青青陌上桑。", "提籠忘采葉，昨夜夢漁陽。"]'),
('9a8ce7ec-47e5-4071-b5b7-932571395d17','春江曲二首 一','張仲素','唐','唐诗','tang','','[]','家寄征河岸，征人幾歲遊。',24,'全唐诗/poet.tang.19000.json','["家寄征河岸，征人幾歲遊。", "不如潮水信，每日到沙頭。"]'),
('f854f545-3e40-41a5-a079-0eee70760591','春江曲二首 二','張仲素','唐','唐诗','tang','','[]','乘曉南湖去，參差疊浪橫。',24,'全唐诗/poet.tang.19000.json','["乘曉南湖去，參差疊浪橫。", "前洲在何處，霜裏鴈嚶嚶。"]'),
('a40752d1-7e06-44ac-aaee-2aa810d164c8','太平詞','張仲素','唐','唐诗','tang','','[]','聖德超千古，皇威靜四方。',24,'全唐诗/poet.tang.19000.json','["聖德超千古，皇威靜四方。", "蒼生今息戰，無事覺時良。"]'),
('b1f281bf-93f2-4046-b80f-9a086648288d','隴上行','張仲素','唐','唐诗','tang','','[]','行到黃雲隴，唯聞羌戍鼙。',24,'全唐诗/poet.tang.19000.json','["行到黃雲隴，唯聞羌戍鼙。", "不如山下水，猶得任東西。"]'),
('927896fd-566d-4aba-841d-0ffdf6253809','思君恩','張仲素','唐','唐诗','tang','','[]','紫禁香如霧，青天月似霜。',24,'全唐诗/poet.tang.19000.json','["紫禁香如霧，青天月似霜。", "雲韶何處奏，祗是在朝陽。"]'),
('a6994348-8a80-47bd-8eb7-54c51c8f2e2f','王昭君','張仲素','唐','唐诗','tang','','[]','仙娥今下嫁，驕子自同和。',24,'全唐诗/poet.tang.19000.json','["仙娥今下嫁，驕子自同和。", "劒戟歸田盡，牛羊繞塞多。"]'),
('1bb3a910-fafa-425e-8c88-bfb7647fe041','秋夜曲','張仲素','唐','唐诗','tang','','["\u601d\u5ff5", "\u79cb\u5929", "\u95fa\u6028"]','丁丁漏水夜何長，漫漫輕雲露月光。',32,'全唐诗/poet.tang.19000.json','["丁丁漏水夜何長，漫漫輕雲露月光。", "秋逼暗蟲通夕響，征衣未寄莫飛霜。"]'),
('6ab3d8b6-f095-4266-8289-51a05cfa6748','秋思贈遠','張仲素','唐','唐诗','tang','','[]','博山沉燎絕餘香，蘭燼金檠怨夜長。',32,'全唐诗/poet.tang.19000.json','["博山沉燎絕餘香，蘭燼金檠怨夜長。", "爲問青青河畔草，幾回經雨復經霜。"]'),
('e09ba4e3-92e5-47a0-93cb-8f1e83d7419b','塞上曲','張仲素','唐','唐诗','tang','','[]','卷斾生風喜氣新，早持龍節靜邊塵。',32,'全唐诗/poet.tang.19000.json','["卷斾生風喜氣新，早持龍節靜邊塵。", "漢家天子圖麟閣，身是當今第一人。"]'),
('d8cf1ef0-2fa2-48c0-b5d9-d5ee381d2904','塞下曲五首 一','張仲素','唐','唐诗','tang','','[]','三戍漁陽再渡遼，騂弓在臂劒橫腰。',32,'全唐诗/poet.tang.19000.json','["三戍漁陽再渡遼，騂弓在臂劒橫腰。", "匈奴似若知名姓，休傍陰山更射雕。"]'),
('7be12bdf-03cf-4670-9466-89db4ef0f1dd','塞下曲五首 二','張仲素','唐','唐诗','tang','','[]','獵馬千行鴈幾雙，燕然山下碧油幢。',32,'全唐诗/poet.tang.19000.json','["獵馬千行鴈幾雙，燕然山下碧油幢。", "傳聲漠北單于破，火照旌旗夜受降。"]'),
('9202aa26-8e4f-4828-9fdc-237729e175f7','塞下曲五首 三','張仲素','唐','唐诗','tang','','[]','朔雪飄飄開鴈門，平沙歷亂卷蓬根。',32,'全唐诗/poet.tang.19000.json','["朔雪飄飄開鴈門，平沙歷亂卷蓬根。", "功名耻計擒生數，直斬樓蘭報國恩。"]'),
('bfe82b29-9ada-44f1-9a46-30824df16333','塞下曲五首 四','張仲素','唐','唐诗','tang','','[]','隴水潺湲隴樹秋，征人到此淚雙流。',32,'全唐诗/poet.tang.19000.json','["隴水潺湲隴樹秋，征人到此淚雙流。", "鄉關萬里無因見，西戍河源早晚休。"]'),
('832b9a46-3471-49c3-a3eb-6d6077d1a5a3','塞下曲五首 五','張仲素','唐','唐诗','tang','','[]','陰磧茫茫塞草肥，桔槔烽上暮雲飛。',32,'全唐诗/poet.tang.19000.json','["陰磧茫茫塞草肥，桔槔烽上暮雲飛。", "交河北望天連海，蘇武曾將漢節歸。"]'),
('0c6d66a8-1fda-4008-be00-00b59e8b432d','秋思二首 一','張仲素','唐','唐诗','tang','','[]','碧窗斜日藹深暉，愁聽寒螿淚濕衣。',32,'全唐诗/poet.tang.19000.json','["碧窗斜日藹深暉，愁聽寒螿淚濕衣。", "夢裏分明見關塞，不知何路向金微。"]'),
('795f99c5-30cc-4e7e-8473-64d952646600','秋思二首 二','張仲素','唐','唐诗','tang','','[]','秋天一夜靜無雲，斷續鴻聲到曉聞。',32,'全唐诗/poet.tang.19000.json','["秋天一夜靜無雲，斷續鴻聲到曉聞。", "欲寄征衣問消息，居延城外又移軍。"]'),
('f7eba4eb-71a4-4f2f-b648-9eec4f7a0071','漢苑行二首','張仲素','唐','唐诗','tang','','[]','回鴈高飛太液池，新花低發上林枝。',32,'全唐诗/poet.tang.19000.json','["回鴈高飛太液池，新花低發上林枝。", "年光到處皆堪賞，春色人間總不知。"]'),
('ae156321-4ecb-456c-bf03-50ff6f759113','漢苑行二首 二','張仲素','唐','唐诗','tang','','[]','春風淡蕩景悠悠，鶯囀高枝燕入樓。',32,'全唐诗/poet.tang.19000.json','["春風淡蕩景悠悠，鶯囀高枝燕入樓。", "千步回廊聞鳳吹，珠簾處處上銀鉤。"]'),
('99425c56-1131-40e3-b17d-050d00595775','天馬辭二首 一','張仲素','唐','唐诗','tang','','[]','天馬初從渥水來，郊歌曾唱得龍媒。',32,'全唐诗/poet.tang.19000.json','["天馬初從渥水來，郊歌曾唱得龍媒。", "不知玉塞沙中路，苜蓿殘花幾處開。"]'),
('43e882d6-e931-4bf5-8b4a-4f8f7cac363a','天馬辭二首 二','張仲素','唐','唐诗','tang','','[]','躞蹀宛駒齒未齊，摐金噴玉向風嘶。',32,'全唐诗/poet.tang.19000.json','["躞蹀宛駒齒未齊，摐金噴玉向風嘶。", "來時欲盡金河道，獵獵輕風在碧蹄。"]'),
('1c7b87cc-6a9f-48ae-bc40-8c42e728fbbf','燕子樓詩三首 一','張仲素','唐','唐诗','tang','','[]','樓上殘燈伴曉霜，獨眠人起合歡牀。',32,'全唐诗/poet.tang.19000.json','["樓上殘燈伴曉霜，獨眠人起合歡牀。", "相思一夜情多少，地角天涯不是長。"]'),
('759dcb8a-b3d8-4663-bba1-070dfc772779','燕子樓詩三首 二','張仲素','唐','唐诗','tang','','[]','北邙松栢鎖愁煙，燕子樓人思悄然。',32,'全唐诗/poet.tang.19000.json','["北邙松栢鎖愁煙，燕子樓人思悄然。", "自埋劒履歌塵散，紅袖香消已十年。"]'),
('ccee06f6-eba9-4e98-be08-1191da6d4319','燕子樓詩三首 三','張仲素','唐','唐诗','tang','','[]','適看鴻鴈岳陽回，又覩玄禽逼社來。',32,'全唐诗/poet.tang.19000.json','["適看鴻鴈岳陽回，又覩玄禽逼社來。", "瑤瑟玉簫無意緒，任從蛛網任從灰。"]'),
('f9d93b0e-0749-464a-9b9d-a3502ec33860','賦得冬日可愛','庾承宣','唐','唐诗','tang','','[]','宿霧開天霽，寒郊見初日。',72,'全唐诗/poet.tang.19000.json','["宿霧開天霽，寒郊見初日。", "林疎照逾遠，冰輕影微出。", "豈假陽和氣，暫忘玄冬律。", "愁抱望自寬，羈情就如失。", "欣欣事幾許，曈曈狀非一。", "傾心倘知期，良願自茲畢。"]'),
('a276c4a9-2394-499e-9ded-3a9b970f0ece','贈毛仙翁','鄭澣','唐','唐诗','tang','','[]','至道無名，至人長生。',180,'全唐诗/poet.tang.19000.json','["至道無名，至人長生。", "爰觀繪事，以挹真形。", "方口渥丹，濃眉刷青。", "松姿本秀，鶴質自輕。", "道德神仙，內蘊心靈。", "紅肌絲髮，外彰華精。", "色如含芳，貌若和光。", "胚渾造化，含吐陰陽。", "吾聞安期，隱見不常。", "或在世間，或遊上蒼。", "猗歟真人，得非後身。", "寫此仙骨，久而不磷。", "皎皎明眸，瞭然如新。", "藹藹童顏，的然如春。", "金石可並，丹青不冺。", "通天臺上，有見常人。", "俗士觀瞻，方悟幽塵。", "君子圖之，敬兮如神。"]'),
('81af164e-12d2-4721-99fe-abc913d7832c','和李德裕遊漢州房公湖二首 一','鄭澣','唐','唐诗','tang','','[]','太尉留琴地，時移重可尋。',48,'全唐诗/poet.tang.19000.json','["太尉留琴地，時移重可尋。", "徽弦一掩抑，風月助登臨。", "榮駐青油騎，高張白雪音。", "秖言酬唱美，良史記王箴。"]'),
('33330690-7c93-49e6-95ec-1f73ccda3f48','和李德裕遊漢州房公湖二首 二','鄭澣','唐','唐诗','tang','','[]','靜對煙波夕，猶思棟宇青。',48,'全唐诗/poet.tang.19000.json','["靜對煙波夕，猶思棟宇青。", "臥龍空有處，馴鳥獨忘情。", "顧步襟期遠，參差物象橫。", "自宜雕樂石，爽氣際青城。"]'),
('79ce57af-0925-4c46-a8a7-cc39e2f96cab','中書相公任兵部侍郎日後閣植四松逾數年澣忝此官因獻拙什','鄭澣','唐','唐诗','tang','','[]','丞相當時植，幽襟對此開。',120,'全唐诗/poet.tang.19000.json','["丞相當時植，幽襟對此開。", "人知舟檝器，天假棟梁材。", "錯落龍鱗出，䙰褷鶴翅迴。", "重陰羅武庫，細響靜山臺。", "得地公堂裏，移根澗水隈。", "吳臣夢寐遠，秦嶽歲年摧。", "轉覺飛纓繆，何因繼組來。", "幾尋珠履迹，願比角弓培。", "栢悅猶依社，星高久照台。", "後凋應共操，無復問良媒。"]'),
('3a743ab1-137d-42c8-b20a-b5021c133831','和李德裕房公舊竹亭聞琴','鄭澣','唐','唐诗','tang','','[]','石室寒飆驚，孫枝雅器裁。',24,'全唐诗/poet.tang.19000.json','["石室寒飆驚，孫枝雅器裁。", "坐來山水操，玄斷吊遺埃。"]'),
('d428d881-8dd3-4731-b628-6d5d0b6d1890','句','鄭澣','唐','唐诗','tang','','[]','但慮彩色污，無虞臂胛肥。',12,'全唐诗/poet.tang.19000.json','["但慮彩色污，無虞臂胛肥。"]'),
('3d3de4cd-4cd4-427a-b6c5-d5ba4ef52ca6','遊棲霞寺','張彙','唐','唐诗','tang','','[]','躋險入幽林，翠微含竹殿。',48,'全唐诗/poet.tang.19000.json','["躋險入幽林，翠微含竹殿。", "泉聲無休歇，山色時隱見。", "潮來雜風雨，梅落成霜霰。", "一從方外遊，頓覺塵心變。"]'),
('43caa39b-c485-4b66-9daf-0ef097728803','春風扇微和','張彙','唐','唐诗','tang','','[]','木德生和氣，微微入曙風。',72,'全唐诗/poet.tang.19000.json','["木德生和氣，微微入曙風。", "暗催南向葉，漸翥北歸鴻。", "澹蕩侵冰谷，悠揚轉蕙叢。", "拂塵迴廣路，泛籟過遙空。", "暖上煙光際，雲移律侯中。", "扶搖如可借，從此戾蒼穹。"]'),
('9aa9bfe8-4f9b-4b00-ab44-64ae029cf72b','觀藏冰','張彙','唐','唐诗','tang','','[]','寒氣方窮律，陰精正結冰。',72,'全唐诗/poet.tang.19000.json','["寒氣方窮律，陰精正結冰。", "體堅風帶壯，影素月臨凝。", "冬賦凌人掌，春期命婦昇。", "鑿來壺色徹，納處鏡光澄。", "魯史曾留問，幽詩舊見稱。", "同觀里射享，王道頌還興。"]'),
('e4029274-33c0-4961-a478-54e928838cae','賦得春風扇微和','張彙','唐','唐诗','tang','','[]','習習和風扇，悠悠淑氣微。',72,'全唐诗/poet.tang.19000.json','["習習和風扇，悠悠淑氣微。", "陽升知候改，律應喜春歸。", "池柳晴初拆，林鶯暖欲飛。", "川原浮彩翠，臺館動光輝。", "泛豔搖丹闕，揚芳入粉闈。", "發生當有分，枯朽幸因依。"]'),
('718dab72-8ed1-493d-a5ad-d0e8a56700af','金谷園懷古','張彙','唐','唐诗','tang','','[]','緩步洛城下，軫懷金谷園。',72,'全唐诗/poet.tang.19000.json','["緩步洛城下，軫懷金谷園。", "昔人隨水逝，舊樹逐春繁。", "冉冉搖風弱，菲菲裛露翻。", "歌臺豈易見，舞袖乍如存。", "戲蝶香中起，流鶯暗處喧。", "徒聞施錦帳，此地擁行軒。"]'),
('ddbf2fde-0c6f-4cd7-9d78-639cfa557239','句','張彙','唐','唐诗','tang','','[]','應念路傍憔悴翼，昔年喬木幸同遷。',16,'全唐诗/poet.tang.19000.json','["應念路傍憔悴翼，昔年喬木幸同遷。"]'),
('bca6b90b-74ce-43c6-b4f7-098230b947d4','立春日曉望三素雲','李應','唐','唐诗','tang','','[]','玄鳥初來日，靈仙望裏分。',72,'全唐诗/poet.tang.19000.json','["玄鳥初來日，靈仙望裏分。", "冰容朝上界，玉輦擁朝雲。", "碧落流輕豔，紅霓間綵文。", "帶煙時縹緲，向斗更氤氳。", "髣髴隨風馭，迢遙出曉雰。", "茲辰三見後，希得從元君。"]'),
('33faa2b4-fc76-48e2-b9f8-a59b39a2b17d','立春日曉望三素雲','陳師穆','唐','唐诗','tang','','[]','晴曉初春日，高心望素雲。',72,'全唐诗/poet.tang.19000.json','["晴曉初春日，高心望素雲。", "彩光浮玉輦，紫氣隱元君。", "縹緲中天去，逍遙上界分。", "鸞驂攀不及，仙吹遠難聞。", "禮候於斯覩，明循在解紛。", "人歸懸想處，霞色自氛氳。"]'),
('cb4b244c-dc3f-41bb-9974-0240a5f57d4b','立春日曉望三素雲','李季何','唐','唐诗','tang','','[]','靄靄青春曙，飛仙駕五雲。',72,'全唐诗/poet.tang.19000.json','["靄靄青春曙，飛仙駕五雲。", "浮輪初縹緲，承蓋下氤氳。", "薄影隨風度，殊容向日分。", "羽毛紛共遠，環佩杳猶聞。", "靜合煙霞色，遙將鸞鶴羣。", "年年瞻此節，應許從元君。"]'),
('43770857-261c-4d91-8f38-4f3852b30f1d','春臺晴望','李程','唐','唐诗','tang','','[]','曲臺送春目，景物麗新晴。',72,'全唐诗/poet.tang.19000.json','["曲臺送春目，景物麗新晴。", "靄靄煙收翠，忻忻木向榮。", "靜看遲日上，閑愛野雲平。", "風慢遊絲轉，天開遠水明。", "登高塵慮息，觀徼道心清。", "更有遷喬意，翩翩出谷鶯。"]'),
('dd0fbdfc-5b79-4c20-a8ce-11fc23e7cf18','玉壺冰','李程','唐','唐诗','tang','','[]','琢玉性惟堅，成壺體更圓。',96,'全唐诗/poet.tang.19000.json','["琢玉性惟堅，成壺體更圓。", "虛心含衆象，應物受寒泉。", "溫潤資天質，清貞稟自然。", "日融光乍散，雪照色逾鮮。", "至鑒功寧宰，無私照豈偏。", "明將水鏡對，白與粉闈連。", "拂拭終爲美，提攜佇見傳。", "勿令毫髮累，遺恨鮑公篇。"]'),
('713f4117-92d2-4b83-b9a7-1b46d770dffb','賦得竹箭有筠','李程','唐','唐诗','tang','','[]','常愛凌寒竹，堅貞可喻人。',72,'全唐诗/poet.tang.19000.json','["常愛凌寒竹，堅貞可喻人。", "能將先進禮，義與後凋鄰。", "冉冉猶全節，青青尚有筠。", "陶鈞二儀內，柯葉四時春。", "待鳳花仍吐，停霜色更新。", "方持不易操，對此欲觀身。"]'),
('77fa0f6d-1e51-416f-b478-a0816000e52f','觀慶雲圖','李程','唐','唐诗','tang','','[]','五雲從表瑞，藻繪宛成圖。',72,'全唐诗/poet.tang.19000.json','["五雲從表瑞，藻繪宛成圖。", "柯葉何時改，丹青此不渝。", "非煙色尚麗，似蓋狀應殊。", "渥彩看猶在，輕陰望已無。", "方將遇翠幄，那羨起蒼梧。", "欲識從龍處，今逢聖合符。"]'),
('8ad18b50-73a0-4ce9-b33a-74f4fffa235f','贈毛仙翁','李程','唐','唐诗','tang','','[]','茫茫塵累愧腥膻，強把蜉蝣望列仙。',64,'全唐诗/poet.tang.19000.json','["茫茫塵累愧腥膻，強把蜉蝣望列仙。", "閑指紫霄峯下路，却歸白鹿洞中天。", "吹簫鳳去經何代，茹玉方傳得幾年。", "他日更來人世看，又應東海變桑田。"]'),
('4bf8a7fa-166a-4008-9a0e-11a66bffa518','省試春臺晴望','高弁','唐','唐诗','tang','','[]','層臺聊一望，遍賞帝城春。',72,'全唐诗/poet.tang.19000.json','["層臺聊一望，遍賞帝城春。", "風煖聞啼鳥，冰開見躍鱗。", "晴山煙外翠，香蘂日邊新。", "已變青門柳，初銷紫陌塵。", "金湯千里國，車騎萬方人。", "此處雲霄近，憑高願致身。"]'),
('56f535d2-27cb-485a-9fc4-1c4f04e2131d','霜菊','席夔','唐','唐诗','tang','','[]','時令忽已變，行看被霜菊。',72,'全唐诗/poet.tang.19000.json','["時令忽已變，行看被霜菊。", "可憐後時秀，當此凜風肅。", "淅瀝翠枝翻，淒清金蘂馥。", "凝姿節堪重，澄豔景非淑。", "寧祛青女威，願盈君子掬。", "持來泛罇酒，永以照幽獨。"]'),
('7bdba31a-6f91-4972-b474-4e92a31b977f','賦得竹箭有筠','席夔','唐','唐诗','tang','','[]','共愛東南美，青青歎有筠。',72,'全唐诗/poet.tang.19000.json','["共愛東南美，青青歎有筠。", "貞姿衆木異，秀色四時均。", "枝葉當無改，風霜豈憚頻。", "虛心如待物，勁節自留春。", "鮮潤期棲鳳，嬋娟可並人。", "可憐初籜卷，粉澤更宜新。"]'),
('ec532d4c-48d4-4c3d-8158-f7f18f1d1348','省試觀慶雲圖','李行敏','唐','唐诗','tang','','[]','縑素傳休祉，丹青狀慶雲。',72,'全唐诗/poet.tang.19000.json','["縑素傳休祉，丹青狀慶雲。", "非煙凝漠漠，似蓋乍紛紛。", "尚駐從龍意，全舒捧日文。", "光因五色起，影向九霄分。", "裂素觀嘉瑞，披圖賀聖君。", "寧同窺汗漫，方此覩氛氳。"]'),
('198a78e5-eeb4-4d65-bff8-d6e9a8750a3e','賦得冬日可愛','陳諷','唐','唐诗','tang','','[]','寒日臨清晝，寥天一望時。',72,'全唐诗/poet.tang.19000.json','["寒日臨清晝，寥天一望時。", "未消埋逕雪，先暖讀書帷。", "屬思光難駐，舒情影若遺。", "晉臣曾比德，謝客昔言詩。", "散彩寧偏照，流陰信不追。", "餘輝如可就，迴燭幸無私。"]'),
('0a7aa2fe-4d9a-4a0c-921e-222543d5d103','郡齋三月下旬作','崔護','唐','唐诗','tang','','[]','春事日已歇，池塘曠幽尋。',48,'全唐诗/poet.tang.19000.json','["春事日已歇，池塘曠幽尋。", "殘紅披獨墜，嫩綠間淺深。", "偃仰捲芳褥，顧步愛新陰。", "謀春未及竟，夏初遽見侵。"]'),
('ed2bf5ab-6bb5-46bc-a5c0-ba3b70ce1351','五月水邊柳','崔護','唐','唐诗','tang','','["\u548f\u7269", "\u548f\u7269\u8bd7", "\u67f3\u6811"]','結根挺涯涘，垂影覆清淺。',72,'全唐诗/poet.tang.19000.json','["結根挺涯涘，垂影覆清淺。", "睡臉寒未開，嬾腰晴更軟。", "搖空條已重，拂水帶方展。", "似醉煙景凝，如愁月露泫。", "絲長魚悞恐，枝弱禽驚踐。", "長別幾多情，含春任攀搴。"]'),
('411af073-b2a1-4eb4-9c04-ee32d49849dd','三月五日陪裴大夫泛長沙東湖','崔護','唐','唐诗','tang','','[]','上巳餘風景，芳辰集遠坰。',72,'全唐诗/poet.tang.19000.json','["上巳餘風景，芳辰集遠坰。", "綵舟浮泛蕩，繡轂下娉婷。", "林樹迴蔥蒨，笙歌入杳冥。", "湖光迷翡翠，草色醉蜻蜓。", "鳥弄桐花日，魚翻穀雨萍。", "從今留勝會，誰看畫蘭亭。"]'),
('4d0b9981-59b6-41f0-b77b-2b73734bda15','山雞舞石鏡','崔護','唐','唐诗','tang','','[]','廬峯開石鏡，人說舞山雞。',72,'全唐诗/poet.tang.19000.json','["廬峯開石鏡，人說舞山雞。", "物象纖舞隱，禽情秖自迷。", "景當煙霧歇，心喜錦翎齊。", "宛轉烏呈彩，婆娑鳳欲棲。", "何言資羽族，在地得天倪。", "應笑翰音者，終朝飲敗醯。"]'),
('0c41ce6b-948a-456a-9c4d-f0c767e61cd7','題都城南莊','崔護','唐','唐诗','tang','','["\u6545\u4e8b", "\u5199\u666f", "\u6292\u60c5", "\u666f\u4e2d\u60c5"]','去年今日此門中，人面桃花相映紅。',32,'全唐诗/poet.tang.19000.json','["去年今日此門中，人面桃花相映紅。", "人面不知何處在，桃花依舊笑春風。"]'),
('5d91b18a-d871-49c0-acd2-1f6d4b8066bd','晚雞','崔護','唐','唐诗','tang','','[]','黯黯嚴城罷鼓鼙，數聲相續出寒棲。',32,'全唐诗/poet.tang.19000.json','["黯黯嚴城罷鼓鼙，數聲相續出寒棲。", "不嫌驚破紗窗夢，却恐爲奴半夜啼。"]'),
('febedf36-8cf3-41ef-88bc-cf8d3291173d','贈藥山高僧惟儼二首 一','李翱','唐','唐诗','tang','','[]','練得身形似鶴形，千株松下兩函經。',32,'全唐诗/poet.tang.19000.json','["練得身形似鶴形，千株松下兩函經。", "我來問道無餘說，雲在青霄水在瓶。"]'),
('b633bc4d-ce69-43e2-8ec7-3bcee1a21ae7','贈藥山高僧惟儼二首 二','李翱','唐','唐诗','tang','','[]','選得幽居愜野情，終年無送亦無迎。',32,'全唐诗/poet.tang.19000.json','["選得幽居愜野情，終年無送亦無迎。", "有時直上孤峯頂，月下披雲嘯一聲。"]'),
('68c82e5b-9e84-4f65-8a12-58dd11bf9dc2','贈毛仙翁','李翱','唐','唐诗','tang','','[]','紫霄仙客下三山，因救生靈到世間。',64,'全唐诗/poet.tang.19000.json','["紫霄仙客下三山，因救生靈到世間。", "龜鶴計年承甲子，冰霜爲質駐童顏。", "韜藏休咎傳真籙，變化榮枯試小還。", "從此便教塵骨貴，九霄雲路願追攀。"]'),
('43ddb018-6993-4bf3-923d-cc9d116c9b9b','拜禹歌','李翱','唐','唐诗','tang','','[]','惟天地之無窮兮，哀生人之常勤。',34,'全唐诗/poet.tang.19000.json','["惟天地之無窮兮，哀生人之常勤。", "往者吾弗及兮，來者吾弗聞。", "已而，已而。"]'),
('93bc93d8-4334-44c9-a968-03392dd63fa7','廣慶寺','李翱','唐','唐诗','tang','','[]','傳者不足信，見景勝如聞。',48,'全唐诗/poet.tang.19000.json','["傳者不足信，見景勝如聞。", "一水遠赴海，兩山高入雲。", "魚龍晴自戲，猿狖晚成羣。", "醉酒斜陽下，離心草自薰。"]'),
('22e61a32-c236-41d6-b4e0-d80e655afd3d','奉酬劉言史宴光風亭','李翱','唐','唐诗','tang','','[]','閏餘春早景沈沈，禊飲風亭恣賞心。',32,'全唐诗/poet.tang.19000.json','["閏餘春早景沈沈，禊飲風亭恣賞心。", "紅袖青娥留永夕，漢陰寧肯羨山陰。"]'),
('3f4e9d44-7d2e-4f22-8ad7-9a72a8551a8b','戲贈詩','李翱','唐','唐诗','tang','','[]','縣君好磚渠，繞水恣行游。',60,'全唐诗/poet.tang.19000.json','["縣君好磚渠，繞水恣行游。", "鄙性樂疎野，鑿地便成溝。", "兩岸值芳草，中央漾清流。", "所尚既不同，磚鑿可自修。", "從他後人見，境趣誰爲幽。"]'),
('8c0bf07f-f529-472a-8468-2334daf509ff','題浯溪石','皇甫湜','唐','唐诗','tang','','[]','次山有文章，可惋只在碎。',144,'全唐诗/poet.tang.19000.json','["次山有文章，可惋只在碎。", "然長於指敘，約潔有餘態。", "心語適相應，出句多分外。", "於諸作者間，拔戟成一隊。", "中行雖富劇，粹美若可蓋。", "子昂感遇佳，未若君雅裁。", "退之全而神，上與千載對。", "李杜才海翻，高下非可概。", "文與一氣間，爲物莫與大。", "先王路不荒，豈不仰吾輩。", "石屏立衙衙，溪口揚素瀨。", "我思何人知，徙倚如有待。"]'),
('a4e950b8-67be-436c-a943-1163a62d231a','石佛谷','皇甫湜','唐','唐诗','tang','','[]','[澶漫]太行北，千里一塊石。',146,'全唐诗/poet.tang.19000.json','["[澶漫]太行北，千里一塊石。", "平腹有壑谷，深廣數百尺。", "土僧何爲者，老草毛髮白。", "寢處容身龕，足膝隱成跡。", "金僊琢靈象，相好倚北壁。", "花座五雲扶，玉豪六虛射。", "文人留紀述，時事可辨析。", "鳥跡巧均分，龍骸極癯瘠。", "枯松間槎枿，猛獸恣騰擲。", "蛣𧎜蟲食縱，懸垂露凝滴。", "精藝貫古今，窮巖誰愛惜。", "託師禪誦餘，勿使塵埃積。"]'),
('509875e7-d471-4e07-bb1a-167d5138fe9e','出世篇','皇甫湜','唐','唐诗','tang','','[]','生當爲大丈夫，斷羈羅，出泥塗。',259,'全唐诗/poet.tang.19000.json','["生當爲大丈夫，斷羈羅，出泥塗。", "四散號呶，[俶擾]無隅。", "埋之深淵，飄然上浮。", "騎龍披青雲，汎覽遊八區。", "經太山，絕大海，一長吁。", "西摩月鏡，東弄日珠。", "上括天之門，直指帝所居。", "羣仙來迎塞天衢，鳳皇鸞鳥燦金輿。", "音聲嘈嘈滿太虛，旨飲食兮照庖廚。", "食之不飫飫不盡，使人不陋復不愚。", "旦旦狎玉皇，夜夜御天姝。", "當御者幾人，百千爲番。", "宛宛舒舒，忽不自知。", "支消體化膏露明，湛然無色茵席濡。", "俄而散漫，[斐]然虛無。", "翕然復摶，摶久而蘇。", "精神如太陽，霍然照清都。", "四肢爲琅玕，五臟爲璠璵。", "顏如芙蓉，頂爲醍醐。", "與天地相終始，浩漫爲歡娛。", "下顧人間，溷糞蠅蛆。"]'),
('ddf2f039-cc90-4dc2-ae8e-78de2bc1b925','蜀綿州越王樓詩','樊宗師','唐','唐诗','tang','','[]','危樓倚天門，如𨶻星辰宮。',120,'全唐诗/poet.tang.19000.json','["危樓倚天門，如𨶻星辰宮。", "榱薄龍虎怪，洄洄繞雷風。", "徂秋試登臨，大靄屯喬空。", "不見西北路，考懷益彫窮。", "石瀨薄濺濺，上山杳穹穹。", "昔人創爲逝，所適酡顏紅。", "今我茲之來，猶校成歲功。", "輟田植科畝，遊圃歌芳叢。", "地財無叢厚，人室安取豐。", "既乏富庶能，千萬慙文翁。"]'),
('59523b40-e8f1-42e3-aa5f-db45b9f6a5f9','催妝','盧儲','唐','唐诗','tang','','[]','昔年將去玉京遊，第一仙人許狀頭。',32,'全唐诗/poet.tang.19000.json','["昔年將去玉京遊，第一仙人許狀頭。", "今日幸爲秦晉會，早教鸞鳳下妝樓。"]'),
('2b095345-7711-4570-8432-60863403e1d4','官舍迎內子有庭花開','盧儲','唐','唐诗','tang','','[]','芍藥斬新栽，當庭數朵開。',24,'全唐诗/poet.tang.19000.json','["芍藥斬新栽，當庭數朵開。", "東風與拘束，留待細君來。"]'),
('e6e95e10-730c-461e-99e7-34c66b2fd585','古松感興','皇甫松','唐','唐诗','tang','','[]','皇天后土力，使我向此生。',72,'全唐诗/poet.tang.19000.json','["皇天后土力，使我向此生。", "貴賤不我均，若爲天地情。", "我家世道德，旨意匡文明。", "家集四百卷，獨立天地經。", "寄言青松姿，豈羨朱槿榮。", "昭昭大化光，共此遺芳馨。"]'),
('3522a59a-87e7-4257-8f35-6720b581f2d9','怨回紇歌','皇甫松','唐','唐诗','tang','','[]','白首南朝女，愁聽異域歌。',48,'全唐诗/poet.tang.19000.json','["白首南朝女，愁聽異域歌。", "收兵頡利國，飲馬胡蘆河。", "毳布腥膻久，穹廬歲月多。", "鵰巢城上宿，吹笛淚滂沱。"]'),
('4940f632-76a9-416f-a029-47163aaba310','江上送別','皇甫松','唐','唐诗','tang','','[]','祖席駐征棹，開帆候信潮。',48,'全唐诗/poet.tang.19000.json','["祖席駐征棹，開帆候信潮。", "隔筵桃葉泣，吹管杏花飄。", "船去鷗飛閣，人歸塵上橋。", "別離惆悵淚，江路濕紅蕉。"]'),
('c1ab438f-0521-4b14-8056-9e57eb77a87a','採蓮子二首 一','皇甫松','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5973\u5b50", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','菡萏香連十頃陂，小姑貪戲採蓮遲。',32,'全唐诗/poet.tang.19000.json','["菡萏香連十頃陂，小姑貪戲採蓮遲。", "晚來弄水船頭濕，更脫紅裙裹鴨兒。"]'),
('ed9ff702-9ada-422f-885d-8e4fafb39c87','採蓮子二首 二','皇甫松','唐','唐诗','tang','','["\u7231\u60c5", "\u5199\u666f", "\u6c5f\u5357", "\u79cb\u5929", "\u5a49\u7ea6"]','船動湖光灧灧秋，貪看年少信船流。',32,'全唐诗/poet.tang.19000.json','["船動湖光灧灧秋，貪看年少信船流。", "無端隔水拋蓮子，遙被人知半日羞。"]'),
('e5577e01-af86-42fc-a780-c904f4cc1104','拋毬樂 一','皇甫松','唐','唐诗','tang','','[]','紅撥一聲飄，輕毬墜越綃。',36,'全唐诗/poet.tang.19000.json','["紅撥一聲飄，輕毬墜越綃。", "帶翻金孔雀，香滿繡蜂腰。", "少少拋分數，花枝正索饒。"]'),
('b0122d59-f298-4dd7-9a57-3e608971f96f','拋毬樂 二','皇甫松','唐','唐诗','tang','','[]','金蹙花毬小，真珠繡帶垂。',36,'全唐诗/poet.tang.19000.json','["金蹙花毬小，真珠繡帶垂。", "幾回衝蠟燭，千度入春懷。", "上客終須醉，觥杯自亂排。"]'),
('39ab0a9c-f09b-4bf7-9731-713a9f617049','勸僧酒','皇甫松','唐','唐诗','tang','','[]','勸僧一杯酒，共看青青山。',24,'全唐诗/poet.tang.19000.json','["勸僧一杯酒，共看青青山。", "酣然萬象滅，不動心印閑。"]'),
('01e590af-430c-4a61-8b2d-6b56fa7650e9','登郭隗臺','皇甫松','唐','唐诗','tang','','[]','燕相謀在茲，積金黃巍巍。',24,'全唐诗/poet.tang.19000.json','["燕相謀在茲，積金黃巍巍。", "上諸欲何顏，使我千載悲。"]'),
('1679b6b2-641c-4ba0-864b-cc75bf1db5cb','楊柳枝詞二首 一','皇甫松','唐','唐诗','tang','','[]','爛漫春歸水國時。',32,'全唐诗/poet.tang.19000.json','["爛漫春歸水國時。", "吳王宮殿柳絲垂，黃鶯長叫空閨畔。", "西子無因更得知。"]'),
('2cf117ff-1b92-4b48-82a6-93d691934727','楊柳枝詞二首 二','皇甫松','唐','唐诗','tang','','[]','春入行宮映翠微，玄宗侍女舞煙絲。',32,'全唐诗/poet.tang.19000.json','["春入行宮映翠微，玄宗侍女舞煙絲。", "如今柳向空城綠，玉笛何人更把吹。"]'),
('ce370efa-af20-41b6-bad6-d64f123f0f23','浪淘沙二首 一','皇甫松','唐','唐诗','tang','','[]','灘頭細草接疎林，浪惡罾船半欲沈。',32,'全唐诗/poet.tang.19000.json','["灘頭細草接疎林，浪惡罾船半欲沈。", "宿鷺眠洲非舊浦，去年沙觜是江心。"]'),
('150b20f1-92ac-4017-ac9f-04d6ec90af17','浪淘沙二首 二','皇甫松','唐','唐诗','tang','','[]','蠻歌荳蔻北人愁，松雨蒲風野艇秋。',32,'全唐诗/poet.tang.19000.json','["蠻歌荳蔻北人愁，松雨蒲風野艇秋。", "浪起鵁鶄眠不得，寒沙細細入江流。"]'),
('b1b58020-3ebf-4a66-89bb-493ac631f91c','句','皇甫松','唐','唐诗','tang','','[]','夜入真珠室，朝游玳瑁宮。',12,'全唐诗/poet.tang.19000.json','["夜入真珠室，朝游玳瑁宮。"]'),
('ca395156-c9cd-4913-a138-551934235f8f','送皇甫湜赴舉','馬異','唐','唐诗','tang','','[]','馬蹄聲特特，去入天子國。',72,'全唐诗/poet.tang.19000.json','["馬蹄聲特特，去入天子國。", "借問去是誰，秀才皇甫湜。", "吞吐一腹文，八音兼五色。", "主文有崔李，郁郁爲朝德。", "青銅鏡必明，朱絲繩必直。", "稱意太平年，願子長相憶。"]'),
('bcffe3f2-ca85-43d9-90e2-dc230f4d2a42','貞元旱歲','馬異','唐','唐诗','tang','','[]','赤地炎都寸草無，百川水沸煮蟲魚。',32,'全唐诗/poet.tang.19000.json','["赤地炎都寸草無，百川水沸煮蟲魚。", "定應燋爛無人救，淚落三篇古尚書。"]'),
('b75b1142-7167-4b81-8b99-f5b289671144','暮春醉中寄李干秀才','馬異','唐','唐诗','tang','','[]','歡異且交親，酒生開甕春。',48,'全唐诗/poet.tang.19000.json','["歡異且交親，酒生開甕春。", "不須愁犯卯，且乞醉過申。", "折草爲籌筯，鋪花作錦裀。", "嬌鶯解言語，留客也殷勤。"]'),
('798214ad-1966-4897-b35c-517685eef589','荅盧仝結交詩','馬異','唐','唐诗','tang','','[]','有鳥自南翔，口銜一書扎，達我山之維。',380,'全唐诗/poet.tang.19000.json','["有鳥自南翔，口銜一書扎，達我山之維。", "開緘金玉煥陸離，乃是盧仝結交詩。", "此詩峭絕天邊格，力與文星色相射。", "長河拔作數條絲，太華磨成一拳石。", "莫嗟獨笑無往還，月中芳桂難追攀。", "況值亂邦不平年，迴陵倒谷如等閑。", "與君俯首大艱阻，喙長三尺不得語。", "因君今日形章句，羨獼猴兮著衣裳。", "悲蚯蚓兮安翅羽，上天不識察。", "仰我爲遼天失所，將吾劒兮切淤泥。", "使良驥兮捕老鼠，昨日脫身卑賤籠。", "卯星借與老人峯，抱鋤劚地芸芝朮。", "偃蓋參天舊有松，朮與松兮保身世。", "臥居居兮起于于，漱潺潺兮聆嘒嘒。", "道在其中可終歲，不教辜負堯爲帝。", "燒我荷衣摧我身，回看天地如砥平。", "鋼刀銼骨不辭去，卑躬君子今明明。", "俛首辭山心慘惻，白雲雖好戀不得。", "看雲且擬直須臾，疾風又卷西飛翼。", "爲報覃懷心結交，死生富貴存後凋。", "我心不畏朱公叔，君意須防劉孝標。", "以膠投漆苦不早，就中相去萬里道。", "河水悠悠山之間，無由把袂攄懷抱。", "憶仝吟能文，洽臭成蘭薰。"]'),
('571c5fa8-bcb0-435c-80dd-e5d15cdc5d2a','白雲起封中詩','呂溫','唐','唐诗','tang','','[]','封開白雲起，漢帝坐齋宮。',72,'全唐诗/poet.tang.19000.json','["封開白雲起，漢帝坐齋宮。", "望在泥金上，疑生祕玉中。", "攢柯初繚繞，布葉漸蒙籠。", "日觀祥光合，天門瑞氣通。", "無心已出岫，有勢欲凌風。", "倘遣成膏澤，從茲遍大空。"]'),
('e87e77b3-2185-408e-85b7-17d9c5097a50','終南精舍月中聞磬聲詩','呂溫','唐','唐诗','tang','','[]','月峰禪室掩，幽磬靜昏氛。',72,'全唐诗/poet.tang.19000.json','["月峰禪室掩，幽磬靜昏氛。", "思入空門妙，聲從覺路聞。", "泠泠滿虛壑，杳杳出寒雲。", "天籟疑難辨，霜鐘誰可分。", "偶來遊法界，便欲謝人羣。", "竟夕聽真響，塵心自解紛。"]'),
('3cf445fc-c7ec-4b9d-9efc-7099d6232f4a','青出藍詩','呂溫','唐','唐诗','tang','','[]','物有無窮好，藍青又出青。',48,'全唐诗/poet.tang.19000.json','["物有無窮好，藍青又出青。", "朱研未比德，白受始成形。", "袍襲宜從政，衿垂可問經。", "當時不採擷，作色幾飄零。"]'),
('485a7c66-db07-40f2-b3e8-ff412f168ec8','奉和李相公早朝於中書候傳點偶書所懷奉呈門下武相公中書鄭相公','呂溫','唐','唐诗','tang','','[]','禁門留騎吹，內省正衣冠。',120,'全唐诗/poet.tang.19000.json','["禁門留騎吹，內省正衣冠。", "稍辨旂常色，尚聞鐘漏殘。", "九天鑪氣煖，六月玉聲寒。", "宿霧開霞觀，晨光泛露盤。", "致君期反樸，求友得如蘭。", "政自同歸理，言成共不刊。", "準繩臨百度，領袖映千宮。", "臥鼓流沙靜，飛航漲海安。", "盡規詶主意，偕賦代交歡。", "雅韻人間滿，多慙竊和難。"]'),
('db059c3a-3fb2-4801-a1f1-213dab865fc5','奉和武中丞秋日臺中寄懷簡諸僚友','呂溫','唐','唐诗','tang','','[]','聖朝思紀律，憲府得中賢。',96,'全唐诗/poet.tang.19000.json','["聖朝思紀律，憲府得中賢。", "指顧風行地，儀形月麗天。", "不仁恒自遠，爲政復何先。", "虛室唯生白，閑情却草玄。", "迎霜紅葉早，過雨碧苔鮮。", "魚樂翻秋水，烏聲隔暮煙。", "舊遊多絕席，感物遂成篇。", "更許窮荒谷，追歌白雪前。"]'),
('9fcff534-60c0-4abd-ab83-fb3c5b7e413f','吐蕃別館和周十一郎中楊七錄事望白水山作','呂溫','唐','唐诗','tang','','[]','純精結奇狀，皎皎天一涯。',96,'全唐诗/poet.tang.19000.json','["純精結奇狀，皎皎天一涯。", "玉嶂擁清氣，蓮峰開白花。", "半巖晦雲雪，高頂澄煙霞。", "朝昏對賓館，隱映如仙家。", "夙聞蘊孤尚，終欲窮幽遐。", "暫因行役暇，偶得志所嘉。", "明時無外戶，勝境即中華。", "況今舅甥國，誰道隔流沙。"]'),
('abf4f3ab-455e-45f8-a783-923d6434a2a0','奉和張舍人閣中直夜思聞雅琴因書事通簡僚友','呂溫','唐','唐诗','tang','','[]','迢遞天上直，寂寞丘中琴。',72,'全唐诗/poet.tang.19000.json','["迢遞天上直，寂寞丘中琴。", "憶爾山水韻，起予仁智心。", "凝情在正始，超想疎煩襟。", "涼生子夜後，月照禁垣深。", "遠風靄蘭氣，微露清桐陰。", "方襲緇衣慶，永奉南薰吟。"]'),
('e84b1b9f-31ef-4943-a4b4-efbf20d6e414','和舍弟惜花絕句','呂溫','唐','唐诗','tang','','[]','去年無花看，今年未看花。',24,'全唐诗/poet.tang.19000.json','["去年無花看，今年未看花。", "更聞飄落盡，走馬向誰家。"]'),
('831340f9-8136-4cfd-b167-b4cf22ca64c9','和恭聽曉籠中山鵲','呂溫','唐','唐诗','tang','','[]','掩[抑]中天意，悽愴觸籠音。',26,'全唐诗/poet.tang.19000.json','["掩[抑]中天意，悽愴觸籠音。", "驚曉一聞處，傷春千里心。"]'),
('ffd38736-bdc8-4562-a9cf-32421dbb94fd','和舍弟讓籠中鷹','呂溫','唐','唐诗','tang','','[]','未用且求安，無猜也不殘。',50,'全唐诗/poet.tang.19000.json','["未用且求安，無猜也不殘。", "九天飛勢在，六月目[睛]寒。", "動觸樊籠倦，閑消肉食難。", "主人憎惡鳥，試待一呼看。"]'),
('40c4708f-c549-4604-886d-9104c5a792da','同恭夏日題尋真觀李寬中秀才書院','呂溫','唐','唐诗','tang','','[]','閉院開軒笑語闌，江山併入一壺寬。',64,'全唐诗/poet.tang.19000.json','["閉院開軒笑語闌，江山併入一壺寬。", "微風但覺杉香滿，烈日方知竹氣寒。", "披卷最宜生白室，吟詩好就步虛壇。", "願君此地攻文字，如煉仙家九轉丹。"]'),
('9119e1b9-97a3-473d-8829-e2de87dd4324','同舍弟恭歲暮寄晉州李六協律三十韻','呂溫','唐','唐诗','tang','','[]','古人猶悲秋，況復歲暮時。',288,'全唐诗/poet.tang.19000.json','["古人猶悲秋，況復歲暮時。", "急景迫流念，窮陰結長悲。", "陽烏下西嶺，月鵲驚南枝。", "攬衣步霜砌，倚杖臨冰池。", "怳怳若有失，悄悄良不怡。", "忽聞晨起吟，宛是同所思。", "有美壯感激，無何遠棲遲。", "摧藏變化用，掩抑扶搖姿。", "時傑豈虛出，天道信可欺。", "巨川望汔濟，寒谷待潛吹。", "劒匣益精利，玉韜寧磷緇。", "戒哉輕沽諸，行矣自寵之。", "伊我抱微尚，仲氏即心期。", "討論自少小，形影相差池。", "比來胸中氣，欲耀天下奇。", "雲雨沛蕭艾，煙閣雙萎蕤。", "幾年困方枘，一旦迷多岐。", "道因窮理悟，命以盡性知。", "事去類絕弦，時來如轉規。", "伊呂偶然得，孔墨徒爾爲。", "早行多露悔，強進觸藩羸。", "功名豈身利，仁義非吾私。", "萬物自身化，一失何驅馳。", "不如任行止，委命安所宜。"]'),
('44a47c95-11fc-406c-a9bb-4dc2fe40b8ec','青海西寄竇三端公','呂溫','唐','唐诗','tang','','[]','時同事弗同，窮節厲陰風。',48,'全唐诗/poet.tang.19000.json','["時同事弗同，窮節厲陰風。", "我役流沙外，君朝紫禁中。", "從容非所羨，辛苦竟何功。", "但示酬恩路，浮生任轉蓬。"]'),
('ca0a0144-8a3c-49ad-bb47-af73f31846a9','蕃中拘留歲餘迴至隴石先寄城中親故','呂溫','唐','唐诗','tang','','[]','蓬轉星霜改，蘭陔色養違。',48,'全唐诗/poet.tang.19000.json','["蓬轉星霜改，蘭陔色養違。", "窮泉百死別，絕域再生歸。", "鏡數成絲髮，囊收抆血衣。", "酬恩有何力，秖棄一毛微。"]'),
('2ddd5a9c-f14a-4816-8c9c-c300e3d468fa','吐蕃別館臥病寄朝中諸友','呂溫','唐','唐诗','tang','','[]','星漢縱橫車馬喧，風搖玉佩燭花繁。',32,'全唐诗/poet.tang.19000.json','["星漢縱橫車馬喧，風搖玉佩燭花繁。", "豈知羸臥窮荒外，日滿深山猶閉門。"]'),
('914430c1-0aab-4a66-8757-339ed2ce1b59','吐蕃別館中和日寄朝中僚舊','呂溫','唐','唐诗','tang','','[]','清時令節千官會，絕域窮山一病夫。',32,'全唐诗/poet.tang.19000.json','["清時令節千官會，絕域窮山一病夫。", "遙想滿堂歡笑處，幾人緣我向西隅。"]'),
('9d59c785-4f4e-468b-a02f-3f695dc68c30','及第後荅潼關主人','呂溫','唐','唐诗','tang','','[]','本欲雲雨化，却隨波浪翻。',50,'全唐诗/poet.tang.19000.json','["本欲雲雨化，却隨波浪翻。", "一沾太常第，十過潼關門。", "志力且虛棄，功名誰復論。", "主人故相問，[慙]笑不能言。"]'),
('6994530c-4bb0-40f7-a4ce-15683d96a209','河中城南姚家浴後題贈主人','呂溫','唐','唐诗','tang','','[]','新浴振輕衣，滿堂寒月色。',24,'全唐诗/poet.tang.19000.json','["新浴振輕衣，滿堂寒月色。", "主人有美酒，況是曾相識。"]'),
('00cc533a-059f-49d8-9812-a43906c52e11','看渾中丞山桃花初有他客不通晚方得入因有戲贈','呂溫','唐','唐诗','tang','','[]','朝來駐馬香街裏，風度遙聞語笑聲。',32,'全唐诗/poet.tang.19000.json','["朝來駐馬香街裏，風度遙聞語笑聲。", "無事閉門教日晚，山桃落盡不勝情。"]'),
('9aa8f7e8-bdb9-47d6-a706-820954f8a7a0','贈友人','呂溫','唐','唐诗','tang','','[]','南山雙喬松，擢本皆千尋。',72,'全唐诗/poet.tang.19000.json','["南山雙喬松，擢本皆千尋。", "夕流膏露津，朝被青雲陰。", "負雪出深澗，搖風倚高岑。", "明堂久不構，雲幹何森森。", "匠意方雕巧，時情正誇淫。", "生材會有用，天地豈無心。"]'),
('eb3e517c-0a3f-4366-a51c-c7e5b6afa3a4','道州夏日郡內北橋新亭書懷贈何元二處士','呂溫','唐','唐诗','tang','','[]','結構池梁上，登臨日幾迴。',120,'全唐诗/poet.tang.19000.json','["結構池梁上，登臨日幾迴。", "晴空交密葉，陰岸積蒼苔。", "爽氣中央滿，清風四面來。", "振衣生羽翰，高枕出塵埃。", "齊物魚何樂，忘機鳥不猜。", "閑銷炎晝靜，選勝火雲開。", "僻遠宜孱性，優游賴廢材。", "願爲長泛梗，莫作重然灰。", "守道窮非過，先時動是灾。", "寄言徐孺子，賓榻旦徘徊。"]'),
('d278ecae-0473-4883-badf-35a51775044f','道州弘道縣主簿知縣三年頗著廉慎秩滿縣闕申使請留將赴衡州題其廳事','呂溫','唐','唐诗','tang','','[]','爲理賴同力，陟明非所任。',48,'全唐诗/poet.tang.19000.json','["爲理賴同力，陟明非所任。", "廢田方墾草，新柘未成陰。", "術淺功難就，人疲感易深。", "煩君駐歸棹，與慰不欺心。"]'),
('eeaf4924-0078-4827-a6e5-469f5c7377fe','道州將赴衡州酬別江華毛令','呂溫','唐','唐诗','tang','','[]','布帛精麄任土宜，疲人識信每先期。',32,'全唐诗/poet.tang.19000.json','["布帛精麄任土宜，疲人識信每先期。", "明朝別後無他囑，雖是蒲鞭也莫施。"]'),
('0b794523-2925-4f69-89b4-bee7b3f2f4c9','道州夏日早訪荀參軍林園敬酬見贈','呂溫','唐','唐诗','tang','','[]','高眠日出始開門，竹徑旁通到後園。',64,'全唐诗/poet.tang.19000.json','["高眠日出始開門，竹徑旁通到後園。", "陶亮橫琴空有意，任棠置水竟無言。", "松窗宿翠含風薄，槿援朝花帶露繁。", "山郡本來車馬少，更容相訪莫辭喧。"]'),
('65f198ad-081f-4d17-b9c9-fa77ef4e5040','道州敬酬何處士懷郡樓月夜之作','呂溫','唐','唐诗','tang','','[]','清質悠悠素彩融，長川迥陸合爲空。',32,'全唐诗/poet.tang.19000.json','["清質悠悠素彩融，長川迥陸合爲空。", "佳人甚近山城閉，夏夜相望水鏡中。"]'),
('1913b906-c679-4afd-9d9c-27b4adea76b3','道州敬酬何處士書情見贈','呂溫','唐','唐诗','tang','','[]','意氣曾傾四國豪，偶來幽寺息塵勞。',64,'全唐诗/poet.tang.19000.json','["意氣曾傾四國豪，偶來幽寺息塵勞。", "嚴陵釣處江初滿，梁甫吟時月正高。", "新識幾人知杞梓，故園何歲長蓬蒿。", "期君自致青雲上，不用傷心歎二毛。"]'),
('55f35e81-eb00-49c5-9454-b583449c7543','戲贈靈澈上人','呂溫','唐','唐诗','tang','','[]','僧家亦有芳春興，自是禪心無滯境。',32,'全唐诗/poet.tang.19000.json','["僧家亦有芳春興，自是禪心無滯境。", "君看池水湛然時，何曾不受花枝影。"]'),
('cd1b5a78-ba91-4db6-beb0-302578f2c12d','二月一日是貞元舊節有感絕句寄黔南竇三洛陽盧七','呂溫','唐','唐诗','tang','','[]','同事先皇立玉墀，中和舊節又支離。',32,'全唐诗/poet.tang.19000.json','["同事先皇立玉墀，中和舊節又支離。", "今朝各自看花處，萬里遙知掩淚時。"]'),
('3fe69b33-97fd-4b3b-ab21-252170d3f45d','初發道州荅崔三連州題海陽亭見寄絕句','呂溫','唐','唐诗','tang','','[]','吏中習隱好躋攀，不擾疲人便自閑。',32,'全唐诗/poet.tang.19000.json','["吏中習隱好躋攀，不擾疲人便自閑。", "聞說慇懃海陽事，令人轉憶舜祠山。"]'),
('09a74f09-999d-452e-a52c-855802aa02b1','荅段秀才','呂溫','唐','唐诗','tang','','[]','盡日看花君不來，江城半夜與君開。',32,'全唐诗/poet.tang.19000.json','["盡日看花君不來，江城半夜與君開。", "樓中共指南園火，紅燼隨花落碧苔。"]'),
('afce00e6-d52f-467d-bfd0-5b859eba3e7d','宗禮欲往桂州苦雨因以戲贈','呂溫','唐','唐诗','tang','','[]','農人辛苦綠苗齊，正愛梅天水滿堤。',32,'全唐诗/poet.tang.19000.json','["農人辛苦綠苗齊，正愛梅天水滿堤。", "知汝使車行意速，但令驄馬著鄣泥。"]'),
('0bb08537-625e-4066-bb1e-b37c70f2a209','道州奉寄襄陽裴相公','呂溫','唐','唐诗','tang','','[]','悠悠世路自浮沈，豈問仁賢待物心。',32,'全唐诗/poet.tang.19000.json','["悠悠世路自浮沈，豈問仁賢待物心。", "最憶過時留宴處，豔歌催酒後亭深。"]'),
('beca6f42-4666-4e74-b549-3dbf48fb430d','吐蕃別館月夜','呂溫','唐','唐诗','tang','','[]','三五窮荒月，還應照北堂。',24,'全唐诗/poet.tang.19000.json','["三五窮荒月，還應照北堂。", "迴身向暗臥，不忍見圓光。"]'),
('d18389c3-c130-47dc-90c1-9153f750940b','望思臺作','呂溫','唐','唐诗','tang','','[]','浸潤成宮蠱，蒼黃弄父兵。',48,'全唐诗/poet.tang.19000.json','["浸潤成宮蠱，蒼黃弄父兵。", "人情疑始變，天性感還生。", "宇縣猶能洽，閨門詎不平。", "空令千載後，悽愴望思名。"]'),
('21bafceb-4556-4956-963c-db950f27cd77','孟冬蒲津關河亭作','呂溫','唐','唐诗','tang','','[]','息駕非窮途，未濟豈迷津。',48,'全唐诗/poet.tang.19000.json','["息駕非窮途，未濟豈迷津。", "獨立大河上，北風來吹人。", "雪霜自茲始，草木當更新。", "嚴冬不肅殺，何以見陽春。"]'),
('49a3037d-ff19-41a6-9427-9bf6a1098d0a','鞏路感懷','呂溫','唐','唐诗','tang','','[]','馬嘶白日暮，劒鳴秋氣來。',24,'全唐诗/poet.tang.19000.json','["馬嘶白日暮，劒鳴秋氣來。", "我心浩無際，河上空徘徊。"]'),
('df902d49-82b4-436e-b03b-daa199a7b92c','題梁宣帝陵二首 一','呂溫','唐','唐诗','tang','','[]','即讐終自翦，覆國豈爲雄。',24,'全唐诗/poet.tang.19000.json','["即讐終自翦，覆國豈爲雄。", "假號孤城裏，何殊在甬東。"]'),
('bbd976af-147d-4603-876d-d1424bcfd7bb','題梁宣帝陵二首 二','呂溫','唐','唐诗','tang','','[]','祀夏功何薄，尊周義不成。',24,'全唐诗/poet.tang.19000.json','["祀夏功何薄，尊周義不成。", "淒涼庾信賦，千載共傷情。"]'),
('5af61ecb-4c41-4634-983d-a27fddb5341e','岳陽懷古','呂溫','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','晨飆發荆州，落日到巴丘。',120,'全唐诗/poet.tang.19000.json','["晨飆發荆州，落日到巴丘。", "方知刳剡利，可接鬼神遊。", "二湖豁南寖，九派駛東流。", "襟帶三千里，盡在岳陽樓。", "憶昔鬬羣雄，此焉爭上游。", "吳昌屯虎旅，晉盛騖龍舟。", "宋齊紛禍難，梁陳成寇讎。", "鐘鼓長震耀，魚龍不得休。", "風雪一蕭散，功業忽如浮。", "今日時無事，空江滿白鷗。"]'),
('b617825b-f157-4040-ae7d-e0737141e481','道州途中即事','呂溫','唐','唐诗','tang','','[]','零桂佳山水，[滎]陽舊自同。',146,'全唐诗/poet.tang.19000.json','["零桂佳山水，[滎]陽舊自同。", "經途看不暇，遇境說難窮。", "疊嶂青時合，澄湘漫處空。", "舟移明鏡裏，路入畫屏中。", "巖壑千家接，松蘿一徑通。", "漁煙生縹緲，犬吠隔籠葱。", "戲鳥留餘翠，幽花恡晚紅。", "光翻沙瀨日，香散橘園風。", "信美非吾土，分憂屬賤躬。", "守愚資地僻，卹隱望年豐。", "且保心能靜，那求政必工。", "課終如免戾，歸養洛城東。"]'),
('886658ad-200a-4b9c-93bd-5b103ca04f0e','登少陵原望秦中諸川太原王至德妙用有水術因用感歎','呂溫','唐','唐诗','tang','','[]','少陵最高處，曠望極秋空。',144,'全唐诗/poet.tang.19000.json','["少陵最高處，曠望極秋空。", "君山噴清源，脉散秦川中。", "荷鍤自成雨，由來非鬼工。", "如何盛明代，委棄傷豳風。", "涇灞徒絡繹，漆沮虛會同。", "東流滔滔去，沃野飛秋蓬。", "大禹平水土，吾人得其宗。", "發機迴地勢，運思與天通。", "早欲獻奇策，豐財敘西戎。", "豈知年三十，未識大明宮。", "卷爾出岫雲，追吾入冥鴻。", "無爲學驚俗，狂醉哭途窮。"]'),
('4f2ce410-9efb-41b9-bf08-70752f495087','奉敕祭南嶽十四韻','呂溫','唐','唐诗','tang','','["\u8861\u5c71"]','皇家禮赤帝，謬獲司風域。',168,'全唐诗/poet.tang.19000.json','["皇家禮赤帝，謬獲司風域。", "致齋紫蓋下，宿設祝融側。", "鳴澗驚宵寐，清猿遞時刻。", "澡潔事夙興，簪佩思盡飾。", "危壇象嶽趾，秘殿翹翬翼。", "登拜不遑願，酌獻皆累息。", "贊道儀匪繁，祝史詞甚直。", "忽覺心魂悸，如有精靈逼。", "漠漠雲氣生，森森杉栢黑。", "風吹虛簫韻，露洗寒玉色。", "寂寞有至公，馨香在明德。", "禮成謝邑吏，駕言歸郡職。", "憩桑訪蠶事，遵疇課農力。", "所願風雨時，迴首瞻南極。"]'),
('ea381f78-93b7-4e26-825e-74e48e8f1147','經河源軍漢邨作','呂溫','唐','唐诗','tang','','[]','行行忽到舊河源，城外千家作漢村。',64,'全唐诗/poet.tang.19000.json','["行行忽到舊河源，城外千家作漢村。", "樵採爲侵征虜墓，耕耘猶就破羌屯。", "金湯天險長全設，伏臘華風亦暗存。", "暫駐單車空下淚，有心無力復何言。"]'),
('f72719f9-d363-4ad9-9505-1186bd31aaa8','題河州赤岸橋','呂溫','唐','唐诗','tang','','[]','左南橋上見河州，遺老相依赤岸頭。',32,'全唐诗/poet.tang.19000.json','["左南橋上見河州，遺老相依赤岸頭。", "匝塞歌鐘受恩者，誰憐被髮哭東流。"]'),
('53193e66-6f34-4823-98d0-9f59d9ea20a8','題陽人城','呂溫','唐','唐诗','tang','','[]','忠驅義感即風雷，誰道南方乏武才。',32,'全唐诗/poet.tang.19000.json','["忠驅義感即風雷，誰道南方乏武才。", "天下起兵誅董卓，長沙子弟最先來。"]'),
('ab676126-ebf9-4825-a0e5-8dffaa67f83e','晉王龍驤墓','呂溫','唐','唐诗','tang','','[]','虎旗龍艦順長風，坐引全吳入掌中。',32,'全唐诗/poet.tang.19000.json','["虎旗龍艦順長風，坐引全吳入掌中。", "孫皓小兒何足取，便令千載笑爭功。"]'),
('2b4dbde9-900b-4109-bdfe-12c08b3989f9','題石勒城二首 一','呂溫','唐','唐诗','tang','','[]','長驅到處積人頭，大斾連營壓上游。',32,'全唐诗/poet.tang.19000.json','["長驅到處積人頭，大斾連營壓上游。", "建業烏棲何足問，慨然歸去王中州。"]'),
('b0202fb0-4a13-4de9-a5a3-7ca989a7ccc6','題石勒城二首 二','呂溫','唐','唐诗','tang','','[]','天生傑異固難馴，應變摧枯若有神。',32,'全唐诗/poet.tang.19000.json','["天生傑異固難馴，應變摧枯若有神。", "夷甫自能疑倚嘯，忍將虛誕誤時人。"]'),
('70461c20-6e4f-414e-93c8-1fc7465abd4c','劉郎浦口號','呂溫','唐','唐诗','tang','','[]','吳蜀成婚此水潯，明珠步障幄黃金。',32,'全唐诗/poet.tang.19000.json','["吳蜀成婚此水潯，明珠步障幄黃金。", "誰將一女輕天下，欲換劉郎鼎峙心。"]'),
('7dbb1cb7-a75e-4226-bdc9-0fd197d89f13','自江華之衡陽途中作','呂溫','唐','唐诗','tang','','[]','孤棹遲遲悵有違，沿湘數日逗晴暉。',32,'全唐诗/poet.tang.19000.json','["孤棹遲遲悵有違，沿湘數日逗晴暉。", "人生隨分爲憂喜，迴雁峰南是北歸。"]'),
('f4804373-f8a1-4dc3-b0fa-56ce46d93551','吐蕃別館送楊七錄事先歸','呂溫','唐','唐诗','tang','','[]','愁雲重拂地，飛雪亂遙程。',24,'全唐诗/poet.tang.19000.json','["愁雲重拂地，飛雪亂遙程。", "莫慮前山暗，歸人正眼明。"]'),
('f9de4ce7-66ea-43f0-8976-cd193d6e48bf','奉送范司空赴朔方','呂溫','唐','唐诗','tang','','[]','築壇登上將，膝席委前籌。',72,'全唐诗/poet.tang.19000.json','["築壇登上將，膝席委前籌。", "虜滅南侵跡，朝分北顧憂。", "抗旌迴廣漠，撫劒動旄頭。", "坐見黃雲暮，行看白草秋。", "山橫舊秦塞，河繞古靈州。", "戍守如無事，惟應獵騎游。"]'),
('5d0e5278-81cd-4efe-bc81-ddc544749c31','送文暢上人東遊','呂溫','唐','唐诗','tang','','[]','隨緣聊振錫，高步出東城。',48,'全唐诗/poet.tang.19000.json','["隨緣聊振錫，高步出東城。", "水止無恒地，雲行不計程。", "到時爲彼岸，過處即前生。", "今日臨岐別，吾徒自有情。"]'),
('53a2852c-be2c-4efd-a808-5b994c598280','喜儉北至送宗禮南行','呂溫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭舟始泊，桂江帆又開。',48,'全唐诗/poet.tang.19000.json','["洞庭舟始泊，桂江帆又開。", "魂從會處斷，愁向笑中來。", "惝怳看殘景，殷勤祝此盃。", "衡陽刷羽待，成取一行迴。"]'),
('7ca86ad6-5a75-44fb-9af8-c5a73522870e','送段九秀才歸灃州','呂溫','唐','唐诗','tang','','[]','湘南孤白芷，幽託在清潯。',72,'全唐诗/poet.tang.19000.json','["湘南孤白芷，幽託在清潯。", "豈有馨香發，空勞知處深。", "摧賢路已隔，賑乏力不任。", "慙我一言分，貞君千里心。", "寸義薄聯組，片誠敵兼金。", "方期踐冰雪，無使弱思侵。"]'),
('8b422008-5472-4c8e-855e-486c449e1b1b','衡州送李十一兵曹赴浙東','呂溫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','慷慨視別劒，淒清泛離琴。',48,'全唐诗/poet.tang.19000.json','["慷慨視別劒，淒清泛離琴。", "前程楚塞斷，此恨洞庭深。", "文字已久廢，循良非所任。", "期君碧雲上，千里一揚音。"]'),
('5639d478-c006-47d4-a1d3-d72ecba760a9','臨洮送袁七書記歸朝','呂溫','唐','唐诗','tang','','[]','憶年十五在江湄，聞說平涼且半疑。',32,'全唐诗/poet.tang.19000.json','["憶年十五在江湄，聞說平涼且半疑。", "豈料殷勤洮水上，却將家信託袁師。"]'),
('5eeb5b82-90c0-4cb8-a7f5-c54c8f76a7a7','江陵酒中留別坐客','呂溫','唐','唐诗','tang','','[]','尋常縱恣倚青春，不契心期便不親。',32,'全唐诗/poet.tang.19000.json','["尋常縱恣倚青春，不契心期便不親。", "今日煙波九疑去，相逢盡是眼中人。"]'),
('3ecb0a63-e967-46d3-aa33-cfccd58bc947','道州酬送何山人之容州','呂溫','唐','唐诗','tang','','[]','匣有青萍筒有書，何門不可曳長裾。',32,'全唐诗/poet.tang.19000.json','["匣有青萍筒有書，何門不可曳長裾。", "應須定取真知者，遣對明君說子虛。"]'),
('149785aa-57ba-4d1a-a9d6-814eb7dde8e9','道州送戴簡處士往賀州謁楊侍郎','呂溫','唐','唐诗','tang','','[]','羸馬孤童鳥道微，三千客散獨南歸。',32,'全唐诗/poet.tang.19000.json','["羸馬孤童鳥道微，三千客散獨南歸。", "山公念舊偏知我，今日因君淚滿衣。"]'),
('ec783f38-7ff3-4775-9618-eff12672de2b','春日遊郭駙馬大安亭子','呂溫','唐','唐诗','tang','','[]','戚里容閑客，山泉若化成。',48,'全唐诗/poet.tang.19000.json','["戚里容閑客，山泉若化成。", "寄遊芳徑好，借賞彩船輕。", "春至花常滿，年多水更清。", "此中如傳舍，但自立功名。"]'),
('5f287202-c629-4f46-ae62-58ed4de9c72b','楚州追制後舍弟直長安縣失囚花下共飲','呂溫','唐','唐诗','tang','','[]','天子收郡印，京兆責獄囚。',24,'全唐诗/poet.tang.19000.json','["天子收郡印，京兆責獄囚。", "狂兄與狂弟，不解對花愁。"]'),
('d324f450-a9c7-4141-ba88-d86a4a0ae44f','衡州歲前遊合江亭見山櫻蕊未折因賦含彩恡驚春','呂溫','唐','唐诗','tang','','[]','山櫻先春發，紅蕊滿霜枝。',48,'全唐诗/poet.tang.19000.json','["山櫻先春發，紅蕊滿霜枝。", "幽處竟誰見，芳心空自知。", "似奪朝日照，疑畏煖風吹。", "欲問含彩意，恐驚輕薄兒。"]'),
('89720e30-5558-4007-acc7-e745df2c4496','衡州登樓望南館臨水花呈房戴段李諸公','呂溫','唐','唐诗','tang','','[]','夭桃臨方塘，暮色堪秋思。',48,'全唐诗/poet.tang.19000.json','["夭桃臨方塘，暮色堪秋思。", "託根豈求潤，照影非自媚。", "罥挂青柳絲，零落綠錢地。", "佳期竟何許，時有幽禽至。"]'),
('7a75d079-3e15-4509-99c0-39279579bb98','合江亭檻前多高竹不見遠岸花客命翦之感而成詠','呂溫','唐','唐诗','tang','','[]','吉凶豈前卜，人事何飜覆。',48,'全唐诗/poet.tang.19000.json','["吉凶豈前卜，人事何飜覆。", "緣看數日花，却翦凌霜竹。", "常言契君操，今乃妨衆目。", "自古病當門，誰言出幽獨。"]'),
('d48ca166-8486-46c8-8369-7343f0653100','道州春遊歐陽家林亭','呂溫','唐','唐诗','tang','','[]','道州城北歐陽家，去郭一里占煙霞。',64,'全唐诗/poet.tang.19000.json','["道州城北歐陽家，去郭一里占煙霞。", "主人雖朴甚有思，解留滿地紅桃花。", "桃花成泥不須掃，明朝更訪桃源老。", "政成興足告即歸，門前便是家山道。"]'),
('c67b4710-802a-4ee5-9f1d-8f27b8af8538','衡州早春偶遊黃溪口號','呂溫','唐','唐诗','tang','','[]','偶尋皇溪日欲沒，早梅未盡山櫻發。',32,'全唐诗/poet.tang.19000.json','["偶尋皇溪日欲沒，早梅未盡山櫻發。", "無事江城閉此身，不得坐待花間月。"]'),
('a01bf2d2-039b-4154-b6c2-3c7e8ae5fcf7','衡州夜後把火看花留客','呂溫','唐','唐诗','tang','','[]','紅芳暗落碧池頭，把火遙看且少留。',32,'全唐诗/poet.tang.19000.json','["紅芳暗落碧池頭，把火遙看且少留。", "半夜忽然風更起，明朝不復上南樓。"]'),
('d37a469a-6212-41d7-8d9d-9bf439d0e407','夜後把火看花南園招李十一兵曹不至呈座上諸公','呂溫','唐','唐诗','tang','','[]','夭桃紅燭正相鮮，傲吏閑齋困獨眠。',32,'全唐诗/poet.tang.19000.json','["夭桃紅燭正相鮮，傲吏閑齋困獨眠。", "應是夢中飛作蝶，悠揚只在此花前。"]'),
('342f21d7-7799-43b8-b411-9f306c25a1d4','順宗至德大聖大安孝皇帝挽歌詞三首 一','呂溫','唐','唐诗','tang','','[]','遐視輕神寶，傳歸屬聖猷。',48,'全唐诗/poet.tang.19000.json','["遐視輕神寶，傳歸屬聖猷。", "堯功終有待，文德本無憂。", "坐受朝汾水，行看告岱丘。", "那知鼎成後，龍馭弗淹留。"]'),
('31e5a6da-2f20-4d36-ae28-27f857652787','順宗至德大聖大安孝皇帝挽歌詞三首 二','呂溫','唐','唐诗','tang','','[]','監撫垂三紀，聲徽洽萬方。',48,'全唐诗/poet.tang.19000.json','["監撫垂三紀，聲徽洽萬方。", "禮因馳道著，明自墾田彰。", "積漸承鴻業，從容守太康。", "更留園寢詔，恭聽有餘芳。"]'),
('a68e83b4-2000-4a55-87d8-6cd3a49b7da5','順宗至德大聖大安孝皇帝挽歌詞三首 三','呂溫','唐','唐诗','tang','','[]','早秋同軌至，晨斾露華滋。',48,'全唐诗/poet.tang.19000.json','["早秋同軌至，晨斾露華滋。", "挽度千夫咽，笳凝六馬遲。", "劒悲長閉日，衣望出遊時。", "風起西陵樹，淒涼滿孝思。"]'),
('0a8dfa01-4ce1-47f0-afe2-f4031902861f','詠蜀客石琹枕','呂溫','唐','唐诗','tang','','[]','可憐他山石，幾度負貞堅。',48,'全唐诗/poet.tang.19000.json','["可憐他山石，幾度負貞堅。", "推遷強爲用，彫斲傷自然。", "文含巴江浪，色起青城煙。", "更聞餘玉聲，時入朱絲弦。"]'),
('1285e5fc-3462-461d-83bd-21c0663e6055','河南府試贖帖賦得鄉飲酒詩','呂溫','唐','唐诗','tang','','[]','酌言修舊典，刈楚始登堂。',48,'全唐诗/poet.tang.19000.json','["酌言修舊典，刈楚始登堂。", "百拜賓儀盡，三終樂奏長。", "想同鶯出谷，看似雁成行。", "禮罷知何適，隨雲入帝鄉。"]'),
('2e64f0cc-0611-464b-b22a-f523086159f4','賦得失羣鶴','呂溫','唐','唐诗','tang','','[]','杳杳冲天鶴，風排勢暫違。',48,'全唐诗/poet.tang.19000.json','["杳杳冲天鶴，風排勢暫違。", "有心長自負，無伴可相依。", "萬里寧辭遠，三山詎憶歸。", "但令毛羽在，何處不翻飛。"]'),
('06f0b132-b5d4-4f78-8607-4658adce60f6','道州南樓換柱','呂溫','唐','唐诗','tang','','[]','鴻災起無朕，有見非前知。',48,'全唐诗/poet.tang.19000.json','["鴻災起無朕，有見非前知。", "蟻入不足恤，柱傾何可追。", "良工操斤斧，沈吟方在斯。", "殫材事朽廢，曷若新宏規。"]'),
('1f6aee7d-6663-4789-9c64-ad47752214a1','道州北池放鵝','呂溫','唐','唐诗','tang','','[]','我非好鵝癖，爾乏鳴雁姿。',48,'全唐诗/poet.tang.19000.json','["我非好鵝癖，爾乏鳴雁姿。", "安得免沸鼎，澹然遊清池。", "見生不忍食，深情固在斯。", "能自遠飛去，無念稻粱爲。"]'),
('7b21b404-e080-4b18-a41d-082b68f15e3c','廻風有懷','呂溫','唐','唐诗','tang','','[]','銀宮翠島煙霏霏，珠樹玲瓏朝日暉。',32,'全唐诗/poet.tang.19000.json','["銀宮翠島煙霏霏，珠樹玲瓏朝日暉。", "神仙望見不得到，却逐迴風何處歸。"]'),
('0e95e497-0951-4a6b-ac13-246b38075b98','蕃中荅退渾詞二首 一','呂溫','唐','唐诗','tang','','[]','退渾兒，退渾兒，朔風長在氣何衰。',32,'全唐诗/poet.tang.19000.json','["退渾兒，退渾兒，朔風長在氣何衰。", "萬羣鐵馬從奴虜，強弱由人莫歎時。"]'),
('de8fca4b-97ca-4cb0-bdd4-e1c85af0ccd8','蕃中荅退渾詞二首 二','呂溫','唐','唐诗','tang','','[]','退渾兒，退渾兒，冰消青海草如絲。',32,'全唐诗/poet.tang.19000.json','["退渾兒，退渾兒，冰消青海草如絲。", "明堂天子朝萬國，神島龍駒將與誰。"]'),
('3d13812e-7c3e-4a53-9ffc-e0996ce1cb56','上官昭容書樓歌','呂溫','唐','唐诗','tang','','[]','漢家婕妤唐昭容，工詩能賦千載同。',243,'全唐诗/poet.tang.19000.json','["漢家婕妤唐昭容，工詩能賦千載同。", "自言才藝是天真，不服丈夫勝婦人。", "歌闌舞罷閑無事，縱恣優游弄文字。", "玉樓寶架中天居，緘奇秘異萬卷馀。", "水精編帙錄鈿軸，雲母搗紙黃金書。", "風吹花露清旭時，綺窗高挂紅綃帷。", "香囊盛煙繡結絡，翠羽拂案青琉璃。", "吟披嘯卷終無已，皎皎淵機破研理。", "詞縈彩翰紫鸞迴，思耿寥天碧雲起。", "碧雲起，心悠哉。", "境深轉苦坐自摧，金梯珠履聲一斷。", "瑤階日夜生青苔，青苔祕空關。", "曾比羣玉山，神仙杳何許。", "遺逸滿人間，君不見洛陽南市賣書肆。", "有人買得研神記，紙上香多蠹不成。", "昭容題處猶分明，令人惆悵難爲情。"]'),
('8730625b-e51e-4f44-8f6d-fb7757cdf263','聞砧有感','呂溫','唐','唐诗','tang','','[]','千門儼雲端，此地富羅紈。',48,'全唐诗/poet.tang.19000.json','["千門儼雲端，此地富羅紈。", "秋月三五夜，砧聲滿長安。", "幽人感中懷，靜聽淚汍瀾。", "所恨搗衣者，不知天下寒。"]'),
('0f7654e8-1fbb-4f22-afbe-ac9fc190b9a4','早覺有感','呂溫','唐','唐诗','tang','','[]','東方殊未明，暗室蟲正飛。',48,'全唐诗/poet.tang.19000.json','["東方殊未明，暗室蟲正飛。", "先覺忽先起，衣裳顛倒時。", "嚴冬寒漏長，此夜如何其。", "不用思秉燭，扶桑有清暉。"]'),
('b6ca0486-0760-4131-894e-d8a9712ff712','冬日病中即事','呂溫','唐','唐诗','tang','','[]','牆下長安道，囂塵咫尺間。',48,'全唐诗/poet.tang.19000.json','["牆下長安道，囂塵咫尺間。", "久牽身外役，暫得病中閑。", "背喜朝陽滿，心憐暮鳥還。", "吾廬在何處，南有白雲山。"]'),
('7230be30-877b-441b-9c74-1b709f88843b','病中自戶部員外郎轉司封','呂溫','唐','唐诗','tang','','[]','羸臥承新命，優容獲所安。',48,'全唐诗/poet.tang.19000.json','["羸臥承新命，優容獲所安。", "遣兒迎賀客，無力拂塵冠。", "偃仰晴軒暖，支離曉鏡寒。", "那堪報恩去，感激對衰蘭。"]'),
('ca33e2bb-0ca2-4307-b65f-d80ce2f1ea02','久病初朝衢中即事','呂溫','唐','唐诗','tang','','[]','沉痾矌十旬，還過直城闉。',48,'全唐诗/poet.tang.19000.json','["沉痾矌十旬，還過直城闉。", "老馬猶知路，羸童欲怕人。", "久隳三徑計，更強百年身。", "許國將何力，空生衣上塵。"]'),
('ffa2aa37-ceb2-47a7-93af-5f6c1e283fed','道州城北樓觀李花','呂溫','唐','唐诗','tang','','[]','夜疑關山月，曉似沙場雪。',48,'全唐诗/poet.tang.19000.json','["夜疑關山月，曉似沙場雪。", "曾使西域來，幽情望超越。", "將念浩無際，欲言忘所說。", "豈是花感人，自憐抱孤節。"]'),
('fac2de03-4089-4111-b244-834ebb49df1d','道州秋夜南樓即事','呂溫','唐','唐诗','tang','','[]','誰念獨坐愁，日暮此南樓。',48,'全唐诗/poet.tang.19000.json','["誰念獨坐愁，日暮此南樓。", "雲去舜祠閉，月明瀟水流。", "猿聲何處曉，楓葉滿山秋。", "不分匣中鏡，少年看白頭。"]'),
('a2e51759-a6a1-4731-a255-2f7b3b4da0e4','道州觀野火','呂溫','唐','唐诗','tang','','[]','南風吹烈火，焰焰燒楚澤。',120,'全唐诗/poet.tang.19000.json','["南風吹烈火，焰焰燒楚澤。", "陽景當晝遲，陰天半夜赤。", "過處若彗掃，來時如電激。", "豈復辨蕭蘭，焉能分玉石。", "蟲蛇盡爍爛，虎兕出奔迫。", "積穢一蕩除，和氣始融液。", "堯時既敬授，禹稼斯肇迹。", "遍生合穎禾，大秀兩岐麥。", "家有京坻詠，人無溝壑慼。", "乃悟焚如功，來歲終受益。"]'),
('dc81af55-a84f-4dff-908f-288c2a3e7128','衡州早春二首 一','呂溫','唐','唐诗','tang','','[]','碧水何逶迤，東風吹沙草。',24,'全唐诗/poet.tang.19000.json','["碧水何逶迤，東風吹沙草。", "煙波千萬曲，不辨嵩陽道。"]'),
('686299c5-6b9a-4615-8bdb-06a04d8e742e','衡州早春二首 二','呂溫','唐','唐诗','tang','','[]','病肺不飲酒，傷心不看花。',24,'全唐诗/poet.tang.19000.json','["病肺不飲酒，傷心不看花。", "惟驚望鄉處，猶自隔長沙。"]'),
('b57a88ef-9a0b-4fc8-aad7-5c136a018e5b','郡內書懷寄劉連州竇夔州','呂溫','唐','唐诗','tang','','[]','朱邑何爲者，桐鄉有古祠。',24,'全唐诗/poet.tang.19000.json','["朱邑何爲者，桐鄉有古祠。", "我心常所慕，二郡老人知。"]'),
('cbe7e35e-2cb5-45c9-a315-04e2bddc478c','偶然作二首 一','呂溫','唐','唐诗','tang','','[]','棲棲復汲汲，忽覺年四十。',24,'全唐诗/poet.tang.19000.json','["棲棲復汲汲，忽覺年四十。", "今朝滿衣淚，不是傷春泣。"]'),
('150a61ce-fe4b-4ed1-9cf8-8527ed6a511d','偶然作二首 二','呂溫','唐','唐诗','tang','','[]','中夜兀然坐，無言空涕洟。',24,'全唐诗/poet.tang.19000.json','["中夜兀然坐，無言空涕洟。", "丈夫志氣事，兒女安得知。"]'),
('133009d9-cb8e-4530-aed2-27161c1c3718','古興','呂溫','唐','唐诗','tang','','[]','越歐百鍊時，楚卞三泣地。',72,'全唐诗/poet.tang.19000.json','["越歐百鍊時，楚卞三泣地。", "二寶無人識，千齡皆棄置。", "空巖起白虹，古獄生紫氣。", "安得命世客，直來開奧秘。", "劒任刜鐘看，玉從投火試。", "必能絕疑惑，然後論奇異。"]'),
('0ac2084e-4019-4d6b-a378-a7a586b07d9c','風詠','呂溫','唐','唐诗','tang','','[]','微風生青蘋，習習出金塘。',84,'全唐诗/poet.tang.19000.json','["微風生青蘋，習習出金塘。", "輕搖深林翠，靜獵幽徑芳。", "掩抑時未來，鴻毛亦無傷。", "一朝乘嚴氣，萬里號清霜。", "北走摧鄧林，東去落扶桑。", "掃却垂天雲，澄清無私光。", "悠然返空寂，晏海通舟航。"]'),
('148dee72-c5a4-4929-911a-505336e9835f','鏡中歎白髮','呂溫','唐','唐诗','tang','','[]','年過潘岳纔三歲，還見星星兩鬢中。',32,'全唐诗/poet.tang.19000.json','["年過潘岳纔三歲，還見星星兩鬢中。", "縱使他時能早達，定知不作黑頭公。"]'),
('e1a8d66e-8522-4d12-b6c6-58e9db32770d','友人邀聽歌有感','呂溫','唐','唐诗','tang','','[]','文章拋盡愛功名，三十無成白髮生。',32,'全唐诗/poet.tang.19000.json','["文章拋盡愛功名，三十無成白髮生。", "辜負壯心羞欲死，勞君貴買斷腸聲。"]'),
('cc706844-511c-49a5-a102-41b6c9fb12d1','貞元十四年旱甚見權門移芍藥花','呂溫','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11"]','綠原青壠漸成塵，汲井開園日日新。',32,'全唐诗/poet.tang.19000.json','["綠原青壠漸成塵，汲井開園日日新。", "四月帶花移芍藥，不知憂國是何人。"]'),
('fe56effa-43f7-40d6-8811-7686ed5675b2','冬夜即事','呂溫','唐','唐诗','tang','','[]','百憂攢心起復臥，夜長耿耿不可過。',32,'全唐诗/poet.tang.19000.json','["百憂攢心起復臥，夜長耿耿不可過。", "風吹雪片似花落，月照冰文如鏡破。"]'),
('63af4d48-4676-4288-875c-6241ed1dfd4f','道州郡齋臥疾寄東館諸賢','呂溫','唐','唐诗','tang','','[]','東池送客醉年華，聞道風流勝習家。',32,'全唐诗/poet.tang.19000.json','["東池送客醉年華，聞道風流勝習家。", "獨臥郡齋寥落意，隔簾微雨濕梨花。"]'),
('ad80fe79-c1c9-46d1-a03d-e521dcc1cbe0','讀小弟詩有感因口號以示之','呂溫','唐','唐诗','tang','','[]','憶吾未冠賞年華，二十年間在咄嗟。',32,'全唐诗/poet.tang.19000.json','["憶吾未冠賞年華，二十年間在咄嗟。", "今來羨汝看花歲，似汝追思昨日花。"]'),
('0efd3593-2daa-4523-a76a-d1d57962b469','讀句踐傳','呂溫','唐','唐诗','tang','','[]','丈夫可殺不可羞，如何送我海西頭。',32,'全唐诗/poet.tang.19000.json','["丈夫可殺不可羞，如何送我海西頭。", "更生更聚終須報，二十年間死即休。"]'),
('937c8199-26f4-4f41-bbb5-ce5d1fd95a23','道州月歎','呂溫','唐','唐诗','tang','','[]','別館月，犁牛冰河金山雪。',40,'全唐诗/poet.tang.19000.json','["別館月，犁牛冰河金山雪。", "道州月，霜樹子規啼是血。", "壯心感此孤劒鳴，沈火在灰殊未滅。"]'),
('91ff8585-2491-4411-9899-add491e9cdf6','風歎','呂溫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','青海風，飛沙射面隨驚蓬。',40,'全唐诗/poet.tang.19000.json','["青海風，飛沙射面隨驚蓬。", "洞庭風，危檣欲折身若空。", "西馳南走有何事，會須一決百年中。"]'),
('83b28881-48b3-473e-b6b9-0ed64b6e8ba7','道州感興','呂溫','唐','唐诗','tang','','[]','當代知文字，先皇記姓名。',48,'全唐诗/poet.tang.19000.json','["當代知文字，先皇記姓名。", "七年天下立，萬里海西行。", "苦節終難辨，勞生竟自輕。", "今朝流落處，嘯水遶孤城。"]'),
('d4a01f02-9943-4d4f-bcea-41d23370d25a','和李使君三郎早秋城北亭宴崔司士因寄關中張評事','呂溫','唐','唐诗','tang','','[]','黃花古城路，上盡見青山。',72,'全唐诗/poet.tang.19000.json','["黃花古城路，上盡見青山。", "桑柘晴川口，牛羊落照間。", "野情隨卷幔，塵事隔重關。", "道合偏重賞，官微獨不閑。", "鶴分琴久罷，書到雁應還。", "爲謝登臨客，瓊林寄一攀。"]'),
('2e8c660d-163a-439d-8f3e-fbf4b4e022e3','題從叔園林','呂溫','唐','唐诗','tang','','[]','阮宅閑園暮，窻中見樹陰。',48,'全唐诗/poet.tang.19000.json','["阮宅閑園暮，窻中見樹陰。", "樵歌依野草，僧語過長林。", "鳥向花間井，人彈竹裏琴。", "自嫌身未老，已有住山心。"]'),
('4ef417d1-417b-4d98-bd85-fb783ca7165a','送僧歸漳州','呂溫','唐','唐诗','tang','','[]','幾夏京城住，今朝獨遠歸。',48,'全唐诗/poet.tang.19000.json','["幾夏京城住，今朝獨遠歸。", "修行四分律，護淨七條衣。", "溪寺黃橙熟，沙田紫芋肥。", "九龍潭上路，同去客應稀。"]'),
('a9d3bfca-8402-4946-ad02-53db1964a3b2','列女操','孟郊','唐','唐诗','tang','','["\u8d5e\u9882", "\u5987\u5973", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c"]','梧桐相待老，鴛鴦會雙死。',36,'全唐诗/poet.tang.19000.json','["梧桐相待老，鴛鴦會雙死。", "貞女貴狥夫，捨生亦如此。", "波瀾誓不起，妾心井中水。"]'),
('20c08319-13a8-4ba6-869c-3a846e5fbf14','灞上輕薄行','孟郊','唐','唐诗','tang','','[]','長安無緩步，況值天景莫。',60,'全唐诗/poet.tang.19000.json','["長安無緩步，況值天景莫。", "相逢灞滻間，親戚不相顧。", "自歎方拙身，忽隨輕薄倫。", "常恐失所避，化爲車轍塵。", "此中生白髮，疾走亦未歇。"]'),
('34cfc639-9d8b-45f1-9804-c8b07819bfe4','長安羈旅行','孟郊','唐','唐诗','tang','','[]','十日一理髮，每梳飛旅塵。',96,'全唐诗/poet.tang.19000.json','["十日一理髮，每梳飛旅塵。", "三旬九過飲，每食唯舊貧。", "萬物皆及時，獨余不覺春。", "失名誰肯訪，得意爭相親。", "直木有恬翼，靜流無躁鱗。", "始知喧競場，莫處君子身。", "野策藤竹輕，山蔬薇蕨新。", "潛歌歸去來，事外風景真。"]'),
('c71ae2ee-cd4f-4d85-8447-e3b52a3aa33d','長安道','孟郊','唐','唐诗','tang','','[]','胡風激秦樹，賤子風中泣。',48,'全唐诗/poet.tang.19000.json','["胡風激秦樹，賤子風中泣。", "家家朱門開，得見不可入。", "長安十二衢，投樹鳥亦急。", "高閣何人家，笙簧正喧吸。"]'),
('5ba83042-7622-4259-8226-99757df8826c','送遠吟','孟郊','唐','唐诗','tang','','[]','河水昏復晨，河邊相送頻。',48,'全唐诗/poet.tang.19000.json','["河水昏復晨，河邊相送頻。", "離杯有淚飲，別柳無枝春。", "一笑忽然歛，萬愁俄已新。", "東波與西日，不惜遠行人。"]'),
('c858a566-2503-4249-8f55-e22a7c9b12bd','古薄命妾','孟郊','唐','唐诗','tang','','[]','不惜十指絃，爲君千萬彈。',72,'全唐诗/poet.tang.19000.json','["不惜十指絃，爲君千萬彈。", "常恐新聲至，坐使故聲殘。", "棄置今日悲，即是昨日歡。", "將新變故易，持故爲新難。", "青山有蘼蕪，淚葉長不乾。", "空令後代人，采掇幽思攢。"]'),
('362aca58-b9d3-42ac-b082-eb9ce3544363','古離別','孟郊','唐','唐诗','tang','','[]','松山雲繚繞，萍路水分離。',48,'全唐诗/poet.tang.19000.json','["松山雲繚繞，萍路水分離。", "雲去有歸日，水分無合時。", "春芳役雙眼，春色柔四支。", "楊柳織別愁，千條萬條絲。"]'),
('757d9f4d-b8a5-4ed9-97e8-d8ee6740f932','雜怨 一','孟郊','唐','唐诗','tang','','[]','憶人莫至悲，至悲空自衰。',48,'全唐诗/poet.tang.19000.json','["憶人莫至悲，至悲空自衰。", "寄人莫剪衣，剪衣未必歸。", "朝爲雙蒂花，莫爲四散飛。", "花落還遶樹，遊子不顧期。"]'),
('6660d6da-6ce6-4062-b07f-1cc957aac84f','雜怨 二','孟郊','唐','唐诗','tang','','[]','夭桃花清晨，遊女紅粉新。',48,'全唐诗/poet.tang.19000.json','["夭桃花清晨，遊女紅粉新。", "夭桃花薄暮，遊女紅粉故。", "樹有百年花，人無一定顏。", "花送人老盡，人悲花自閑。"]'),
('67e8cc8d-6684-41a2-8754-4bbdb9753731','雜怨 三','孟郊','唐','唐诗','tang','','[]','貧女鏡不明，寒花日少容。',60,'全唐诗/poet.tang.19000.json','["貧女鏡不明，寒花日少容。", "暗蛩有虛織，短線無長縫。", "浪水不可照，狂夫不可從。", "浪水多散影，狂夫多異蹤。", "持此一生薄，空城萬恨濃。"]'),
('26387e92-800d-4dcb-966c-8675b51c9a70','靜女吟','孟郊','唐','唐诗','tang','','[]','豔女皆妬色，靜女獨檢蹤。',48,'全唐诗/poet.tang.19000.json','["豔女皆妬色，靜女獨檢蹤。", "任禮恥任粧，嫁德不嫁容。", "君子易求聘，小人難自從。", "此志誰與諒，琴弦幽韻重。"]'),
('16e3b4be-1631-43ce-b3a1-fdd9dc1a7719','歸信吟','孟郊','唐','唐诗','tang','','[]','淚墨灑爲書，將寄萬里親。',24,'全唐诗/poet.tang.19000.json','["淚墨灑爲書，將寄萬里親。", "書去魂亦去，兀然空一身。"]'),
('44579c97-44b2-4be3-95a4-a86f4f0ab919','山老吟','孟郊','唐','唐诗','tang','','[]','不行山下地，唯種山上田。',48,'全唐诗/poet.tang.19000.json','["不行山下地，唯種山上田。", "腰斧斫旅松，手飄汲家泉。", "詎知文字力，莫記日月遷。", "蟠木爲我身，始得全天年。"]'),
('4cf19354-4c0a-4e55-980b-69fa7f81ed0f','遊子吟','孟郊','唐','唐诗','tang','','["\u6742\u66f2\u6b4c\u8f9e", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u6bcd\u7231", "\u4e09\u5e74\u7ea7\u4e0b\u518c", "\u8d5e\u9882"]','慈母手中線，遊子身上衣。',36,'全唐诗/poet.tang.19000.json','["慈母手中線，遊子身上衣。", "臨行密密縫，意恐遲遲歸。", "誰言寸草心，報得三春暉。"]'),
('26c288f1-a266-4aa3-8570-56f6461df827','小隱吟','孟郊','唐','唐诗','tang','','[]','我飲不在醉，我歡長寂然。',48,'全唐诗/poet.tang.19000.json','["我飲不在醉，我歡長寂然。", "酌溪四五盞，聽彈兩三弦。", "鍊性靜棲白，洗情深寄玄。", "號怒路傍子，貪敗不貪全。"]'),
('5d6bff07-e320-4040-951f-9ce4a24ba27a','苦寒吟','孟郊','唐','唐诗','tang','','[]','天寒色青蒼，北風呌枯桑。',48,'全唐诗/poet.tang.19000.json','["天寒色青蒼，北風呌枯桑。", "厚冰無裂文，短日有冷光。", "敲石不得火，壯陰奪正陽。", "苦調竟何言，凍吟成此章。"]'),
('88b1cabe-1b5d-463f-a67b-9ffc2a897391','猛將吟','孟郊','唐','唐诗','tang','','[]','擬膾樓蘭肉，蓄怒時未揚。',48,'全唐诗/poet.tang.19000.json','["擬膾樓蘭肉，蓄怒時未揚。", "秋鼙無退聲，夜劍不隱光。", "虎隊手驅出，豹篇心卷藏。", "古今皆有言，猛將出北方。"]'),
('a1f46e3a-7479-4a58-8af2-38725960a2f1','傷哉行','孟郊','唐','唐诗','tang','','[]','衆毒蔓貞松，一枝難久榮。',72,'全唐诗/poet.tang.19000.json','["衆毒蔓貞松，一枝難久榮。", "豈知黃庭客，仙骨生不成。", "春色捨芳蕙，秋風遶枯莖。", "彈琴不成曲，始覺知音傾。", "館月改舊照，弔賓寫餘情。", "還舟空江上，波浪送銘旌。"]'),
('bf16dec6-a78d-48d3-805e-8c4cd378df40','怨詩','孟郊','唐','唐诗','tang','','[]','試妾與君淚，兩處滴池水。',24,'全唐诗/poet.tang.19000.json','["試妾與君淚，兩處滴池水。", "看取芙蓉花，今年爲誰死。"]'),
('9749d483-61a2-4d10-a13e-4b9864170fe4','湘弦怨','孟郊','唐','唐诗','tang','','[]','昧者理芳草，蒿蘭同一鋤。',96,'全唐诗/poet.tang.19000.json','["昧者理芳草，蒿蘭同一鋤。", "狂飆怒秋林，曲直同一枯。", "嘉木忌深蠹，哲人悲巧誣。", "靈均入迴流，靳尚爲良謨。", "我願分衆泉，清濁各異渠。", "我願分衆巢，梟鸞相遠居。", "此志諒難保，此情竟何如。", "湘弦少知音，孤響空踟蹰。"]'),
('5341c76a-98e0-470e-9edf-8d4b186cb894','楚竹吟酬盧虔端公見和湘弦怨','孟郊','唐','唐诗','tang','','[]','握中有新聲，楚竹人未聞。',96,'全唐诗/poet.tang.19000.json','["握中有新聲，楚竹人未聞。", "識音者謂誰，清夜吹贈君。", "昔爲瀟湘引，曾動瀟湘雲。", "一呌鳳改聽，再驚鶴失羣。", "江花匪秋落，山日當晝曛。", "衆濁響雜沓，孤清思氛氳。", "欲知怨有形，願向明月分。", "一掬靈均淚，千年湘水文。"]'),
('5cb01d76-da0c-4563-840d-1b3e6b93a4c3','遠愁曲','孟郊','唐','唐诗','tang','','[]','飄颻何所從，遺塚行未逢。',72,'全唐诗/poet.tang.19000.json','["飄颻何所從，遺塚行未逢。", "東西不見人，哭向青青松。", "此地有時盡，此哀無處容。", "聲翻太白雲，淚洗藍田峰。", "水涉七八曲，山登千萬重。", "願邀玄夜月，出視白日蹤。"]'),
('651924eb-4e38-45ea-bc5c-1a7b46d7cc1c','貧女詞寄從叔先輩簡','孟郊','唐','唐诗','tang','','[]','蠶女非不勤，今年獨無春。',60,'全唐诗/poet.tang.19000.json','["蠶女非不勤，今年獨無春。", "二月冰雪深，死盡萬木身。", "時令自逆行，造化豈不仁。", "仰企碧霞仙，高控滄海雲。", "永別勞苦場，飄颻遊無垠。"]'),
('49481e55-7419-44d9-8f13-d7a0ff906cb5','邊城吟','孟郊','唐','唐诗','tang','','[]','西城近日天，俗稟氣候偏。',48,'全唐诗/poet.tang.19000.json','["西城近日天，俗稟氣候偏。", "行子獨自渴，主人仍賣泉。", "燒烽碧雲外，牧馬青坡巔。", "何處鶻突夢，歸思寄仰眠。"]'),
('180b0392-df28-41e4-9169-27088a3cb818','新平歌送許問','孟郊','唐','唐诗','tang','','[]','邊柳三四尺，暮春離別歌。',36,'全唐诗/poet.tang.19000.json','["邊柳三四尺，暮春離別歌。", "早迴儒士駕，莫飲土番河。", "誰識匣中寶，楚雲章句多。"]'),
('9c08395d-8811-4dcd-aa96-3328a9cb2e90','殺氣不在邊','孟郊','唐','唐诗','tang','','[]','殺氣不在邊，凜然中國秋。',132,'全唐诗/poet.tang.19000.json','["殺氣不在邊，凜然中國秋。", "道險不在山，平地有摧輈。", "河南又起兵，清濁俱鎖流。", "豈唯私客艱，擁滯官行舟。", "況余隔晨昏，去家成阻修。", "忽然兩鬢雪，同是一日愁。", "獨寢夜難曉，起視星漢浮。", "涼風蕩天地，日夕聲颼飗。", "萬物無少色，兆人皆老憂。", "長策苟未立，丈夫誠可羞。", "靈響復何事，劍鳴思戮讐。"]'),
('6bda9fec-8249-4fcf-9fe9-aa5894e54755','結愛','孟郊','唐','唐诗','tang','','[]','心心復心心，結愛務在深。',60,'全唐诗/poet.tang.19000.json','["心心復心心，結愛務在深。", "一度欲離別，千迴結衣襟。", "結妾獨守志，結君早歸意。", "始知結衣裳，不如結心腸。", "坐結行亦結，結盡百年月。"]'),
('667e27c0-8648-4a7c-b763-15f360873077','弦歌行','孟郊','唐','唐诗','tang','','[]','驅儺擊鼓吹長笛，瘦鬼染面惟齒白。',50,'全唐诗/poet.tang.19000.json','["驅儺擊鼓吹長笛，瘦鬼染面惟齒白。", "暗中崒崒拽茅鞭，倮足朱[褌]行戚戚。", "相顧笑聲衝庭燎，桃弧射矢時獨呌。"]'),
('456ed339-7a31-4b5e-a1f0-caced6424dd3','覆巢行','孟郊','唐','唐诗','tang','','[]','荒城古木枝多枯，飛禽嗷嗷朝哺雛。',96,'全唐诗/poet.tang.19000.json','["荒城古木枝多枯，飛禽嗷嗷朝哺雛。", "枝傾巢覆雛墜地，烏鳶下啄更相呼。", "陽和發生均孕育，鳥獸有情知不足。", "枝危巢小風雨多，未容長成已先覆。", "靈枝珍木滿上林，鳳巢阿閣重且深。", "爾今所托非本地，烏鳶何得同爾心。"]'),
('bc6ae174-dfab-465f-93a2-5c7ead5126ce','出門行 一','孟郊','唐','唐诗','tang','','[]','長河悠悠去無極，百齡同此可歎息。',80,'全唐诗/poet.tang.19000.json','["長河悠悠去無極，百齡同此可歎息。", "秋風白露霑人衣，壯心凋落奪顏色。", "少年出門將訴誰，川無梁兮路無岐。", "一聞陌上苦寒奏，使我佇立驚且悲。", "君今得意厭粱肉，豈復念我貧賤時。"]'),
('bc9cf356-e947-48f9-93cb-db2222f41fb7','出門行 二','孟郊','唐','唐诗','tang','','[]','海風蕭蕭天雨霜，窮愁獨坐夜何長。',96,'全唐诗/poet.tang.19000.json','["海風蕭蕭天雨霜，窮愁獨坐夜何長。", "驅車舊憶太行險，始知遊子悲故鄉。", "美人相思隔天闕，長望雲端不可越。", "手持琅玕欲有贈，愛而不見心斷絕。", "南山峩峩白石爛，碧海之波浩漫漫。", "參辰出沒不相待，我欲橫天無羽翰。"]'),
('1f9c9bcf-7163-4eff-b528-31fd81683a23','湘妃怨','孟郊','唐','唐诗','tang','','[]','南巡竟不返，二妃怨逾積。',72,'全唐诗/poet.tang.19000.json','["南巡竟不返，二妃怨逾積。", "萬里喪蛾眉，瀟湘水空碧。", "冥冥荒山下，古廟收貞魄。", "喬木深青春，清光滿瑤席。", "搴芳徒有薦，靈意殊脉脉。", "玉佩不可親，徘徊煙波夕。"]'),
('22081f36-db4c-49e7-a108-303e34dba425','巫山曲','孟郊','唐','唐诗','tang','','["\u5199\u5c71", "\u4f20\u8bf4", "\u5199\u666f", "\u63cf\u5199\u5c71"]','巴江上峽重復重，陽臺碧峭十二峰。',64,'全唐诗/poet.tang.19000.json','["巴江上峽重復重，陽臺碧峭十二峰。", "荆王獵時逢暮雨，夜臥高丘夢神女。", "輕紅流煙濕豔姿，行雲飛去明星稀。", "目極魂斷望不見，猿啼三聲淚滴衣。"]'),
('f644e100-c6e9-416c-9586-303a242585ee','巫山高','孟郊','唐','唐诗','tang','','[]','見盡數萬里，不聞三聲猿。',48,'全唐诗/poet.tang.19000.json','["見盡數萬里，不聞三聲猿。", "但飛蕭蕭雨，中有亭亭魂。", "千載楚王恨，遺文宋玉言。", "至今晴明天，雲結深閨門。"]'),
('538c200b-49c5-4487-8087-9736b2947053','楚怨','孟郊','唐','唐诗','tang','','[]','秋入楚江水，獨照汨羅魂。',36,'全唐诗/poet.tang.19000.json','["秋入楚江水，獨照汨羅魂。", "手把綠荷泣，意愁珠淚翻。", "九門不可入，一犬吠千門。"]'),
('529cccc6-76a7-4205-aa70-a6f66772187f','塘下行','孟郊','唐','唐诗','tang','','[]','塘邊日欲斜，年少早還家。',36,'全唐诗/poet.tang.19000.json','["塘邊日欲斜，年少早還家。", "徒將白羽扇，調妾木蘭花。", "不是城頭樹，那棲來去鴉。"]'),
('953d2114-3444-4345-81bb-5b8271c4a90a','臨池曲','孟郊','唐','唐诗','tang','','[]','池中春蒲葉如帶，紫菱成角蓮子大。',32,'全唐诗/poet.tang.19000.json','["池中春蒲葉如帶，紫菱成角蓮子大。", "羅裙蟬鬢倚迎風，雙雙伯勞飛向東。"]'),
('696de506-98cf-40a0-849c-b33338970bea','車遙遙','孟郊','唐','唐诗','tang','','[]','路喜到江盡，江上又通舟。',96,'全唐诗/poet.tang.19000.json','["路喜到江盡，江上又通舟。", "舟車兩無阻，何處不得遊。", "丈夫四方志，女子安可留。", "郎自別日言，無令生遠愁。", "旅雁忽呌月，斷猿寒啼秋。", "此夕夢君夢，君在百城樓。", "寄淚無因波，寄恨無因輈。", "願爲馭者手，與郎迴馬頭。"]'),
('3eee4c43-b44b-4867-9042-0fed63140b87','征婦怨 一','孟郊','唐','唐诗','tang','','[]','良人昨日去，明月又不圓。',60,'全唐诗/poet.tang.19000.json','["良人昨日去，明月又不圓。", "別時各有淚，零落青樓前。", "君淚濡羅巾，妾淚滿路塵。", "羅巾長在手，今得隨妾身。", "路塵如得風，得上君車輪。"]'),
('56eb92ab-9e51-4834-8023-8222cde175c3','征婦怨 二','孟郊','唐','唐诗','tang','','[]','漁陽千里道，近如中門限。',48,'全唐诗/poet.tang.19000.json','["漁陽千里道，近如中門限。", "中門踰有時，漁陽長在眼。", "生在綠羅下，不識漁陽道。", "良人自戍來，夜夜夢中到。"]'),
('c4cbde46-e465-4d07-a44b-428e980f5341','空城雀','孟郊','唐','唐诗','tang','','[]','一雀入官倉，所食寧損幾。',48,'全唐诗/poet.tang.19000.json','["一雀入官倉，所食寧損幾。", "祗慮往覆頻，官倉終害爾。", "魚網不在天，鳥羅不張水。", "飲啄要自然，可以空城裏。"]'),
('26ca7601-8922-46a3-8104-b2b982afa8bb','閑怨','孟郊','唐','唐诗','tang','','[]','妾恨比斑竹，下盤煩冤根。',24,'全唐诗/poet.tang.19000.json','["妾恨比斑竹，下盤煩冤根。", "有筍未出土，中已含淚痕。"]'),
('a6844edc-20ad-4dbc-913f-0e8b4e474c18','羽林行','孟郊','唐','唐诗','tang','','["\u9ec4\u6cb3"]','朔雪寒斷指，朔風勁裂冰。',48,'全唐诗/poet.tang.19000.json','["朔雪寒斷指，朔風勁裂冰。", "胡中射鵰者，此日猶不能。", "翩翩羽林兒，錦臂飛蒼鷹。", "揮鞭快白馬，走出黃河凌。"]'),
('7175c86c-5225-4405-a542-0a41be737c43','古意','孟郊','唐','唐诗','tang','','[]','河邊織女星，河畔牽牛郎。',24,'全唐诗/poet.tang.19000.json','["河邊織女星，河畔牽牛郎。", "未得渡清淺，相對遙相望。"]'),
('f2565c5f-57c5-4e9e-bef1-56d864b52158','古別離','孟郊','唐','唐诗','tang','','["\u9001\u522b", "\u5973\u5b50", "\u60c5\u90ce"]','欲別牽郎衣，郎今到何處。',24,'全唐诗/poet.tang.19000.json','["欲別牽郎衣，郎今到何處。", "不恨歸來遲，莫向臨邛去。"]'),
('03b75928-cca2-41a0-9900-7db63c882850','遊俠行','孟郊','唐','唐诗','tang','','[]','壯士性剛決，火中見石裂。',48,'全唐诗/poet.tang.19000.json','["壯士性剛決，火中見石裂。", "殺人不迴頭，輕生如蹔別。", "豈知眼有淚，肯白頭上髮。", "半生無恩酬，劍閑一百月。"]'),
('0c8b7f84-4642-4a4c-9700-f56fbc9fbf81','黃雀吟','孟郊','唐','唐诗','tang','','[]','黃雀舞承塵，倚恃主人仁。',72,'全唐诗/poet.tang.19000.json','["黃雀舞承塵，倚恃主人仁。", "主人忽不仁，買彈彈爾身。", "何不遠飛去，蓬蒿正繁新。", "蒿粒無人爭，食之足爲珍。", "莫覰翻車粟，覰翻罪有因。", "黃雀不知言，贈之徒慇懃。"]'),
('1c9a5943-91ce-4186-a6da-d866239bcbc7','有所思','孟郊','唐','唐诗','tang','','[]','桔槔烽火晝不滅，客路迢迢信難越。',48,'全唐诗/poet.tang.19000.json','["桔槔烽火晝不滅，客路迢迢信難越。", "古鎮刀攢萬片霜，寒江浪起千堆雪。", "此時西去定如何，空使南心遠淒切。"]'),
('0e9443e4-6654-4e55-bca6-be13ccfcd2dd','求仙曲','孟郊','唐','唐诗','tang','','[]','仙教生爲門，仙宗靜爲根。',48,'全唐诗/poet.tang.19000.json','["仙教生爲門，仙宗靜爲根。", "持心若妄求，服食安足論。", "鏟惑有靈藥，餌真成本源。", "自當出塵網，馭鳳登崑崙。"]'),
('956dbc93-60a2-4ec0-8a1b-21e8755eb0e5','嬋娟篇','孟郊','唐','唐诗','tang','','[]','花嬋娟，泛春泉。',64,'全唐诗/poet.tang.19000.json','["花嬋娟，泛春泉。", "竹嬋娟，籠曉煙。", "妓嬋娟，不長妍。", "月嬋娟，真可憐。", "夜半姮娥朝太一，人間本自無靈匹。", "漢宮承寵不多時，飛燕婕妤相妬嫉。"]'),
('398f7bd3-e4bc-44ae-9db4-b36240fb65a2','南浦篇','孟郊','唐','唐诗','tang','','[]','南浦桃花亞水紅，水邊柳絮由春風。',48,'全唐诗/poet.tang.19000.json','["南浦桃花亞水紅，水邊柳絮由春風。", "鳥鳴喈喈煙濛濛，自從遠送對悲翁。", "此翁已與少年別，唯憶深山深谷中。"]'),
('baa11fc0-5176-4ca0-9558-635c02ba581d','清東曲','孟郊','唐','唐诗','tang','','[]','櫻桃花參差，香雨紅霏霏。',60,'全唐诗/poet.tang.19000.json','["櫻桃花參差，香雨紅霏霏。", "含笑競攀折，美人濕羅衣。", "采采清東曲，明眸豔圭玉。", "青巾艑上郎，上下看不足。", "南陽公首詞，編入新樂錄。"]'),
('549feb1a-842e-488c-ba57-51fe7a55c8e8','望遠曲','孟郊','唐','唐诗','tang','','[]','朝朝候歸信，日日登高臺。',68,'全唐诗/poet.tang.19000.json','["朝朝候歸信，日日登高臺。", "行人未去植庭梅，別來三見庭花開。", "庭花開盡復幾時，春光駘蕩阻佳期。", "愁來望遠煙塵隔，空憐綠鬢風吹白，何當歸見遠行客。"]'),
('169ed652-8bdb-4083-9d22-642d563b58fd','織婦辭','孟郊','唐','唐诗','tang','','[]','夫是田中郎，妾是田中女。',60,'全唐诗/poet.tang.19000.json','["夫是田中郎，妾是田中女。", "當年嫁得君，爲君秉機杼。", "筋力日已疲，不息窻下機。", "如何織紈素，自著藍縷衣。", "官家牓村路，更索栽桑樹。"]'),
('39218922-06e9-4338-8bf5-59101a45b1a6','古意','孟郊','唐','唐诗','tang','','[]','蕩子守邊戍，佳人莫相從。',204,'全唐诗/poet.tang.19000.json','["蕩子守邊戍，佳人莫相從。", "去來年月多，苦愁改形容。", "上山復下山，踏草成古蹤。", "徒言采蘼蕪，十度一不逢。", "鑒獨是明月，識志唯寒松。", "井桃始開花，一見悲萬重。", "人顏不再春，桃色有再濃。", "捐氣入空房，無憀乍從容。", "啓貼理針線，非獨學裁縫。", "手持未染綵，繡爲白芙蓉。", "芙蓉無染污，將以表心素。", "欲寄未歸人，當春無信去。", "無信反增愁，愁心緣隴頭。", "願君如隴水，冰鏡水還流。", "宛宛青絲線，纖纖白玉鉤。", "玉鉤不虧缺，青絲無斷絕。", "迴還勝雙手，解盡心中結。"]'),
('a33eb418-ca0d-44d6-91e0-d9833c805c5a','折楊柳 一','孟郊','唐','唐诗','tang','','[]','楊柳多短枝，短枝多別離。',72,'全唐诗/poet.tang.19000.json','["楊柳多短枝，短枝多別離。", "贈遠屢攀折，柔條安得垂。", "青春有定節，離別無定時。", "但恐人別促，不怨來遲遲。", "莫言短枝條，中有長相思。", "朱顏與綠楊，併在別離期。"]'),
('7ccecc3e-cf75-4766-8bbe-c499eb15c518','折楊柳 二','孟郊','唐','唐诗','tang','','[]','樓上春風過，風前楊柳歌。',48,'全唐诗/poet.tang.19000.json','["樓上春風過，風前楊柳歌。", "枝疎緣別苦，曲怨爲年多。", "花驚燕地雲，葉映楚池波。", "誰堪別離此，征戍在交河。"]'),
('b415633c-4f43-46e2-b062-6aab6d38aac0','和丁助教塞上吟','孟郊','唐','唐诗','tang','','[]','哭雪復吟雪，廣文丁夫子。',48,'全唐诗/poet.tang.19000.json','["哭雪復吟雪，廣文丁夫子。", "江南萬里寒，曾未及如此。", "整頓氣候誰，言從生靈始。", "無令惻隱者，哀哀不能已。"]'),
('d0251203-99b4-4dcb-adab-30ba1de7725c','古怨別','孟郊','唐','唐诗','tang','','["\u79cb\u5929", "\u79bb\u522b", "\u7231\u60c5"]','颯颯秋風生，愁人怨離別。',48,'全唐诗/poet.tang.19000.json','["颯颯秋風生，愁人怨離別。", "含情兩相向，欲語氣先咽。", "心曲千萬端，悲來却難說。", "別後唯所思，天涯共明月。"]'),
('55abc3aa-bcab-467d-81cf-c97b3cca108e','古別曲','孟郊','唐','唐诗','tang','','[]','山川古今路，縱橫無斷絕。',96,'全唐诗/poet.tang.19000.json','["山川古今路，縱橫無斷絕。", "來往天地間，人皆有離別。", "行衣未束帶，中腸已先結。", "不用看鏡中，自知生白髮。", "欲陳去留意，聲向言前咽。", "愁結填心胸，茫茫若爲說。", "荒郊煙莽蒼，曠野風淒切。", "處處得相隨，人那不如月。"]'),
('06b2953a-743b-4980-9866-a3fedcc80371','戲贈陸大夫十二丈 一','孟郊','唐','唐诗','tang','','[]','蓮子不可得，荷花生水中。',24,'全唐诗/poet.tang.19000.json','["蓮子不可得，荷花生水中。", "猶勝道傍柳，無事蕩春風。"]'),
('ec19ed84-ec10-4e36-8b5b-3c5c3ea26131','戲贈陸大夫十二丈 二','孟郊','唐','唐诗','tang','','[]','淥萍與荷葉，同此一水中。',24,'全唐诗/poet.tang.19000.json','["淥萍與荷葉，同此一水中。", "風吹荷葉在，淥萍西復東。"]'),
('f11d37f2-5338-420c-b4f6-920c0a6cd026','戲贈陸大夫十二丈 三','孟郊','唐','唐诗','tang','','[]','蓮葉未開時，苦心終日卷。',24,'全唐诗/poet.tang.19000.json','["蓮葉未開時，苦心終日卷。", "春水徒蕩漾，荷花未開展。"]'),
('14bdc9b8-1bb4-4a87-8565-e189fe5899a3','勸善吟','孟郊','唐','唐诗','tang','','[]','瘦郭有志氣，相哀老龍鍾。',180,'全唐诗/poet.tang.19000.json','["瘦郭有志氣，相哀老龍鍾。", "勸我少吟詩，俗窄難爾容。", "一口百味別，況在醉會中。", "四座正當喧，片言何由通。", "顧余昧時調，居止多疎慵。", "見書眼始開，聞樂耳不聰。", "視聽互相隔，一身且莫同。", "天疾難自醫，詩癖將何攻。", "見君如見書，語善千萬重。", "自悲咄咄感，變作煩惱翁。", "煩惱不可欺，古劍澁亦雄。", "知君方少年，少年懷古風。", "藏書拄屋脊，不惜與凡聾。", "我願拜少年，師之學崇崇。", "從他笑爲矯，矯善亦可宗。"]'),
('fe77358b-f71f-4499-8f15-03ed4f8dfacb','望夫石','孟郊','唐','唐诗','tang','','[]','望夫石，夫不來兮江水碧。',28,'全唐诗/poet.tang.19000.json','["望夫石，夫不來兮江水碧。", "行人悠悠朝與莫，千年萬年色如故。"]'),
('41eb0dd0-d8bc-4925-9cfe-13743c64f145','寒江吟','孟郊','唐','唐诗','tang','','[]','冬至日光白，始知陰氣凝。',144,'全唐诗/poet.tang.19000.json','["冬至日光白，始知陰氣凝。", "寒江波浪凍，千里無平冰。", "飛鳥絕高羽，行人皆晏興。", "荻洲素浩渺，碕岸澌碐磳。", "煙舟忽自阻，風帆不相乘。", "何況異形體，信任爲股肱。", "涉江莫涉凌，得意須得朋。", "結交非賢良，誰免生愛憎。", "凍水有再浪，失飛有載騰。", "一言縱醜詞，萬響無善應。", "取鑒諒不遠，江水千萬層。", "何當春風吹，利涉吾道弘。"]'),
('a464fba3-0c39-4b24-bd39-3eeb3f6032e1','審交','孟郊','唐','唐诗','tang','','[]','種樹須擇地，惡土變木根。',72,'全唐诗/poet.tang.19000.json','["種樹須擇地，惡土變木根。", "結交若失人，中道生謗言。", "君子芳桂性，春榮冬更繁。", "小人槿花心，朝在夕不存。", "莫躡冬冰堅，中有潛浪翻。", "唯當金石交，可以賢達論。"]'),
('9f7c3bfb-2996-48a2-9d18-e485218881d4','怨別','孟郊','唐','唐诗','tang','','[]','一別一迴老，志士白髮早。',60,'全唐诗/poet.tang.19000.json','["一別一迴老，志士白髮早。", "在富易爲容，居貧難自好。", "沉憂損性靈，服藥亦枯槁。", "秋風遊子衣，落日行遠道。", "君問去何之，賤身難自保。"]'),
('831055d2-b22f-4489-8128-22baa957d506','百憂','孟郊','唐','唐诗','tang','','[]','萱草女兒花，不解壯士憂。',96,'全唐诗/poet.tang.19000.json','["萱草女兒花，不解壯士憂。", "壯士心是劍，爲君射斗牛。", "朝思除國讐，暮思除國讐。", "計盡山河畫，意窮草木籌。", "智士日千慮，愚夫唯四愁。", "何必在波濤，然後驚沈浮。", "伯倫心不醉，四皓迹難留。", "出處各有時，衆議徒啾啾。"]'),
('d8a8ab40-f615-44dd-9366-883aa1202a1c','路病','孟郊','唐','唐诗','tang','','[]','病客無主人，艱哉求臥難。',72,'全唐诗/poet.tang.19000.json','["病客無主人，艱哉求臥難。", "飛光赤道路，內火焦肺肝。", "欲飲井泉竭，欲醫囊用單。", "稚顏能幾日，壯志忽已殘。", "人子不言苦，歸書但云安。", "愁環在我腸，宛轉終無端。"]'),
('f68e3f49-bef0-48d1-8f02-9022aea3fc8a','衰松','孟郊','唐','唐诗','tang','','[]','近世交道衰，青松落顏色。',48,'全唐诗/poet.tang.19000.json','["近世交道衰，青松落顏色。", "人心忌孤直，木性隨改易。", "既摧棲日榦，未展擎天力。", "終是君子材，還思君子識。"]'),
('4a1c8111-6859-40b2-8a74-07089a737ab3','遣興','孟郊','唐','唐诗','tang','','[]','弦貞五條音，松直百尺心。',36,'全唐诗/poet.tang.19000.json','["弦貞五條音，松直百尺心。", "貞弦含古風，直松凌高岑。", "浮聲與狂葩，胡爲欲相侵。"]'),
('ec9e8b7c-cd3d-4cb8-92a2-8caa2ee7b1b4','退居','孟郊','唐','唐诗','tang','','[]','退身何所食，敗力不能閑。',48,'全唐诗/poet.tang.19000.json','["退身何所食，敗力不能閑。", "種稻耕白水，負薪斫青山。", "衆聽喜巴唱，獨醒愁楚顏。", "日莫靜歸時，幽幽扣松關。"]'),
('13bdc587-9348-4995-a30c-d2566bebab9c','臥病','孟郊','唐','唐诗','tang','','[]','貧病誠可羞，故牀無新裘。',60,'全唐诗/poet.tang.19000.json','["貧病誠可羞，故牀無新裘。", "春色燒肌膚，時餐苦咽喉。", "倦寢意蒙昧，強言聲幽柔。", "承顏自俛仰，有淚不敢流。", "默默寸心中，朝愁續莫愁。"]'),
('5c1e671b-34ec-431f-aab6-62b50a2c24b1','隱士','孟郊','唐','唐诗','tang','','[]','本末一相返，漂浮不還真。',156,'全唐诗/poet.tang.19000.json','["本末一相返，漂浮不還真。", "山野多餒士，市井無飢人。", "虎豹忌當道，麋鹿知藏身。", "奈何貪競者，日與患害親。", "顏貌歲歲改，利心朝朝新。", "孰知富生禍，取富不取貧。", "寶玉忌出璞，出璞先爲塵。", "松栢忌出山，出山先爲薪。", "君子隱石壁，道書爲我隣。", "寢興思其義，澹泊味始真。", "陶公自放歸，尚平去有依。", "草木擇地生，禽鳥順性飛。", "青青與冥冥，所保各不違。"]'),
('c22da4b9-fa17-4a74-af7b-cbe97bdfd84f','獨愁','孟郊','唐','唐诗','tang','','[]','前日遠別離，昨日生白髮。',36,'全唐诗/poet.tang.19000.json','["前日遠別離，昨日生白髮。", "欲知萬里情，曉臥半牀月。", "常恐百蟲鳴，使我芳草歇。"]'),
('1d54b5f8-e2c7-4aa6-8677-4d750b9203a2','春日有感','孟郊','唐','唐诗','tang','','[]','雨滴草芽出，一日長一日。',48,'全唐诗/poet.tang.19000.json','["雨滴草芽出，一日長一日。", "風吹柳線垂，一枝連一枝。", "獨有愁人顏，經春如等閑。", "且持酒滿杯，狂歌狂笑來。"]'),
('745593e7-f1c7-42d3-93b0-af3810d1f5a9','將見故人','孟郊','唐','唐诗','tang','','[]','故人季夏中，及此百餘日。',48,'全唐诗/poet.tang.19000.json','["故人季夏中，及此百餘日。", "無日不相思，明鏡改形色。", "寧知仲冬時，忽有相逢期。", "振衣起躑躅，頳鯉躍天池。"]'),
('a8b811e7-f77b-4661-8732-47f2cb612b1e','傷時','孟郊','唐','唐诗','tang','','[]','常聞貧賤士之常，嗟爾富者莫相笑。',128,'全唐诗/poet.tang.19000.json','["常聞貧賤士之常，嗟爾富者莫相笑。", "男兒得路即榮名，邂逅失途成不調。", "古人結交而重義，今人結交而重利。", "勸人一種種桃李，種亦直須遍天地。", "一生不愛囑人事，囑即直須爲生死。", "我亦不羨季倫富，我亦不笑原憲貧。", "有財有勢即相識，無財無勢同路人。", "因知世事皆如此，却向東溪臥白雲。"]'),
('0c27dc22-d5c6-4ca4-9e20-5a3039db9922','寓言','孟郊','唐','唐诗','tang','','[]','誰言碧山曲，不廢青松直。',48,'全唐诗/poet.tang.19000.json','["誰言碧山曲，不廢青松直。", "誰言濁水泥，不污明月色。", "我有松月心，俗騁風霜力。", "貞明既如此，摧折安可得。"]'),
('f5dc036b-4c4f-4ac7-9116-99f1ea05a617','偶作','孟郊','唐','唐诗','tang','','[]','利劍不可近，美人不可親。',48,'全唐诗/poet.tang.19000.json','["利劍不可近，美人不可親。", "利劍近傷手，美人近傷身。", "道險不在廣，十步能摧輪。", "情愛不在多，一夕能傷神。"]'),
('fb023af2-c8ba-4778-9a81-c9a9e617279f','勸學','孟郊','唐','唐诗','tang','','["\u52b1\u5fd7", "\u54f2\u7406", "\u8bfb\u4e66"]','擊石乃有火，不擊元無煙。',48,'全唐诗/poet.tang.19000.json','["擊石乃有火，不擊元無煙。", "人學始知道，不學非自然。", "萬事須己運，他得非我賢。", "青春須早爲，豈能長少年。"]'),
('ca59b1cf-1e8c-4f0d-94fb-45b2dd68739d','贈農人','孟郊','唐','唐诗','tang','','[]','勸爾勤耕田，盈爾倉中粟。',60,'全唐诗/poet.tang.19000.json','["勸爾勤耕田，盈爾倉中粟。", "勸爾伐桑株，減爾身上服。", "清霜一委地，萬草色不綠。", "狂飆一入林，萬葉不著木。", "青春如不耕，何以自結束。"]'),
('936c238e-950d-4f90-a8e6-fb7367fdba2d','長安早春','孟郊','唐','唐诗','tang','','[]','旭日朱樓光，東風不驚塵。',60,'全唐诗/poet.tang.19000.json','["旭日朱樓光，東風不驚塵。", "公子醉未起，美人爭探春。", "探春不爲桑，探春不爲麥。", "日日出西園，秖望花柳色。", "乃知田家春，不入五侯宅。"]'),
('a0880f82-c30e-41f1-906c-230706dfac96','罪松','孟郊','唐','唐诗','tang','','[]','雖爲青松姿，霜風何所宜。',120,'全唐诗/poet.tang.19000.json','["雖爲青松姿，霜風何所宜。", "二月天下樹，綠於青松枝。", "勿謂賢者喻，勿謂愚者規。", "伊呂代封爵，夷齊終身飢。", "彼曲既在斯，我正實在茲。", "涇流合渭流，清濁各自持。", "天令設四時，榮衰有常期。", "榮合隨時榮，衰合隨時衰。", "天令既不從，甚不敬天時。", "松乃不臣木，青青獨何爲。"]'),
('7d3366b9-8061-489c-ac39-b37c1c82e5d1','感興','孟郊','唐','唐诗','tang','','[]','拔心草不死，去根柳亦榮。',84,'全唐诗/poet.tang.19000.json','["拔心草不死，去根柳亦榮。", "獨有失意人，恍然無力行。", "昔爲連理枝，今爲斷絃聲。", "連理時所重，斷弦今所輕。", "吾欲進孤舟，三峽水不平。", "吾欲載車馬，太行路崢嶸。", "萬物根一氣，如何互相傾。"]'),
('cac5d9ee-11e9-4205-afa0-cbb86c5070f8','感懷 一','孟郊','唐','唐诗','tang','','[]','秋氣悲萬物，驚風振長道。',48,'全唐诗/poet.tang.19000.json','["秋氣悲萬物，驚風振長道。", "登高有所思，寒雨傷百草。", "平生有親愛，零落不相保。", "五情今已傷，安得自能老。"]'),
('1b2f5ed7-e0a6-44c3-9b91-1041b4314ed3','感懷 二','孟郊','唐','唐诗','tang','','[]','晨登洛陽坂，目極天茫茫。',84,'全唐诗/poet.tang.19000.json','["晨登洛陽坂，目極天茫茫。", "羣物歸大化，六龍頹西荒。", "豺狼日已多，草木日已霜。", "饑年無遺粟，衆鳥去空場。", "路傍誰家子，白首離故鄉。", "含酸望松栢，仰面訴穹蒼。", "去去勿復道，苦飢形貌傷。"]'),
('98170a6d-2d65-4819-9089-469d5e89f1cb','感懷 三','孟郊','唐','唐诗','tang','','[]','徘徊不能寐，耿耿含酸辛。',48,'全唐诗/poet.tang.19000.json','["徘徊不能寐，耿耿含酸辛。", "中夜登高樓，憶我舊星辰。", "四時互遷移，萬物何時春。", "唯憶首陽路，永謝當時人。"]'),
('ec46a618-9713-4d62-8042-677e9f8c9786','感懷 四','孟郊','唐','唐诗','tang','','[]','長安佳麗地，宮月生蛾眉。',84,'全唐诗/poet.tang.19000.json','["長安佳麗地，宮月生蛾眉。", "陰氣凝萬里，坐看芳草衰。", "玉堂有玄鳥，亦以從此辭。", "傷哉志士歎，故國多遲遲。", "深宮豈無樂，擾擾復何爲。", "朝見名與利，莫還生是非。", "姜牙佐周武，世業永巍巍。"]'),
('364d924b-b07a-465a-8d0a-fbc2e9bfa84d','感懷 五','孟郊','唐','唐诗','tang','','[]','舉才天道親，首陽誰采薇。',96,'全唐诗/poet.tang.19000.json','["舉才天道親，首陽誰采薇。", "去去荒澤遠，落日當西歸。", "羲和駐其輪，四海借餘暉。", "極目何蕭索，驚風正離披。", "鴟鴞鳴高樹，衆鳥相因依。", "東方有一士，歲莫常苦飢。", "主人數相問，脈脈今何爲。", "貧賤亦有樂，且願掩柴扉。"]'),
('4d7d2a89-fc55-4bf9-b7df-db11e4fcc8df','感懷 六','孟郊','唐','唐诗','tang','','[]','火雲流素月，三五何明明。',48,'全唐诗/poet.tang.19000.json','["火雲流素月，三五何明明。", "光曜侵白日，賢愚迷至精。", "四時更變化，天道有虧盈。", "常恐今已沒，須臾還復生。"]'),
('e854bca3-ff16-4d38-bab5-6d63ab0298c1','感懷 七','孟郊','唐','唐诗','tang','','[]','河梁莫相遇，草草不復言。',72,'全唐诗/poet.tang.19000.json','["河梁莫相遇，草草不復言。", "漢家正離亂，王粲別荆蠻。", "野澤何蕭條，悲風振空山。", "舉頭是星辰，念我何時還。", "親愛久別散，形神各離遷。", "未爲生死訣，長在心目間。"]'),
('104b68f1-3d11-470c-8b02-a824259a3f8e','感懷 八','孟郊','唐','唐诗','tang','','[]','有鳥東西來，哀鳴過我前。',24,'全唐诗/poet.tang.19000.json','["有鳥東西來，哀鳴過我前。", "願飛浮雲外，飲啄見青天。"]'),
('f6eaa832-4095-432e-9113-13c3b2a19a0e','達士','孟郊','唐','唐诗','tang','','[]','四時如逝水，百川皆東波。',60,'全唐诗/poet.tang.19000.json','["四時如逝水，百川皆東波。", "青春去不還，白髮鑷更多。", "達人識元化，變愁爲高歌。", "傾產取一醉，富者奈貧何。", "君看土中宅，富貴無偏頗。"]'),
('5825a752-9a37-43e9-8bc7-e7561e9fedc1','暮秋感思 一','孟郊','唐','唐诗','tang','','[]','西風吹垂楊，條條脆如藕。',48,'全唐诗/poet.tang.19000.json','["西風吹垂楊，條條脆如藕。", "上有噪日蟬，催人成皓首。", "亦恐旅步難，何獨朱顏醜。", "欲慰一時心，莫如千日酒。"]'),
('3165accd-aa7f-46b5-a207-375f38e5d4a5','暮秋感思 二','孟郊','唐','唐诗','tang','','[]','優哉遵渚鴻，自得養身旨。',38,'全唐诗/poet.tang.19000.json','["優哉遵渚鴻，自得養身旨。", "不[啄]太倉粟，不飲方塘水。", "振羽戛浮雲，罝羅任徒爾。"]'),
('ab79e040-791d-4435-b89e-7eecf2117656','古興','孟郊','唐','唐诗','tang','','[]','楚血未乾衣，荆虹尚埋輝。',24,'全唐诗/poet.tang.19000.json','["楚血未乾衣，荆虹尚埋輝。", "痛玉不痛身，抱璞求所歸。"]'),
('782d0d2e-385d-42f9-983d-af4d2f0a9289','勸友','孟郊','唐','唐诗','tang','','[]','至白涅不緇，至交淡不疑。',48,'全唐诗/poet.tang.19000.json','["至白涅不緇，至交淡不疑。", "人生靜躁殊，莫厭相箴規。", "膠漆武可接，金蘭文可思。", "堪嗟無心人，不如松栢枝。"]'),
('f5cfd1a9-4cdc-40a3-b199-b4327960228a','夷門雪贈主人','孟郊','唐','唐诗','tang','','[]','夷門貧士空吟雪，夷門豪士皆飲酒。',48,'全唐诗/poet.tang.19000.json','["夷門貧士空吟雪，夷門豪士皆飲酒。", "酒聲歡閑入雪銷，雪聲激切悲枯朽。", "悲歡不同歸去來，萬里春風動江柳。"]'),
('d61224bd-fb25-4b11-9f56-9ee465942123','堯歌 一','孟郊','唐','唐诗','tang','','[]','爾室何不安，爾孝無與齊。',84,'全唐诗/poet.tang.19000.json','["爾室何不安，爾孝無與齊。", "一言應對姑，一度爲出妻。", "往轍才晚鐘，還轍及晨雞。", "往還跡徒新，很戾竟獨迷。", "娥女無禮數，污家如糞泥。", "父母吞聲哭，禽鳥亦爲啼。", "如何天與惡，不得和鳴棲。"]'),
('b7f5a6e4-2017-439a-b828-227c077ac604','堯歌 二','孟郊','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','山色挽心肝，將歸盡日看。',72,'全唐诗/poet.tang.19000.json','["山色挽心肝，將歸盡日看。", "村肩籃轝子，野坐白髮官。", "鶯弄方短短，花明碎攢攢。", "瑠璃堆可掬，琴瑟饒多歡。", "翠韻仙窈窕，嵐漪出無端。", "養館洞庭秋，響答虛吹彈。"]'),
('8d87bfa1-d299-4686-9b4e-fc6818fb7fc1','亂離','孟郊','唐','唐诗','tang','','[]','天下無義劍，中原多瘡痍。',132,'全唐诗/poet.tang.19000.json','["天下無義劍，中原多瘡痍。", "哀哀陸大夫，正直神反欺。", "子路已成血，嵇康今尚嗤。", "爲君每一慟，如劍在四肢。", "折羽不復飛，逝水不復歸。", "直松摧高柯，弱蔓將何依。", "朝爲春日歡，夕爲秋日悲。", "淚下無尺寸，紛紛天雨絲。", "積怨成疾疹，積恨成狂癡。", "怨草豈有邊，恨水豈有涯。", "怨恨馳我心，茫茫日何之。"]'),
('62e815c1-cea7-41bf-988d-5f3c328705e6','勸酒','孟郊','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','白日無定影，清江無定波。',72,'全唐诗/poet.tang.19000.json','["白日無定影，清江無定波。", "人無百年壽，百年復如何。", "堂上陳美酒，堂下列清歌。", "勸君今曲巵，勿謂朱顏酡。", "松栢歲歲茂，丘陵日日多。", "君看終南山，千古青峨峨。"]'),
('cdf3d065-5de0-4928-88c8-35d79d7a99d6','去婦','孟郊','唐','唐诗','tang','','[]','君心匣中鏡，一破不復全。',60,'全唐诗/poet.tang.19000.json','["君心匣中鏡，一破不復全。", "妾心藕中絲，雖斷猶牽連。", "安知御輪士，今日翻回轅。", "一女事一夫，安可再移天。", "君聽去鶴言，哀哀七絲弦。"]'),
('55df7dee-65bb-4d53-925a-e8c081aec5ea','君子勿鬱鬱士有謗毀者作詩以贈之 一','孟郊','唐','唐诗','tang','','[]','君子勿鬱鬱，聽我青蠅歌。',96,'全唐诗/poet.tang.19000.json','["君子勿鬱鬱，聽我青蠅歌。", "人間少平地，森聳山嶽多。", "折輈不在道，覆舟不在河。", "須知一尺水，日夜增高波。", "叔孫毀仲尼，臧倉掩孟軻。", "蘭艾不同香，自然難爲和。", "良玉燒不熱，直竹文不頗。", "自古皆如此，其如道在何。"]'),
('0a73b9ea-451f-4987-b3e4-ec2e2f14b6ee','君子勿鬱鬱士有謗毀者作詩以贈之 二','孟郊','唐','唐诗','tang','','[]','日往復不見，秋堂莫仍學。',48,'全唐诗/poet.tang.19000.json','["日往復不見，秋堂莫仍學。", "玄髮不知白，曉入寒銅覺。", "爲林未離樹，有玉猶在璞。", "誰把碧梧枝，刻作雲門樂。"]'),
('655ee98b-833b-410f-a994-4e0212903c3a','聞砧','孟郊','唐','唐诗','tang','','[]','杜鵑聲不哀，斷猿啼不切。',48,'全唐诗/poet.tang.19000.json','["杜鵑聲不哀，斷猿啼不切。", "月下誰家砧，一聲腸一絕。", "杵聲不爲客，客聞髮自白。", "杵聲不爲衣，欲令遊子歸。"]'),
('82d09cba-94f5-40ba-9435-ec83e2c5ad89','遊子','孟郊','唐','唐诗','tang','','[]','萱草生堂堦，遊子行天涯。',24,'全唐诗/poet.tang.19000.json','["萱草生堂堦，遊子行天涯。", "慈親倚堂門，不見萱草花。"]'),
('51674759-a2c4-4523-a184-84c0a37b1191','自歎','孟郊','唐','唐诗','tang','','["\u9ec4\u6cb3"]','愁與髮相形，一愁白數莖。',96,'全唐诗/poet.tang.19000.json','["愁與髮相形，一愁白數莖。", "有髮能幾多，禁愁日日生。", "古若不置兵，天下無戰爭。", "古若不置名，道路無欹傾。", "太行聳巍峩，是天產不平。", "黃河奔濁浪，是天生不清。", "四蹄日日多，雙輪日日成。", "二物不在天，安能免營營。"]'),
('d5a7b4cd-f865-40c4-bc71-a4f7785e1215','求友','孟郊','唐','唐诗','tang','','[]','北風臨大海，堅冰臨河面。',60,'全唐诗/poet.tang.19000.json','["北風臨大海，堅冰臨河面。", "下有大波瀾，對之無由見。", "求友須在良，得良終相善。", "求友若非良，非良中道變。", "欲知求友心，先把黃金鍊。"]'),
('5871d156-c2f9-42ce-b80b-b8e4b5a3cfaf','投所知','孟郊','唐','唐诗','tang','','[]','苦心知苦節，不容一毛髮。',180,'全唐诗/poet.tang.19000.json','["苦心知苦節，不容一毛髮。", "鍊金索堅貞，洗玉求明潔。", "自慙所業微，功用如鳩拙。", "何殊嫫母顏，對彼寒塘月。", "君存古人心，道出古人轍。", "盡美固可揚，片善亦不遏。", "朝向公卿說，暮向公卿說。", "誰謂黃鍾管，化爲君子舌。", "一說清嶰竹，二說變嶰谷。", "三說四說時，寒花拆寒木。", "𣊪𣊪家道路，燦燦我衣服。", "豈直輝友朋，亦用慰骨肉。", "一暖荷匹素，一飽荷升粟。", "而況大恩恩，此身報得足。", "且將食檗勞，酬之作金刀。"]'),
('1ad9c073-5eb5-4821-aba0-81b4b3e31c21','病客吟','孟郊','唐','唐诗','tang','','[]','主人夜呻吟，皆入妻子心。',96,'全唐诗/poet.tang.19000.json','["主人夜呻吟，皆入妻子心。", "客子晝呻吟，徒爲蟲鳥音。", "妻子手中病，愁思不復深。", "童僕手中病，憂危獨難任。", "丈夫久飄泊，神氣自然沈。", "況於滯疾中，何人免噓𠾬。", "大海亦有涯，高山亦有岑。", "沈憂獨無極，塵淚互盈襟。"]'),
('f9c79a0d-5cf1-4ccc-8675-3f8c4929e3b5','感懷','孟郊','唐','唐诗','tang','','[]','孟冬陰氣交，兩河正屯兵。',120,'全唐诗/poet.tang.19000.json','["孟冬陰氣交，兩河正屯兵。", "煙塵相馳突，烽火日夜驚。", "太行險阻高，輓粟輸連營。", "奈何操弧者，不使梟巢傾。", "猶聞漢北兒，怙亂謀縱橫。", "擅搖干戈柄，呼呌豺狼聲。", "白日臨爾軀，胡爲喪丹誠。", "豈無感激士，以致天下平。", "登高望寒原，黃雲鬱崢嶸。", "坐馳悲風莫，歎息空沾纓。"]'),
('85bce622-6a9a-4e92-aed2-0e1e6f943833','離思','孟郊','唐','唐诗','tang','','[]','不寐亦不語，片月秋稍舉。',60,'全唐诗/poet.tang.19000.json','["不寐亦不語，片月秋稍舉。", "孤鴻憶霜羣，獨鶴叫雲侶。", "怨彼浮花心，飄飄無定所。", "高張繫繂帆，遠過梅根渚。", "迴織別離字，機聲有酸楚。"]'),
('0b24ccca-ca94-4dd4-bcb9-9abf39919666','結交','孟郊','唐','唐诗','tang','','[]','鑄鏡須青銅，青銅易磨拭。',48,'全唐诗/poet.tang.19000.json','["鑄鏡須青銅，青銅易磨拭。", "結交遠小人，小人難姑息。", "鑄鏡圖鑑微，結交圖相依。", "凡銅不可照，小人多是非。"]'),
('93f7031a-187e-4ed1-aae6-68c9bdfb8cda','傷春','孟郊','唐','唐诗','tang','','[]','兩河春草海水清，十年征戰城郭腥。',88,'全唐诗/poet.tang.19000.json','["兩河春草海水清，十年征戰城郭腥。", "亂兵殺兒將女去，二月三月花冥冥。", "千里無人旋風起，鶯啼燕語荒城裏。", "春色不揀墓傍株，紅顏皓色逐春去。", "春去春來那得知，今人看花古人墓，令人惆悵山頭路。"]'),
('b6089595-0726-4aed-81cb-1ec11d47d4e8','擇友','孟郊','唐','唐诗','tang','','[]','獸中有人性，形異遭人隔。',144,'全唐诗/poet.tang.19000.json','["獸中有人性，形異遭人隔。", "人中有獸心，幾人能真識。", "古人形似獸，皆有大聖德。", "今人表似人，獸心安可測。", "雖笑未必和，雖哭未必戚。", "面結口頭交，肚裏生荆棘。", "好人常直道，不順世間逆。", "惡人巧諂多，非義苟且得。", "若是傚真人，堅心如鐵石。", "不諂亦不欺，不奢復不溺。", "面無恡色容，心無詐憂惕。", "君子大道人，朝夕恒的的。"]'),
('3b688d99-3ac3-4a79-b123-e32ea870c318','夜憂','孟郊','唐','唐诗','tang','','[]','豈獨科斗死，所嗟文字捐。',48,'全唐诗/poet.tang.19000.json','["豈獨科斗死，所嗟文字捐。", "蒿蔓轉驕弄，菱荇減嬋娟。", "未遂擺鱗志，空思吹浪旋。", "何當再霖雨，洗濯生華鮮。"]'),
('faef1075-f344-4bf8-84d4-7947fe952241','惜苦','孟郊','唐','唐诗','tang','','[]','于鵠值諫議，以毬不能官。',84,'全唐诗/poet.tang.19000.json','["于鵠值諫議，以毬不能官。", "焦蒙值舍人，以盃不得完。", "可惜大雅旨，意此小團欒。", "名迴不敢辨，心轉實是難。", "不惜爲君轉，轉非君子觀。", "轉之復轉之，強轉誰能歡。", "哀哉虛轉言，不可窮波瀾。"]'),
('ad0a69ad-a067-4afd-9ec7-3d21741d00c2','寒地百姓吟','孟郊','唐','唐诗','tang','','[]','無火炙地眠，半夜皆立號。',96,'全唐诗/poet.tang.19000.json','["無火炙地眠，半夜皆立號。", "冷箭何處來，棘針風騷勞。", "霜吹破四壁，苦痛不可逃。", "高堂搥鐘飲，到曉聞烹炮。", "寒者願爲蛾，燒死彼華膏。", "華膏隔仙羅，虛遶千萬遭。", "到頭落地死，踏地爲遊遨。", "遊遨者是誰，君子爲鬱陶。"]'),
('8f564510-dac3-4b3c-a8cb-23811394dbd7','出東門','孟郊','唐','唐诗','tang','','[]','餓馬骨亦聳，獨驅出東門。',72,'全唐诗/poet.tang.19000.json','["餓馬骨亦聳，獨驅出東門。", "少年一日程，衰叟十日奔。", "寒景不我爲，疾走落平原。", "眇默荒草行，恐懼夜魄翻。", "一生自組織，千首大雅言。", "道路如抽蠶，宛轉羈腸繁。"]'),
('51a9182f-80d3-4619-aa44-8334185a9e0e','教坊歌兒','孟郊','唐','唐诗','tang','','[]','十歲小小兒，能歌得朝天。',60,'全唐诗/poet.tang.19000.json','["十歲小小兒，能歌得朝天。", "六十孤老人，能詩獨臨川。", "去年西京寺，衆伶集講筵。", "能嘶竹枝詞，供養繩牀禪。", "能詩不如歌，悵望三百篇。"]'),
('dd12c7fd-3627-416d-bb07-77d4ac2e82b3','訪疾','孟郊','唐','唐诗','tang','','[]','冷氣入瘡痛，夜來痛如何。',60,'全唐诗/poet.tang.19000.json','["冷氣入瘡痛，夜來痛如何。", "瘡從公怒生，豈以私恨多。", "公怒亦非道，怒消乃天和。", "古有煥輝句，嵇康閑婆娑。", "請君吟嘯之，正氣庶不訛。"]'),
('62cb6d0f-4361-4bb2-ad8b-fe8e11d39e58','酒德','孟郊','唐','唐诗','tang','','[]','酒是古明鏡，輾開小人心。',48,'全唐诗/poet.tang.19000.json','["酒是古明鏡，輾開小人心。", "醉見異舉止，醉聞異聲音。", "酒功如此多，酒屈亦以深。", "罪人免罪酒，如此可爲箴。"]'),
('958c1880-04c2-40bf-b77f-6222030e85b5','冬日','孟郊','唐','唐诗','tang','','[]','老人行人事，百一不及周。',84,'全唐诗/poet.tang.19000.json','["老人行人事，百一不及周。", "凍馬四蹄吃，陟卓難自收。", "短景仄飛過，午光不上頭。", "少壯日與輝，衰老日與愁。", "日愁疑在日，歲箭迸如讐。", "萬事有何味，一生虛自囚。", "不知文字利，到死空遨遊。"]'),
('b5b4681f-6ca6-455f-9eae-074ecf3fef67','飢雪吟','孟郊','唐','唐诗','tang','','[]','飢烏夜相啄，瘡聲互悲鳴。',108,'全唐诗/poet.tang.19000.json','["飢烏夜相啄，瘡聲互悲鳴。", "冰腸一直刀，天殺無曲情。", "大雪壓梧桐，折柴墮崢嶸。", "安知鸞鳳巢，不與梟鳶傾。", "下有幸災兒，拾遺多新爭。", "但求彼失所，但誇此經營。", "君子亦拾遺，拾遺非拾名。", "將補鸞鳳巢，免與梟鳶幷。", "因爲飢雪吟，至曉竟不平。"]'),
('deb11e19-f946-4df2-9b50-038a2ec6ba72','偷詩','孟郊','唐','唐诗','tang','','[]','餓犬齚枯骨，自喫饞飢涎。',84,'全唐诗/poet.tang.19000.json','["餓犬齚枯骨，自喫饞飢涎。", "今文與古文，各各稱可憐。", "亦如嬰兒食，餳桃口旋旋。", "唯有一點味，豈見逃景延。", "繩床獨坐翁，默覽有所傳。", "終當罷文字，別著逍遙篇。", "從來文字淨，君子不以賢。"]'),
('8d1608ae-c661-4995-865a-159167776333','晚雪吟','孟郊','唐','唐诗','tang','','[]','貧富喜雪晴，出門意皆饒。',180,'全唐诗/poet.tang.19000.json','["貧富喜雪晴，出門意皆饒。", "鏡海見纖悉，冰天步飄颻。", "一一仙子行，家家塵聲銷。", "小兒擊玉指，大耋歌聖朝。", "睿氣流不盡，瑞仙何敻寥。", "始知望幸色，終疑異禮招。", "市井亦清潔，閭閻聳岧嶤。", "蒼生願東顧，翠華仍西遙。", "天念豈薄厚，宸衷多憂焦。", "憂焦致太平，以茲時比堯。", "古耳有未通，新詞有潛韶。", "甘爲酒伶擯，坐恥歌女嬌。", "選音不易言，裁正逢今朝。", "今朝前古文，律異同一調。", "願於堯琯中，奏盡鬱抑謠。"]'),
('1352df99-cda2-4218-a0c7-7f4887e4170e','自惜','孟郊','唐','唐诗','tang','','[]','傾盡眼中力，抄詩過與人。',72,'全唐诗/poet.tang.19000.json','["傾盡眼中力，抄詩過與人。", "自悲風雅老，恐被巴竹嗔。", "零落雪文字，分明鏡精神。", "坐甘冰抱晚，永謝酒懷春。", "徒有言言舊，慙無默默新。", "始驚儒教誤，漸與佛乘親。"]'),
('e3979491-4de0-46d4-ba40-e2c19aa7c7e0','老恨','孟郊','唐','唐诗','tang','','[]','無子抄文字，老吟多飄零。',48,'全唐诗/poet.tang.19000.json','["無子抄文字，老吟多飄零。", "有時吐向床，枕席不解聽。", "鬬蟻甚微細，病聞亦清泠。", "小大不自識，自然天性靈。"]'),
('70612b14-8f6c-4d79-9b5b-9841e322cc61','湖州取解述情','孟郊','唐','唐诗','tang','','[]','霅水徒清深，照影不照心。',36,'全唐诗/poet.tang.19000.json','["霅水徒清深，照影不照心。", "白鶴未輕舉，衆鳥爭浮沉。", "因茲挂帆去，遂作歸山吟。"]'),
('02a6e727-d7c6-4403-84a5-07a505e08c4d','落第','孟郊','唐','唐诗','tang','','[]','曉月難爲光，愁人難爲腸。',48,'全唐诗/poet.tang.19000.json','["曉月難爲光，愁人難爲腸。", "誰言春物榮，獨見葉上霜。", "鵰鶚失勢病，鷦鷯假翼翔。", "棄置復棄置，情如刀劒傷。"]'),
('a1cfc5a5-e594-4021-a405-4d487fc62704','詠懷','孟郊','唐','唐诗','tang','','[]','濁水心易傾，明波興初發。',36,'全唐诗/poet.tang.19000.json','["濁水心易傾，明波興初發。", "思逢海底人，乞取蚌中月。", "此興若未諧，此心終不歇。"]'),
('f40069f7-9847-413e-b358-0e37dd459861','病起言懷','孟郊','唐','唐诗','tang','','[]','強行尋溪水，洗却殘病姿。',60,'全唐诗/poet.tang.19000.json','["強行尋溪水，洗却殘病姿。", "花景晼晚盡，麥風清泠吹。", "交道賤來見，世情貧去知。", "高閑思楚逸，澹泊厭齊兒。", "終伴碧山侶，結言青桂枝。"]'),
('73912850-b514-4b78-afbe-85e7985e75fa','秋夕貧居述懷','孟郊','唐','唐诗','tang','','[]','臥冷無遠夢，聽秋酸別情。',48,'全唐诗/poet.tang.19000.json','["臥冷無遠夢，聽秋酸別情。", "高枝低枝風，千葉萬葉聲。", "淺井不供飲，瘦田長廢耕。", "今交非古交，貧語聞皆輕。"]'),
('d4b68d9a-6a21-4e78-bedf-aea6f7fdc5ba','夜感自遣','孟郊','唐','唐诗','tang','','[]','夜學曉未休，苦吟神鬼愁。',48,'全唐诗/poet.tang.19000.json','["夜學曉未休，苦吟神鬼愁。", "如何不自閑，心與身爲讐。", "死辱片時痛，生辱長年羞。", "清桂無直枝，碧江思舊遊。"]'),
('f3da1c58-4969-4eca-880b-f97fd1b73610','再下第','孟郊','唐','唐诗','tang','','[]','一夕九起嗟，夢短不到家。',24,'全唐诗/poet.tang.19000.json','["一夕九起嗟，夢短不到家。", "兩度長安陌，空將淚見花。"]'),
('002d74c7-deb8-43f1-81c2-3236b0470efb','下第東歸留別長安知己','孟郊','唐','唐诗','tang','','[]','共照日月影，獨爲愁思人。',60,'全唐诗/poet.tang.19000.json','["共照日月影，獨爲愁思人。", "豈知鶗鴂鳴，瑤草不得春。", "一片兩片雲，千里萬里身。", "雲歸嵩之陽，身寄江之濱。", "棄置復何道，楚情吟白蘋。"]'),
('74bc6b81-19de-401e-b879-b20116cc322d','失意歸吳因寄東臺劉復侍御','孟郊','唐','唐诗','tang','','[]','自念西上身，忽隨東歸風。',60,'全唐诗/poet.tang.19000.json','["自念西上身，忽隨東歸風。", "長安日下影，又落江湖中。", "離婁豈不明，子野豈不聰。", "至寶非眼別，至音非耳通。", "因緘俗外詞，仰寄高天鴻。"]'),
('736fb247-b899-44dc-ac8d-cf72e83c8183','下第東南行','孟郊','唐','唐诗','tang','','[]','越風東南清，楚日瀟湘明。',60,'全唐诗/poet.tang.19000.json','["越風東南清，楚日瀟湘明。", "試逐伯鸞去，還作靈均行。", "江蘺伴我泣，海月投人驚。", "失意容貌改，畏途性命輕。", "時聞喪侶猿，一叫千愁幷。"]'),
('0882918a-8acc-4848-957b-44879401cd1d','歎命','孟郊','唐','唐诗','tang','','[]','三十年來命，唯藏一卦中。',60,'全唐诗/poet.tang.19000.json','["三十年來命，唯藏一卦中。", "題詩還問易，問易蒙復蒙。", "本望文字達，今因文字窮。", "影孤別離月，衣破道路風。", "歸去不自息，耕耘成楚農。"]'),
('2cff6882-c9e2-40f0-bd45-7511ed247381','遠遊','孟郊','唐','唐诗','tang','','[]','慈烏不遠飛，孝子念先歸。',96,'全唐诗/poet.tang.19000.json','["慈烏不遠飛，孝子念先歸。", "而我獨何事，四時心有違。", "江海戀空積，波濤信來稀。", "長爲路傍食，著盡家中衣。", "別劒不割物，離人難作威。", "遠行少僮僕，驅使無是非。", "爲性玩好盡，積愁心緒微。", "始知時節駛，夏日非長輝。"]'),
('690ded4d-3b16-4298-aa5a-1e8465591cdb','商州客舍','孟郊','唐','唐诗','tang','','[]','商山風雪壯，遊子衣裳單。',72,'全唐诗/poet.tang.19000.json','["商山風雪壯，遊子衣裳單。", "四望失道路，百憂攢肺肝。", "日短覺易老，夜長知至寒。", "淚流瀟湘弦，調苦屈宋彈。", "識聲今所易，識意古所難。", "聲意今詎辨，高明鑒其端。"]'),
('78101308-3a7d-4e45-a01d-05f4f99dde8b','長安旅情','孟郊','唐','唐诗','tang','','[]','盡說青雲路，有足皆可至。',48,'全唐诗/poet.tang.19000.json','["盡說青雲路，有足皆可至。", "我馬亦四蹄，出門似無地。", "玉京十二樓，峩峩倚青翠。", "下有千朱門，何門薦孤士。"]'),
('87c3d49b-183f-4e35-be4c-da80b625029a','長安羇旅','孟郊','唐','唐诗','tang','','[]','聽樂別離中，聲聲入幽腸。',36,'全唐诗/poet.tang.19000.json','["聽樂別離中，聲聲入幽腸。", "曉淚滴楚瑟，夜魄遶吳鄉。", "幾回羇旅情，夢覺殘燭光。"]'),
('66530050-5e78-4972-ac99-77c7b1c8cb07','渭上思歸','孟郊','唐','唐诗','tang','','[]','獨訪千里信，回臨千里河。',24,'全唐诗/poet.tang.19000.json','["獨訪千里信，回臨千里河。", "家在吳楚鄉，淚寄東南波。"]'),
('6e34d23e-7bcd-437b-8a3e-0a4bb1c2cda8','登科後','孟郊','唐','唐诗','tang','','[]','昔日齷齪不足誇，今朝放蕩思無涯。',32,'全唐诗/poet.tang.19000.json','["昔日齷齪不足誇，今朝放蕩思無涯。", "春風得意馬蹄疾，一日看盡長安花。"]'),
('67487ac2-b13c-4af3-836f-f10171c44671','初於洛中選','孟郊','唐','唐诗','tang','','[]','塵土日易沒，驅馳力無餘。',84,'全唐诗/poet.tang.19000.json','["塵土日易沒，驅馳力無餘。", "青雲不我與，白首方選書。", "宦途事非遠，拙者取自疎。", "終然戀皇邑，誓以結吾廬。", "帝城富高門，京路遶勝居。", "碧水走龍蛇，蜿蜒遶庭除。", "尋常異方客，過此亦踟蹰。"]'),
('b7182dab-b5a7-4fae-ad51-ed07557912a7','乙酉歲舍弟扶侍歸興義莊居後獨止舍待替人','孟郊','唐','唐诗','tang','','[]','誰言舊居止，主人忽成客。',108,'全唐诗/poet.tang.19000.json','["誰言舊居止，主人忽成客。", "僮僕強與言，相懼終脉脉。", "出亦何所求，入亦何所索。", "飲食迷精麤，衣裳失寬窄。", "回風卷閑簟，新月生空壁。", "士有百役身，官無一姓宅。", "丈夫恥自餙，衰鬚從颯白。", "蘭交早已謝，榆景徒相迫。", "惟予心中鏡，不語光歷歷。"]'),
('4e5a5cb0-129a-46d2-ac84-f3580d0aac1b','西齋養病夜懷多感因呈上從叔子雲','孟郊','唐','唐诗','tang','','[]','遠客夜衣薄，厭眠待雞鳴。',84,'全唐诗/poet.tang.19000.json','["遠客夜衣薄，厭眠待雞鳴。", "一床空月色，四壁秋蛩聲。", "守淡遺衆俗，養疴念餘生。", "方全君子拙，恥學小人明。", "蚊蚋亦有時，羽毛各有成。", "如何騏驥跡，踡跼未能行。", "西北有平路，運來無相輕。"]'),
('f5202baa-dbd3-4bb0-a53b-7e987242c42a','秋懷 一','孟郊','唐','唐诗','tang','','[]','孤骨夜難臥，吟蟲相唧唧。',60,'全唐诗/poet.tang.19000.json','["孤骨夜難臥，吟蟲相唧唧。", "老泣無涕洟，秋露爲滴瀝。", "去壯暫如翦，來衰紛似織。", "觸緒無新心，叢悲有餘憶。", "詎忍逐南帆，江山踐往昔。"]'),
('36594eb6-8c71-43f7-a20e-f3086b5f95b6','秋懷 二','孟郊','唐','唐诗','tang','','[]','秋月顏色冰，老客志氣單。',60,'全唐诗/poet.tang.19000.json','["秋月顏色冰，老客志氣單。", "冷露滴夢破，峭風梳骨寒。", "席上印病文，腸中轉愁盤。", "疑懷無所憑，虛聽多無端。", "梧桐枯崢嶸，聲響如哀彈。"]'),
('3c98a25a-7ef0-46ed-95a1-867249adc5ab','秋懷 三','孟郊','唐','唐诗','tang','','[]','一尺月透戶，仡栗如劒飛。',60,'全唐诗/poet.tang.19000.json','["一尺月透戶，仡栗如劒飛。", "老骨坐亦驚，病力所尚微。", "蟲苦貪剪色，鳥危巢焚輝。", "孀娥理故絲，孤哭抽餘思。", "浮年不可追，衰步多夕歸。"]'),
('be84e95c-f31b-42ad-b761-0d5b6aae3f88','秋懷 四','孟郊','唐','唐诗','tang','','[]','秋至老更貧，破屋無門扉。',72,'全唐诗/poet.tang.19000.json','["秋至老更貧，破屋無門扉。", "一片月落床，四壁風入衣。", "疎夢不復遠，弱心良易歸。", "商葩將去綠，繚繞爭餘輝。", "野步踏事少，病謀向物違。", "幽幽草根蟲，生意與我微。"]'),
('1515e904-6c15-430a-a877-c87a0f77f0b4','秋懷 五','孟郊','唐','唐诗','tang','','[]','竹風相戛語，幽閨暗中聞。',72,'全唐诗/poet.tang.19000.json','["竹風相戛語，幽閨暗中聞。", "鬼神滿衰聽，恍惚難自分。", "商葉墮乾雨，秋衣臥單雲。", "病骨可剸物，酸呻亦成文。", "瘦攢如此枯，壯落隨西曛。", "褭褭一線命，徒言繫絪緼。"]'),
('c5536c08-8282-4f9a-80be-79e0edc0e140','秋懷 六','孟郊','唐','唐诗','tang','','[]','老骨懼秋月，秋月刀劒稜。',84,'全唐诗/poet.tang.19000.json','["老骨懼秋月，秋月刀劒稜。", "纖輝不可干，冷魂坐自凝。", "羇雌巢空鏡，仙飆蕩浮冰。", "驚步恐自翻，病大不敢凌。", "單床寤皎皎，瘦臥心兢兢。", "洗河不見水，透濁爲清澄。", "詩壯昔空說，詩衰今何憑。"]'),
('6165b7e5-64c2-44f4-996a-ecb3528a4938','秋懷 七','孟郊','唐','唐诗','tang','','[]','老病多異慮，朝夕非一心。',84,'全唐诗/poet.tang.19000.json','["老病多異慮，朝夕非一心。", "商蟲哭衰運，繁響不可尋。", "秋草瘦如髮，貞芳綴疎金。", "晚鮮詎幾時，馳景還易陰。", "弱習徒自恥，莫知欲何任。", "露才一見讒，潛智早已深。", "防深不防露，此意古所箴。"]'),
('ebd831bc-c598-47ab-a186-609d62311269','秋懷 八','孟郊','唐','唐诗','tang','','[]','歲莫景氣乾，秋風兵甲聲。',84,'全唐诗/poet.tang.19000.json','["歲莫景氣乾，秋風兵甲聲。", "織織勞無衣，喓喓徒自鳴。", "商聲聳中夜，蹇支廢前行。", "青髮如秋園，一翦不復生。", "少年如餓花，瞥見不復明。", "君子山嶽定，小人絲毫爭。", "多爭多無壽，天道戒其盈。"]'),
('2827011a-67cd-4a79-9ace-98df2dfdb05e','秋懷 九','孟郊','唐','唐诗','tang','','[]','冷露多瘁索，枯風曉吹噓。',60,'全唐诗/poet.tang.19000.json','["冷露多瘁索，枯風曉吹噓。", "秋深月清苦，蟲老聲麤疎。", "頳珠枝纍纍，芳金蔓舒舒。", "草木亦趣時，寒榮似春餘。", "悲彼零落生，與我心何如。"]'),
('4a44c187-c1a6-4fb4-8c11-deb5018743eb','秋懷 十','孟郊','唐','唐诗','tang','','[]','老人朝夕異，生死每日中。',204,'全唐诗/poet.tang.19000.json','["老人朝夕異，生死每日中。", "坐隨一啜安，臥與萬景空。", "視短不到門，聽澀詎逐風。", "還如刻削形，免有纖悉聰。", "浪浪謝初始，皎皎幸歸終。", "孤隔文章友，親密蒿萊翁。", "歲綠閔以黃，秋節迸又窮。", "四時既相迫，萬慮自然叢。", "南逸浩淼際，北貧磽确中。", "曩懷沈遙江，衰思結秋嵩。", "鋤食難滿腹，葉衣多醜躬。", "塵縷不自整，古吟將誰通。", "幽竹嘯鬼神，楚鐵生虬龍。", "志士多異感，運鬱由邪衷。", "常思書破衣，至死教初童。", "習樂莫習聲，習聲多頑聾。", "明明胸中言，願寫爲高崇。"]'),
('c22cd23a-5d52-4551-85e9-84c8d27992d2','秋懷 十一','孟郊','唐','唐诗','tang','','[]','幽苦日日甚，老力步步微。',108,'全唐诗/poet.tang.19000.json','["幽苦日日甚，老力步步微。", "常恐暫下牀，至門不復歸。", "飢者重一食，寒者重一衣。", "泛廣豈無涘，恣行亦有隨。", "語中失次第，身外生瘡痍。", "桂蠹既潛朽，桂花損貞姿。", "詈言一失香，千古聞臭詞。", "將死始前悔，前悔不可追。", "哀哉輕薄行，終日與駟馳。"]'),
('92cd561c-8944-4a52-9038-40ea1a82da05','秋懷 十二','孟郊','唐','唐诗','tang','','[]','流運閃欲盡，枯折皆相號。',120,'全唐诗/poet.tang.19000.json','["流運閃欲盡，枯折皆相號。", "棘枝風哭酸，桐葉霜顏高。", "老蟲乾鐵鳴，驚獸孤玉咆。", "商氣洗聲瘦，晚陰驅景勞。", "集耳不可遏，噎神不可逃。", "蹇行散餘鬱，幽坐誰與曹。", "抽壯無一線，剪懷盈千刀。", "清詩既名朓，金菊亦姓陶。", "收拾昔所棄，咨嗟今比毛。", "幽幽歲晏言，零落不可操。"]'),
('57bf399c-f589-49dc-bedf-d183f9dbe03b','秋懷 十三','孟郊','唐','唐诗','tang','','[]','霜氣入病骨，老人身生冰。',144,'全唐诗/poet.tang.19000.json','["霜氣入病骨，老人身生冰。", "衰毛暗相刺，冷痛不可勝。", "鷕鷕伸至明，強強攬所憑。", "瘦坐形欲折，腹飢心將崩。", "勸藥左右愚，言語如見憎。", "聳耳噎神開，始知功用能。", "日中視餘瘡，暗隙聞繩蠅。", "彼齅一何酷，此味半點凝。", "潛毒爾無厭，餘生我堪矜。", "凍飛幸不遠，冬令反心懲。", "出沒各有時，寒熱苦相凌。", "仰謝調運翁，請命願有徵。"]'),
('fe9221d1-71a5-445a-8667-7c93f99b2228','秋懷 十四','孟郊','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河倒上天，衆水有却來。',120,'全唐诗/poet.tang.19000.json','["黃河倒上天，衆水有却來。", "人心不及水，一直去不迴。", "一直亦有巧，不肯至蓬萊。", "一直不知疲，唯聞至省臺。", "忍古不失古，失古志易摧。", "失古劒亦折，失古琴亦哀。", "夫子失古淚，當時落漼漼。", "詩老失古心，至今寒皚皚。", "古骨無濁肉，古衣如蘚苔。", "勸君勉忍古，忍古銷塵埃。"]'),
('d02116d9-4dd1-44af-9598-e8c6d1684e3b','秋懷 十五','孟郊','唐','唐诗','tang','','[]','詈言不見血，殺人何紛紛。',96,'全唐诗/poet.tang.19000.json','["詈言不見血，殺人何紛紛。", "聲如窮家犬，吠竇何誾誾。", "詈痛幽鬼哭，詈侵黃金貧。", "言詞豈用多，憔悴在一聞。", "古詈舌不死，至今書云云。", "今人詠古書，善惡宜自分。", "秦火不爇舌，秦火空爇文。", "所以詈更生，至今橫絪緼。"]'),
('8a668fcf-7299-4644-b583-5910651fd0ec','靖安寄居','孟郊','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','寄靜不寄華，愛茲嵽嵲居。',168,'全唐诗/poet.tang.19000.json','["寄靜不寄華，愛茲嵽嵲居。", "渴飲濁清泉，飢食無名蔬。", "敗菜不敢火，補衣亦寫書。", "古云儉成德，今乃實起予。", "戇叟戇不足，賢人賢有餘。", "役生皆促促，心竟誰舒舒。", "萬馬踏風衢，衆塵隨犇車。", "高賓盡不見，大道夜方虛。", "臥有洞庭夢，坐無長安儲。", "英髦空駭耳，煙火獨微如。", "厚念恐傷性，薄田憶親鋤。", "承世不出力，冬竹肯抽葅。", "外物莫相誘，約心誓從初。", "碧芳既似水，日日詠歸歟。"]'),
('ca9c25f2-45a0-4138-bd18-5b8766b4b273','雪','孟郊','唐','唐诗','tang','','[]','忽然太行雪，昨夜飛入來。',132,'全唐诗/poet.tang.19000.json','["忽然太行雪，昨夜飛入來。", "崚嶒墮庭中，嚴白何皚皚。", "奴婢曉開戶，四肢凍徘徊。", "咽言詞不成，告訴情狀摧。", "官給未入門，家人盡以灰。", "意勸莫笑雪，笑雪貧爲災。", "將暖此殘疾，典賣爭致杯。", "教令再舉手，誇曜餘生才。", "強起吐巧詞，委曲多新裁。", "爲爾作非夫，忍恥轟暍雷。", "書之與君子，庶免生嫌猜。"]'),
('4ac4af11-46dc-4f3b-9fce-dcb136880516','春怨','孟郊','唐','唐诗','tang','','[]','春物與愁客，遇時各有違。',36,'全唐诗/poet.tang.19000.json','["春物與愁客，遇時各有違。", "故花辭新枝，新淚落故衣。", "日莫兩寂寞，飄然亦同歸。"]'),
('e094095a-51e6-4c0c-81c9-6ee791b34883','懊惱','孟郊','唐','唐诗','tang','','[]','惡詩皆得官，好詩空抱山。',72,'全唐诗/poet.tang.19000.json','["惡詩皆得官，好詩空抱山。", "抱山冷殑殑，終日悲顏顏。", "好詩更相嫉，劒戟生牙關。", "前賢死已久，猶在咀嚼間。", "以我殘杪身，清峭養高閑。", "求閑未得閑，衆誚瞋虤虤。"]'),
('9b072c19-d44e-4f9d-9c71-cd4227e11b1f','遊城南韓氏莊','孟郊','唐','唐诗','tang','','[]','初疑瀟湘水，鎖在朱門中。',72,'全唐诗/poet.tang.19000.json','["初疑瀟湘水，鎖在朱門中。", "時見水底月，動搖池上風。", "清氣潤竹林，白光連虛空。", "浪簇霄漢羽，岸芳金碧叢。", "何言數畝間，環泛路不窮。", "願逐神仙侶，飄然汗漫通。"]'),
('8361d298-cefa-4723-81de-049b5bfc1e14','與二三友秋宵會話清上人院 一','孟郊','唐','唐诗','tang','','[]','何處山不幽，此中情又別。',60,'全唐诗/poet.tang.19000.json','["何處山不幽，此中情又別。", "一僧敲一磬，七子吟秋月。", "激石泉韻清，寄枝風嘯咽。", "泠然諸境靜，頓覺浮累滅。", "扣寂兼探真，通宵詎能輟。"]'),
('78b1179f-c3bb-4dd5-8f06-033a8e7dbe92','與二三友秋宵會話清上人院 二','孟郊','唐','唐诗','tang','','[]','好鳥無雜棲，華堂有嘉攜。',72,'全唐诗/poet.tang.19000.json','["好鳥無雜棲，華堂有嘉攜。", "琴樽互傾奏，歌賦相和諧。", "但嘉魚水合，莫令雲雨乖。", "一爲鵾雞彈，再鼓壯士懷。", "初景待誰曉，新春逐君來。", "願言良友會，高駕不知迴。"]'),
('2aeccb3b-6ae6-401c-a3b6-c73ef11cbba2','招文士飲','孟郊','唐','唐诗','tang','','[]','曹劉不免死，誰敢負年華。',108,'全唐诗/poet.tang.19000.json','["曹劉不免死，誰敢負年華。", "文士莫辭酒，詩人命屬花。", "退之如放逐，李白自矜誇。", "萬古忽將似，一朝同歎嗟。", "何言天道正，獨使地形斜。", "南士愁多病，北人悲去家。", "梅芳已流管，柳色未藏鴉。", "相勸罷吟雪，相從愁飲霞。", "醒時不可過，愁海浩無涯。"]'),
('701c0f74-3056-4479-832e-895709027cb3','陪侍御叔遊城南山墅','孟郊','唐','唐诗','tang','','[]','夜坐擁腫亭，晝登崔巍岑。',48,'全唐诗/poet.tang.19000.json','["夜坐擁腫亭，晝登崔巍岑。", "日窺萬峰首，月見雙泉心。", "松氣清耳目，竹氛碧衣襟。", "佇想琅玕字，數聽枯槁吟。"]'),
('7b96a0e4-e9e4-4018-adef-5e28f94079a7','登華巖寺樓望終南山贈林校書兄弟','孟郊','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','地脊亞爲崖，聳出冥冥中。',72,'全唐诗/poet.tang.19000.json','["地脊亞爲崖，聳出冥冥中。", "樓根插迥雲，殿翼翔危空。", "前山胎元氣，靈異生不窮。", "勢吞萬象高，秀奪五嶽雄。", "一望俗慮醒，再登仙願崇。", "青蓮三居士，晝景真賞同。"]'),
('4efcddb4-665c-48e0-a27f-0e3f8264ddb3','遊終南山','孟郊','唐','唐诗','tang','','["\u7ec8\u5357\u5c71", "\u5199\u5c71", "\u5199\u666f", "\u63cf\u5199\u5c71"]','南山塞天地，日月石上生。',60,'全唐诗/poet.tang.19000.json','["南山塞天地，日月石上生。", "高峰夜留景，深谷晝未明。", "山中人自正，路險心亦平。", "長風驅松柏，聲拂萬壑清。", "到此悔讀書，朝朝近浮名。"]'),
('fc44b987-9f0e-48db-82d7-2506ca06060e','遊終南龍池寺','孟郊','唐','唐诗','tang','','[]','飛鳥不到處，僧房終南巔。',60,'全唐诗/poet.tang.19000.json','["飛鳥不到處，僧房終南巔。", "龍在水長碧，雨開山更鮮。", "步出白日上，坐依清溪邊。", "地寒松桂短，石險道路偏。", "晚磬送歸客，數聲落遙天。"]'),
('dc20aed7-693e-44db-99c4-ab3d8f5ba7d1','南陽公請東櫻桃亭子春讌','孟郊','唐','唐诗','tang','','[]','萬木皆未秀，一林先含春。',132,'全唐诗/poet.tang.19000.json','["萬木皆未秀，一林先含春。", "此地獨何力，我公布深仁。", "霜葉日舒卷，風枝遠埃塵。", "初英濯紫霞，飛雨流清津。", "賞異出囂雜，折芳積懽忻。", "文心茲焉重，俗尚安能珍。", "碧玉粧粉比，飛瓊穠豔均。", "鴛鴦七十二，花態併相新。", "常恐遺秀志，迨茲廣讌陳。", "芳菲爭勝引，歌詠竟良辰。", "方知戲馬會，永謝登龍賓。"]'),
('e24ed6f2-0aa8-4e4b-bf73-880febf3987d','遊華山雲臺觀','孟郊','唐','唐诗','tang','','["\u534e\u5c71"]','華嶽獨靈異，草木恒新鮮。',60,'全唐诗/poet.tang.19000.json','["華嶽獨靈異，草木恒新鮮。", "山盡五色石，水無一色泉。", "仙酒不醉人，仙芝皆延年。", "夜聞明星館，時韻女蘿弦。", "敬茲不能寐，焚栢吟道篇。"]'),
('22d7256e-b2d3-4a14-8cc6-7355c6d747ed','喜與長文上人宿李秀才小山池亭','孟郊','唐','唐诗','tang','','[]','燈盡語不盡，主人庭砌幽。',48,'全唐诗/poet.tang.19000.json','["燈盡語不盡，主人庭砌幽。", "柳枝星影曙，蘭葉露華浮。", "塊嶺笑羣岫，片池輕衆流。", "更聞清淨子，逸唱頗難儔。"]'),
('47b2eee4-22f5-4d81-9850-a3388823bb48','邀花伴','孟郊','唐','唐诗','tang','','[]','邊地春不足，十里見一花。',24,'全唐诗/poet.tang.19000.json','["邊地春不足，十里見一花。", "及時須邀遊，日莫饒風沙。"]'),
('640cb571-7386-447d-a2a8-281d3069cd7f','石淙 一','孟郊','唐','唐诗','tang','','[]','巖谷不自勝，水木幽奇多。',60,'全唐诗/poet.tang.19000.json','["巖谷不自勝，水木幽奇多。", "朔風入空曲，涇流無大波。", "迢遞徑難盡，參差勢相羅。", "雪霜有時洗，塵土無由和。", "潔冷誠未厭，晚步將如何。"]'),
('bdae6510-a999-4f60-965b-0048ed0418e8','石淙 二','孟郊','唐','唐诗','tang','','[]','出曲水未斷，入山深更重。',60,'全唐诗/poet.tang.19000.json','["出曲水未斷，入山深更重。", "泠泠若仙語，皎皎多異容。", "萬響不相雜，四時皆有濃。", "日月互分照，雲霞各生峰。", "久迷向方理，逮茲聳前蹤。"]'),
('71d20658-a9e2-4f5a-8816-749907ccb1ef','石淙 三','孟郊','唐','唐诗','tang','','[]','荒策每恣遠，戇步難自迴。',60,'全唐诗/poet.tang.19000.json','["荒策每恣遠，戇步難自迴。", "已抱苔蘚疾，尚凌潺湲隈。", "驛驥苦銜勒，籠禽恨摧頹。", "實力苟未足，浮誇信悠哉。", "顧惟非時用，靜言還自咍。"]'),
('310283b9-6e8d-4b94-ae56-e7c7906ecc5c','石淙 四','孟郊','唐','唐诗','tang','','[]','朔水刀劒利，秋石瓊瑤鮮。',120,'全唐诗/poet.tang.19000.json','["朔水刀劒利，秋石瓊瑤鮮。", "魚龍氣不腥，潭洞狀更妍。", "磴雪入呀谷，掬星灑遙天。", "聲忙不及韻，勢疾多斷漣。", "輸去雖有恨，躁氣一何顛。", "蜿蜒相纏掣，犖确亦迴旋。", "黑草濯鐵髮，白苔浮冰錢。", "具生此云遙，非德不可甄。", "何況被犀士，制之空以權。", "始知靜剛猛，文教從來先。"]'),
('be4fccb0-122f-4fa0-916c-8a2926295aea','石淙 五','孟郊','唐','唐诗','tang','','[]','空谷聳視聽，幽湍澤心靈。',84,'全唐诗/poet.tang.19000.json','["空谷聳視聽，幽湍澤心靈。", "疾流脫鱗甲，疊岸衝風霆。", "丹巘墮環景，霽波灼虛形。", "淙淙豗厚軸，稜稜攢高冥。", "弱棧跨旋碧，危梯倚凝青。", "飄飄鶴骨仙，飛動鼇背庭。", "常聞誇大言，下顧皆細萍。"]'),
('3709cce2-0948-4c21-9601-edd0bf31134c','石淙 六','孟郊','唐','唐诗','tang','','[]','百尺明鏡流，千曲寒星飛。',84,'全唐诗/poet.tang.19000.json','["百尺明鏡流，千曲寒星飛。", "爲君洗故物，有色如新衣。", "不飲泥土污，但飲雪霜飢。", "石稜玉纖纖，草色瓊霏霏。", "谷磑有餘力，溪舂亦多機。", "從來一智萌，能使衆利歸。", "因之山水中，喧然論是非。"]'),
('4a75d6a9-313c-43fb-a4ac-a2ba31e083bb','石淙 七','孟郊','唐','唐诗','tang','','[]','入深得奇趣，昇險爲良躋。',84,'全唐诗/poet.tang.19000.json','["入深得奇趣，昇險爲良躋。", "搜勝有聞見，逃俗無蹤蹊。", "穴流恣迴轉，竅景忘東西。", "戇獸鮮猜懼，羅人巧罝罤。", "幽馳異處所，忍慮多端倪。", "虛護我何飽，實歸彼非迷。", "斯文浪云潔，此旨誰得齊。"]'),
('4b34a931-0a20-4671-b4b0-879f70fecd44','石淙 八','孟郊','唐','唐诗','tang','','[]','屑珠瀉潺湲，裂玉何威瓌。',96,'全唐诗/poet.tang.19000.json','["屑珠瀉潺湲，裂玉何威瓌。", "若調千瑟弦，未果一曲諧。", "古駭毛髮慄，險驚視聽乖。", "二老皆勁骨，風趨緣欹崖。", "地遠有餘美，我遊采棄懷。", "乘時幸勤鑒，前恨多幽霾。", "弱力謝剛健，蹇策貴安排。", "始知隨事靜，何必當夕齋。"]'),
('e6da2a11-4df9-4e7d-92d1-34737fdfa95f','石淙 九','孟郊','唐','唐诗','tang','','[]','昔浮南渡飆，今攀朔山景。',96,'全唐诗/poet.tang.19000.json','["昔浮南渡飆，今攀朔山景。", "物色多瘦削，吟笑還孤永。", "日月凍有稜，雪霜空無影。", "玉噴不生冰，瑤渦旋成井。", "潛角時聳光，隱鱗乍漂冏。", "再吟獲新勝，返步失前省。", "愜懷雖已多，惕慮未能整。", "頹陽落何處，昇魄銜疎嶺。"]'),
('7ae7d2c6-b1be-4754-a932-5824f9352be3','石淙 十','孟郊','唐','唐诗','tang','','[]','聖朝搜巖谷，此地多遺玩。',84,'全唐诗/poet.tang.19000.json','["聖朝搜巖谷，此地多遺玩。", "怠惰成遠遊，頑疎恣靈觀。", "勁飆刷幽視，怒水懾餘愞。", "曾是結芳誠，遠茲勉流倦。", "冰條聳危慮，霜翠瑩遐眄。", "物誘信多端，荒尋諒難遍。", "去矣朔之隅，翛然楚之甸。"]'),
('8ab06dce-8884-4e42-ad72-ea97ea24c877','遊韋七洞庭別業','孟郊','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭如瀟湘，疊翠蕩浮碧。',240,'全唐诗/poet.tang.19000.json','["洞庭如瀟湘，疊翠蕩浮碧。", "松桂無赤日，風物饒清激。", "逍遙展幽韻，參差逗良覿。", "道勝不知疲，冥搜自無斁。", "曠然青霞抱，永矣白雪適。", "崆峒非凡鄉，蓬瀛在仙籍。", "無言從遠尚，還思君子識。", "波濤漱古岸，鏗鏘辨奇石。", "靈響非外求，殊音自中積。", "人皆走煩濁，君能致虛寂。", "何以祛擾擾，叩調清淅淅。", "既懼豪華損，誓從詩書益。", "一舉獨往姿，再搖飛遁跡。", "山深有變異，意愜無驚惕。", "采翠奪日月，照耀迷晝夕。", "松齋何用掃，蘿院自然滌。", "業峻謝煩蕪，文高追古昔。", "暫遙朱門戀，終立青史績。", "物表易淹留，人間重離析。", "難隨洞庭酌，且醉橫塘席。"]'),
('98b22f8c-8982-4dc6-9dce-af1ffffe7120','越中山水','孟郊','唐','唐诗','tang','','[]','日覺耳目勝，我來山水州。',120,'全唐诗/poet.tang.19000.json','["日覺耳目勝，我來山水州。", "蓬瀛若髣髴，田野如泛浮。", "碧嶂幾千遶，清泉萬餘流。", "莫窮合沓步，孰盡派別遊。", "越水淨難污，越天陰易收。", "氣鮮無隱物，目視遠更周。", "舉俗媚蔥蒨，連冬擷芳柔。", "菱湖有餘翠，茗圃無荒疇。", "賞異忽已遠，探奇誠淹留。", "永言終南色，去矣銷人憂。"]'),
('7e2a5f3c-cc3f-4054-8a7b-b5872c8df7e8','春集越州皇甫秀才山亭','孟郊','唐','唐诗','tang','','[]','嘉賓在何處，置亭春山巔。',60,'全唐诗/poet.tang.19000.json','["嘉賓在何處，置亭春山巔。", "顧余寂寞者，謬廁芳菲筵。", "視聽日澄澈，聲光坐連綿。", "晴湖瀉峰嶂，翠浪多萍蘚。", "何以逞高志，爲君吟秋天。"]'),
('776ed337-7535-41f9-8c30-88e10ba03c48','和皇甫判官遊瑯琊溪','孟郊','唐','唐诗','tang','','[]','山中琉璃境，物外瑯琊溪。',84,'全唐诗/poet.tang.19000.json','["山中琉璃境，物外瑯琊溪。", "房廊逐巖壑，道路隨高低。", "碧瀨漱白石，翠煙含青蜺。", "客來暫遊踐，意欲忘簪珪。", "樹杪燈火夕，雲端鐘梵齊。", "時同雖可仰，跡異難相攜。", "唯當清宵夢，髣髴願攀躋。"]'),
('967c006f-b357-45c6-a984-13f51b9b3b5c','汝州南潭陪陸中丞公讌','孟郊','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','一雨百泉漲，南潭夜來深。',108,'全唐诗/poet.tang.19000.json','["一雨百泉漲，南潭夜來深。", "分明碧沙底，寫出青天心。", "遠客洞庭至，因茲滌煩襟。", "既登飛雲舫，願奏清風琴。", "高岸立旗戟，潛蛟失浮沈。", "威稜護斯浸，魍魎逃所侵。", "山態變初霽，水聲流新音。", "耳目極眺聽，潺湲與嶔岑。", "誰言柳太守，空有白蘋吟。"]'),
('bcf7cbb0-0dd6-484c-b4ca-250ceedec33a','汝州陸中丞席喜張從事至同賦十韻','孟郊','唐','唐诗','tang','','[]','汝水無濁波，汝山饒奇石。',120,'全唐诗/poet.tang.19000.json','["汝水無濁波，汝山饒奇石。", "大賢爲此郡，佳士來如積。", "有客乘白駒，奉義愜所適。", "清風蕩華館，雅瑟泛瑤席。", "芳醑靜無喧，金尊光有滌。", "縱情孰慮損，聽論自招益。", "願折若木枝，却彼曜靈夕。", "貴賤一相接，憂悰忽轉易。", "會合勿言輕，別離古來惜。", "請君駐征車，良遇難再覿。"]'),
('ec4c52b8-092d-42e5-9b54-e10d843cc528','夜集汝州郡齋聽陸僧辯彈琴','孟郊','唐','唐诗','tang','','[]','康樂寵詞客，清宵意無窮。',48,'全唐诗/poet.tang.19000.json','["康樂寵詞客，清宵意無窮。", "徵文北山外，借月南樓中。", "千里愁併盡，一樽歡暫同。", "胡爲戛楚琴，淅瀝起寒風。"]'),
('33910f93-5dc7-400b-aebc-22b8d8564f86','同年春燕','孟郊','唐','唐诗','tang','','[]','少年三十士，嘉會良在茲。',192,'全唐诗/poet.tang.19000.json','["少年三十士，嘉會良在茲。", "高歌搖春風，醉舞摧花枝。", "意蕩晼晚景，喜凝芳菲時。", "馬跡攢騕褭，樂聲韻參差。", "視聽改舊趣，物象含新姿。", "紅雨花上滴，綠煙柳際垂。", "淹中講精義，南皮獻清詞。", "前賢與今人，千載爲一期。", "明鑒有皎潔，澄玉無磷緇。", "永與沙泥別，各整雲漢儀。", "盛氣自中積，英名日四馳。", "塞鴻絕儔匹，海月難等夷。", "鬱抑忽已盡，親朋樂無涯。", "幽蘅發空曲，芳杜綿所思。", "浮跡自聚散，壯心誰別離。", "願保金石志，無令有奪移。"]'),
('64e99a66-6f2a-4c6c-90ac-f9ccacf83385','羅氏花下奉招陳侍御','孟郊','唐','唐诗','tang','','[]','眼在枝上春，落地成埃塵。',96,'全唐诗/poet.tang.19000.json','["眼在枝上春，落地成埃塵。", "不是風流者，誰爲攀折人。", "寧辭波浪闊，莫道往來頻。", "拾紫豈宜晚，掇芳須及晨。", "勞收賈生淚，強起屈平身。", "花下本無俗，酒中別有神。", "遊蜂不飲故，戲蝶亦爭新。", "萬物盡如此，過時非所珍。"]'),
('2ede5a4d-71c2-48c1-a027-905b5f54f857','遊石龍渦','孟郊','唐','唐诗','tang','','[]','石龍不見形，石雨如散星。',84,'全唐诗/poet.tang.19000.json','["石龍不見形，石雨如散星。", "山下晴皎皎，山中陰泠泠。", "水飛林木杪，珠綴莓苔屏。", "畜異物皆別，當晨景欲暝。", "泉芳春氣碧，松月寒色青。", "險力此獨壯，猛獸亦不停。", "日暮且迴去，浮心恨未寧。"]'),
('40874ea8-ab27-484c-bd70-161471f0f71a','浮石亭','孟郊','唐','唐诗','tang','','[]','曾是風雨力，崔巍漂來時。',48,'全唐诗/poet.tang.19000.json','["曾是風雨力，崔巍漂來時。", "落星夜皎潔，近榜朝逶迤。", "翠瀲遞明滅，清潨瀉欹危。", "況逢蓬島仙，會合良在茲。"]'),
('1d840e59-3a82-427a-befa-e689ea4ee2ee','看花 一','孟郊','唐','唐诗','tang','','[]','家家有芍藥，不妨至溫柔。',48,'全唐诗/poet.tang.19000.json','["家家有芍藥，不妨至溫柔。", "溫柔一同女，紅笑笑不休。", "月娥雙雙下，楚豔枝枝浮。", "洞裏逢仙人，綽約青宵遊。"]'),
('0386021c-eee1-4a20-9ac3-61b407845d50','看花 二','孟郊','唐','唐诗','tang','','[]','芍藥誰爲壻，人人不敢來。',48,'全唐诗/poet.tang.19000.json','["芍藥誰爲壻，人人不敢來。", "唯應待詩老，日日殷勤開。", "玉立無氣力，春凝且裴徊。", "將何謝青春，痛飲一百杯。"]'),
('edfbf8e8-b5a8-482b-bfb8-e1206c2fbad5','看花 三','孟郊','唐','唐诗','tang','','[]','芍藥吹欲盡，無奈曉風何。',48,'全唐诗/poet.tang.19000.json','["芍藥吹欲盡，無奈曉風何。", "餘花欲誰待，唯待諫郎過。", "諫郎不事俗，黃金買高歌。", "高歌夜更清，花意晚更多。"]'),
('24533579-6606-49d5-9e8a-eb951515180f','看花 四','孟郊','唐','唐诗','tang','','[]','飲之不見底，醉倒深紅波。',48,'全唐诗/poet.tang.19000.json','["飲之不見底，醉倒深紅波。", "紅波蕩諫心，諫心終無它。", "獨遊終難醉，挈榼徒經過。", "問花不解語，勸得酒無多。"]'),
('9908dddc-10d3-4398-b224-ae874d0dee79','看花 五','孟郊','唐','唐诗','tang','','[]','三年此村落，春色入心悲。',24,'全唐诗/poet.tang.19000.json','["三年此村落，春色入心悲。", "料得一孀婦，經時獨淚垂。"]'),
('3d9ae8d8-3b5b-49a4-8746-41e1d5c6f3b9','濟源春','孟郊','唐','唐诗','tang','','[]','太行橫偃脊，百里芳崔巍。',120,'全唐诗/poet.tang.19000.json','["太行橫偃脊，百里芳崔巍。", "濟濱花異顏，枋口雲如裁。", "新畫彩色濕，上界光影來。", "深紅縷草木，淺碧珩泝洄。", "千家門前飲，一道傳禊杯。", "玉鱗吞金鉤，仙璇瑠璃開。", "朴童茂言語，善俗無驚猜。", "狂吹寢恒宴，曉清夢先回。", "治生鮮惰夫，積學多深材。", "再遊詎癲戇，一洗驚塵埃。"]'),
('8dd72526-e682-4f98-b9f6-ab2580fc2b3b','濟源寒食 一','孟郊','唐','唐诗','tang','','[]','風巢嫋嫋春鵶鵶，無子老人仰面嗟。',32,'全唐诗/poet.tang.19000.json','["風巢嫋嫋春鵶鵶，無子老人仰面嗟。", "柳弓葦箭覰不見，高紅遠綠勞相遮。"]'),
('2ee45b31-c075-42cc-bdd7-0288c5da7c30','濟源寒食 二','孟郊','唐','唐诗','tang','','[]','女嬋童子黃短短，耳中聞人惜春晚。',32,'全唐诗/poet.tang.19000.json','["女嬋童子黃短短，耳中聞人惜春晚。", "逃蜂匿蝶踏地來，拋却齋糜一瓷椀。"]'),
('2b9a9785-b5c2-4d96-a65d-02f5bc3555c0','濟源寒食 三','孟郊','唐','唐诗','tang','','[]','一日踏春一百回，朝朝沒脚走芳埃。',32,'全唐诗/poet.tang.19000.json','["一日踏春一百回，朝朝沒脚走芳埃。", "飢童餓馬埽花餵，向晚飲溪三兩杯。"]'),
('ff63b936-2563-444b-896e-403c758b75f3','濟源寒食 四','孟郊','唐','唐诗','tang','','[]','莓苔井上空相憶，轆轤索斷無消息。',32,'全唐诗/poet.tang.19000.json','["莓苔井上空相憶，轆轤索斷無消息。", "酒人皆倚春髮綠，病叟獨藏秋髮白。"]'),
('db4738e2-38e9-4926-9314-4be0751c310e','濟源寒食 五','孟郊','唐','唐诗','tang','','[]','長安落花飛上天，南風引至三殿前。',32,'全唐诗/poet.tang.19000.json','["長安落花飛上天，南風引至三殿前。", "可憐春物亦朝謁，唯我孤吟渭水邊。"]'),
('4d64e5bd-4683-4634-ae58-cd92caa4f669','濟源寒食 六','孟郊','唐','唐诗','tang','','[]','枋口花間掣手歸，嵩陽爲我留紅暉。',32,'全唐诗/poet.tang.19000.json','["枋口花間掣手歸，嵩陽爲我留紅暉。", "可憐躑躅千萬尺，柱地柱天疑欲飛。"]'),
('ae9f5d0d-b139-4125-8a17-c030b21ffbd2','濟源寒食 七','孟郊','唐','唐诗','tang','','[]','蜜蜂爲主各磨牙，咬盡村中萬木花。',32,'全唐诗/poet.tang.19000.json','["蜜蜂爲主各磨牙，咬盡村中萬木花。", "君家甕甕今應滿，五色冬籠甚可誇。"]'),
('96dff9d3-7635-4d21-9863-3bf4f6d61b42','遊枋口 一','孟郊','唐','唐诗','tang','','[]','一步復一步，出行千里幽。',108,'全唐诗/poet.tang.19000.json','["一步復一步，出行千里幽。", "爲取山水意，故作寂寞遊。", "太行青巔高，枋口碧照浮。", "明明無底鏡，泛泛忘機鷗。", "老逸不自限，病狂不可周。", "恣閑饒淡薄，怠玩多淹留。", "芳物競晼晚，綠梢挂新柔。", "和友鶯相遶，言語亦以稠。", "始知萬類然，靜躁難相求。"]'),
('676ed31f-fb87-4c6c-8c91-3edd38c6097b','遊枋口 二','孟郊','唐','唐诗','tang','','[]','聳我殘病骨，健如一仙人。',84,'全唐诗/poet.tang.19000.json','["聳我殘病骨，健如一仙人。", "鏡中照千里，鏡浪洞百神。", "此神日月華，不作尋常春。", "三十夜皆明，四時晝恒新。", "鳥聲盡依依，獸心亦忻忻。", "澄幽出所怪，閃異坐微絪。", "可來復可來，此地靈相親。"]'),
('2a958587-d620-4303-9bff-3cbe20dcdc6c','與王二十一員外涯遊枋口柳溪','孟郊','唐','唐诗','tang','','[]','萬株古柳根，挐此磷磷溪。',180,'全唐诗/poet.tang.19000.json','["萬株古柳根，挐此磷磷溪。", "野榜多屈曲，仙潯無端倪。", "春桃散紅煙，寒竹含晚淒。", "曉聽忽以異，芳樹安能齊。", "共疑落鏡中，坐泛紅景低。", "水意酒易醒，浪情事非迷。", "小儒峭章句，大賢嘉提攜。", "潛竇韻靈瑟，翠崖鳴玉珪。", "主人稷卨翁，德茂芝朮畦。", "鑿出幽隱端，氣象皆升躋。", "曾是清樂抱，逮茲幾省溪。", "宴位席蘭草，濫觴驚鳧鷖。", "靈味薦魴瓣，金花屑橙韲。", "江調擺衰俗，洛風遠塵泥。", "徒言奏狂狷，詎敢忘筌蹄。"]'),
('93409223-a5c9-48a2-b6a8-c7db571ac95b','與王二十一員外涯遊昭成寺','孟郊','唐','唐诗','tang','','[]','洛友寂寂約，省騎霏霏塵。',84,'全唐诗/poet.tang.19000.json','["洛友寂寂約，省騎霏霏塵。", "遊僧步晚磬，話茗含芳春。", "瑤策冰入手，粉壁畫瑩神。", "頳廊芙蓉霽，碧殿瑠璃勻。", "玄講島嶽盡，淵詠文字新。", "屢笑寒竹讌，況接青雲賓。", "顧慙餘眷下，衰瘵嬰殘身。"]'),
('527b0e4c-3a9c-47ee-8f6f-d5482004f3d0','嵩少','孟郊','唐','唐诗','tang','','[]','沙彌舞袈裟，走向躑躅飛。',60,'全唐诗/poet.tang.19000.json','["沙彌舞袈裟，走向躑躅飛。", "閑步亦惺惺，芳援相依依。", "噎塞春咽喉，蜂蝶事光輝。", "羣嬉且已晚，孤引將何歸。", "流豔去不息，朝英亦疎微。"]'),
('b0b8e48b-adad-4519-ab5f-a5e3ee90e1d7','旅次洛城東水亭','孟郊','唐','唐诗','tang','','[]','水竹色相洗，碧花動軒楹。',48,'全唐诗/poet.tang.19000.json','["水竹色相洗，碧花動軒楹。", "自然逍遙風，蕩滌浮競情。", "霜落葉聲燥，景寒人語清。", "我來招隱亭，衣上塵暫輕。"]'),
('7fa85386-6319-4eee-8a93-c4d4e13f928b','洛橋晚望','孟郊','唐','唐诗','tang','','["\u51ac\u5929", "\u5199\u666f", "\u6292\u60c5"]','天津橋下冰初結，洛陽陌上人行絕。',32,'全唐诗/poet.tang.19000.json','["天津橋下冰初結，洛陽陌上人行絕。", "榆柳蕭疎樓閣閑，月明直見嵩山雪。"]'),
('e3fd9123-183f-4fce-95c0-a5e479502f5d','北郭貧居','孟郊','唐','唐诗','tang','','[]','進乏廣莫力，退爲蒙籠居。',60,'全唐诗/poet.tang.19000.json','["進乏廣莫力，退爲蒙籠居。", "三年失意歸，四向相識疎。", "地僻草木壯，荒條扶我廬。", "夜貧燈燭絕，明月照吾書。", "欲識貞靜操，秋蟬飲清虛。"]'),
('9c024e23-7662-4203-89d2-caeebc1733f3','題陸鴻漸上饒新開山舍','孟郊','唐','唐诗','tang','','[]','驚彼武陵狀，移歸此巖邊。',48,'全唐诗/poet.tang.19000.json','["驚彼武陵狀，移歸此巖邊。", "開亭擬貯雲，鑿石先得泉。", "嘯竹引清吹，吟花成新篇。", "乃知高潔情，擺落區中緣。"]'),
('41787652-fe57-4f4d-9c2e-391b1fcf20a9','題韋承總吳王故城下幽居','孟郊','唐','唐诗','tang','','[]','才飽身自貴，巷荒門豈貧。',72,'全唐诗/poet.tang.19000.json','["才飽身自貴，巷荒門豈貧。", "韋生堪繼相，孟子願依鄰。", "夜思琴語切，晝情茶味新。", "霜枝留過鵲，風竹掃蒙塵。", "郢唱一聲發，吳花千片春。", "對君何所得，歸去覺情真。"]'),
('0f444b44-56dd-4bdb-a49f-484c9bb6ed85','蘇州崑山惠聚寺僧房','孟郊','唐','唐诗','tang','','[]','昨日到上方，片雲挂石牀。',48,'全唐诗/poet.tang.19000.json','["昨日到上方，片雲挂石牀。", "錫杖莓苔青，袈裟松栢香。", "晴磬無短韻，古燈含永光。", "有時乞鶴歸，還訪逍遙場。"]'),
('0daa20b6-5cb4-4a13-9f43-ec4b9448bb36','題從叔述靈巖山壁','孟郊','唐','唐诗','tang','','[]','換却世上心，獨起山中情。',84,'全唐诗/poet.tang.19000.json','["換却世上心，獨起山中情。", "露衣涼且鮮，雲策高復輕。", "喜見夏日來，變爲松景清。", "每將逍遙聽，不厭颼飗聲。", "遠念塵末宗，未疎俗間名。", "桂枝妄舉手，萍路空勞生。", "仰謝開淨弦，相招時一鳴。"]'),
('9e4c463f-add2-4dd9-ac6b-bb59f708074b','題林校書花嚴寺書窗','孟郊','唐','唐诗','tang','','[]','隱詠不誇俗，問禪徒淨居。',48,'全唐诗/poet.tang.19000.json','["隱詠不誇俗，問禪徒淨居。", "翻將白雲字，寄向青蓮書。", "擬古投松坐，就明開紙疏。", "昭昭南山景，獨與心相如。"]'),
('9b1f98a9-c2a5-4374-9cf3-532a5cecc46a','藍溪元居士草堂','孟郊','唐','唐诗','tang','','[]','市井不容義，義歸山谷中。',96,'全唐诗/poet.tang.19000.json','["市井不容義，義歸山谷中。", "夫君宅松桂，招我棲蒙籠。", "人朴情慮肅，境閑視聽空。", "清溪宛轉水，修竹徘徊風。", "木倦採樵子，土勞稼穡翁。", "讀書業雖異，敦本志亦同。", "藍岸青漠漠，藍峰碧崇崇。", "日昏各命酒，寒蛩鳴蕙叢。"]'),
('d30a2029-71f7-4990-93cb-b662792e0e0e','新卜清羅幽居恭奉獻陸大夫','孟郊','唐','唐诗','tang','','[]','黔婁住何處，仁邑無餒寒。',120,'全唐诗/poet.tang.19000.json','["黔婁住何處，仁邑無餒寒。", "豈悟舊羇旅，變爲新閑安。", "二頃有餘食，三農行可觀。", "籠禽得高巢，轍鮒還層瀾。", "翳翳桑柘墟，紛紛田里歡。", "兵戈忽消散，耦耕非艱難。", "嘉木偶良酌，芳陰庇清彈。", "力農唯一事，趣世徒萬端。", "靜覺本相厚，動爲末所殘。", "此外有餘暇，鋤荒出幽蘭。"]'),
('c50dbffe-3f66-47a2-935f-fdca33d82efb','題韋少保靜恭宅藏書洞','孟郊','唐','唐诗','tang','','[]','高意合天製，自然狀無窮。',72,'全唐诗/poet.tang.19000.json','["高意合天製，自然狀無窮。", "仙華凝四時，玉蘚生數峰。", "書祕漆文字，匣藏金蛟龍。", "閑爲氣候肅，開作雲雨濃。", "洞隱諒非久，巖夢誠必通。", "將綴文士集，貫就真珠叢。"]'),
('8fb4b6e4-9405-4afc-9893-34d36b291032','生生亭','孟郊','唐','唐诗','tang','','[]','灘鬧不妨語，跨溪仍置亭。',108,'全唐诗/poet.tang.19000.json','["灘鬧不妨語，跨溪仍置亭。", "置亭嵽嵲頭，開窗納遙青。", "遙青新畫出，三十六扇屏。", "褭褭立平地，稜稜浮高冥。", "一日數開扉，仙閃目不停。", "徒誇遠方岫，曷若中峰靈。", "拔意千餘丈，浩言永堪銘。", "浩言無媿同，媿同忍醜醒。", "致之未有力，力在君子聽。"]'),
('d85cd62b-fd20-42c4-aa83-6ddc066d89b5','寒溪 一','孟郊','唐','唐诗','tang','','[]','霜洗水色盡，寒溪見纖鱗。',84,'全唐诗/poet.tang.19000.json','["霜洗水色盡，寒溪見纖鱗。", "幸臨虛空鏡，照此殘悴身。", "潛滑不自隱，露底瑩更新。", "豁如君子懷，曾是危陷人。", "始明淺俗心，夜結朝已津。", "淨漱一掬碧，遠消千慮塵。", "始知泥步泉，莫與山源隣。"]'),
('d5101633-3f8a-4e5e-8eb8-691415b1fb7c','寒溪 二','孟郊','唐','唐诗','tang','','[]','洛陽岸邊道，孟氏莊前溪。',96,'全唐诗/poet.tang.19000.json','["洛陽岸邊道，孟氏莊前溪。", "舟行素冰折，聲作青瑤嘶。", "綠水結綠玉，白波生白珪。", "明明寶鏡中，物物天照齊。", "仄步下危曲，攀枯聞孀啼。", "霜芬稍消歇，凝景微茫齊。", "癡坐直視聽，戇行失蹤蹊。", "岸童斸棘勞，語言多悲悽。"]'),
('a5e6b3e1-c913-47f6-8df6-9798de70ad2d','寒溪 三','孟郊','唐','唐诗','tang','','[]','曉飲一杯酒，踏雪過清溪。',84,'全唐诗/poet.tang.19000.json','["曉飲一杯酒，踏雪過清溪。", "波瀾凍爲刀，剸割鳧與鷖。", "宿羽皆翦棄，血聲沉沙泥。", "獨立欲何語，默念心酸嘶。", "凍血莫作春，作春生不齊。", "凍血莫作花，作花發孀啼。", "幽幽棘針村，凍死難耕犂。"]'),
('fa9144b4-66b5-4761-8582-458968ecf8b3','寒溪 四','孟郊','唐','唐诗','tang','','[]','篙工磓玉星，一路隨迸螢。',84,'全唐诗/poet.tang.19000.json','["篙工磓玉星，一路隨迸螢。", "朔凍哀徹底，獠饞詠潛鯹。", "冰齒相磨嚙，風音酸鐸鈴。", "清悲不可逃，洗出纖悉聽。", "碧瀲卷已盡，彩縷飛飄零。", "下躡滑不定，上棲折難停。", "哮嘐呷喢冤，仰訴何時寧。"]'),
('9c72ed8d-f175-4f34-ab9e-17572f357e52','寒溪 五','孟郊','唐','唐诗','tang','','[]','一曲一直水，白龍何鱗鱗。',132,'全唐诗/poet.tang.19000.json','["一曲一直水，白龍何鱗鱗。", "凍飆雜碎號，韲音坑谷辛。", "柧椾吃無力，飛走更相仁。", "猛弓一折絃，餘喘爭來賓。", "大嚴此之立，小殺不復陳。", "皎皎何皎皎，氤氳復氤氳。", "瑞晴刷日月，高碧開星辰。", "獨立兩脚雪，孤吟千慮新。", "天欃徒昭昭，箕舌虛齗齗。", "堯聖不聽汝，孔微亦有臣。", "諫書竟成章，古義終難陳。"]'),
('ab03dc34-6674-42e6-8870-8fde17e5575a','寒溪 六','孟郊','唐','唐诗','tang','','[]','因凍死得食，殺風仍不休。',108,'全唐诗/poet.tang.19000.json','["因凍死得食，殺風仍不休。", "以兵爲仁義，仁義生刀頭。", "刀頭仁義腥，君子不可求。", "波瀾抽劒冰，相劈如仇讐。", "尖雪入魚心，魚心明愀愀。", "怳如罔兩說，似訴割切由。", "誰使異方氣，入此中土流。", "翦盡一月春，閉爲百谷幽。", "仰懷新霽光，下照疑憂愁。"]'),
('2da7dd48-c1b9-469b-b020-fdb27155b89c','寒溪 七','孟郊','唐','唐诗','tang','','[]','溪老哭甚寒，涕泗冰珊珊。',60,'全唐诗/poet.tang.19000.json','["溪老哭甚寒，涕泗冰珊珊。", "飛死走死形，雪裂紛心肝。", "劒刃凍不割，弓弦彊難彈。", "常聞君子武，不食天殺殘。", "斸玉掩骼胔，弔瓊哀闌干。"]'),
('c29417fe-598c-444b-b009-92e8ae0b2e61','寒溪 八','孟郊','唐','唐诗','tang','','[]','溪風擺餘凍，溪景銜明春。',72,'全唐诗/poet.tang.19000.json','["溪風擺餘凍，溪景銜明春。", "玉消花滴滴，虬解光鱗鱗。", "懸步下清曲，消期濯芳津。", "千里冰裂處，一勺暖亦仁。", "凝精互相洗，漪漣競將新。", "忽如劒瘡盡，初起百戰身。"]'),
('8b6490c5-f505-4416-8043-aa092e593845','立德新居 一','孟郊','唐','唐诗','tang','','[]','立德何亭亭，西南聳高隅。',60,'全唐诗/poet.tang.19000.json','["立德何亭亭，西南聳高隅。", "陽崖洩春意，井圃留冬蕪。", "勝引即紆道，幽行豈通衢。", "碧峰遠相揖，清思誰言孤。", "寺秩雖貴家，濁醪良可哺。"]'),
('6a423dbd-4372-47d0-8010-9c28fdf569d9','立德新居 二','孟郊','唐','唐诗','tang','','[]','聳城架霄漢，潔宅涵絪緼。',60,'全唐诗/poet.tang.19000.json','["聳城架霄漢，潔宅涵絪緼。", "開門洛北岸，時鎖嵩陽雲。", "夜高星辰大，晝長天地分。", "厚韻屬疎語，薄名謝囂聞。", "茲焉有殊隔，永矣難及羣。"]'),
('6d52f1b6-635d-4740-b5fc-b6e6718bc77f','立德新居 三','孟郊','唐','唐诗','tang','','[]','賓秩已覺厚，私儲常恐多。',60,'全唐诗/poet.tang.19000.json','["賓秩已覺厚，私儲常恐多。", "清貧聊自爾，素責將如何。", "儉教先勉力，修襟無餘佗。", "良棲一枝木，靈巢片葉荷。", "仰笑鵾鵬輩，委身拂天波。"]'),
('3202b721-5599-48d1-8d82-85dfb7f2586e','立德新居 四','孟郊','唐','唐诗','tang','','[]','疎門不掩水，洛色寒更高。',60,'全唐诗/poet.tang.19000.json','["疎門不掩水，洛色寒更高。", "曉碧流視聽，夕清濯衣袍。", "爲於仁義得，未覺登陟勞。", "遠岸雪難莫，勁枝風易號。", "霜禽各嘯侶，吾亦愛吾曹。"]'),
('203d1b82-bda8-4fca-acba-f0ba9bf576f5','立德新居 五','孟郊','唐','唐诗','tang','','[]','崎嶇有懸步，委曲饒荒尋。',60,'全唐诗/poet.tang.19000.json','["崎嶇有懸步，委曲饒荒尋。", "遠樹足良木，疎巢無爭禽。", "素魄銜夕岸，綠水生曉潯。", "空曠伊洛視，髣髴瀟湘心。", "何必尚遠異，憂勞滿行襟。"]'),
('80afe0c5-595a-4fa4-9d5a-43ac5c3bbae9','立德新居 六','孟郊','唐','唐诗','tang','','[]','懸途多仄足，崎圃無修畦。',60,'全唐诗/poet.tang.19000.json','["懸途多仄足，崎圃無修畦。", "芳蘭與宿艾，手擷心不迷。", "品子懶讀書，轅駒難服犂。", "虛食日相投，夸腸詎能低。", "恥從新學游，願將古農齊。"]'),
('a4accf6b-6fc4-4b7a-8c43-8ae8b97bdb97','立德新居 七','孟郊','唐','唐诗','tang','','[]','都城多聳秀，愛此高縣居。',60,'全唐诗/poet.tang.19000.json','["都城多聳秀，愛此高縣居。", "伊雒遶街巷，鴛鴦飛閻閭。", "翠景何的礫，霜飔飄空虛。", "突出萬家表，獨治二畝蔬。", "一旬一手版，十日九手鋤。"]'),
('707ccc34-99d8-44db-b57a-0b8b05e7137e','立德新居 八','孟郊','唐','唐诗','tang','','[]','手鋤手自勗，激勸亦已饒。',60,'全唐诗/poet.tang.19000.json','["手鋤手自勗，激勸亦已饒。", "畏彼棃栗兒，空資玩弄驕。", "夜景臥難盡，晝光坐易消。", "治舊得新義，耕荒生嘉苗。", "鋤治苟愜適，心形俱逍遙。"]'),
('0a49e240-79bb-4039-8eb8-d121b4176951','立德新居 九','孟郊','唐','唐诗','tang','','[]','玉蹄裂鳴水，金綬忽照門。',60,'全唐诗/poet.tang.19000.json','["玉蹄裂鳴水，金綬忽照門。", "拂拭貧士席，拜候丞相轅。", "德疎未爲高，禮至方覺尊。", "豈唯耀茲日，可以榮遠孫。", "如何一陽朝，獨荷衆瑞繁。"]'),
('897d5535-0309-4250-94f5-837df31d3d2c','立德新居 十','孟郊','唐','唐诗','tang','','[]','東南富水木，寂寥蔽光輝。',60,'全唐诗/poet.tang.19000.json','["東南富水木，寂寥蔽光輝。", "此地足文字，及時隘驂騑。", "仄雪踏爲平，澀行變如飛。", "令畦生氣色，嘉綠新霏微。", "天意資厚養，賢人肯相違。"]'),
('cb12ace8-3c7c-4c0a-8cae-8ae0ef5ad460','西上經靈寶觀','孟郊','唐','唐诗','tang','','[]','道士無白髮，語音靈泉清。',72,'全唐诗/poet.tang.19000.json','["道士無白髮，語音靈泉清。", "青松多壽色，白石恆夜明。", "放步霽霞起，振衣華風生。", "真文祕中頂，寶氣浮四楹。", "一片古關路，萬里今人行。", "上仙不可見，驅策徒西征。"]'),
('f0e09783-3ec8-4c5f-920f-2a0d3e35f67b','泛黃河','孟郊','唐','唐诗','tang','','["\u9ec4\u6cb3"]','誰開崑崙源，流出混沌河。',48,'全唐诗/poet.tang.19000.json','["誰開崑崙源，流出混沌河。", "積雨飛作風，驚龍噴爲波。", "湘瑟颼飀弦，越賓嗚咽歌。", "有恨不可洗，虛此來經過。"]');
